const MODERN_PHILOSOPHY_QUOTES = [
  { id: 100501, author: "Henry David Thoreau", category: "suffering", tags: ["reckoning","wisdom"],
    text: "The mass of men lead lives of quiet desperation.",
    textTr: "İnsanların çoğu sessiz bir çaresizlik içinde yaşar.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100502, author: "Henry David Thoreau", category: "wisdom", tags: ["focus","wisdom"],
    text: "I went to the woods because I wished to live deliberately, to front only the essential facts of life, and see if I could not learn what it had to teach, and not, when I came to die, discover that I had not lived.",
    textTr: "Ormana gittim çünkü bilinçli yaşamak istiyordum, yaşamın yalnızca temel gerçekleriyle yüzleşmek ve onun öğretebileceklerini öğrenip öğrenemeyeceğimi görmek istiyordum; ölüm anında hiç yaşamadığımı fark etmek istemiyordum.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100503, author: "Henry David Thoreau", category: "fire", tags: ["motivation","discipline"],
    text: "I wanted to live deep and suck out all the marrow of life, to live so sturdily and Spartan-like as to put to rout all that was not life.",
    textTr: "Derinlemesine yaşamak, hayatın özünü tüm iliğine kadar emmek istedim; yaşam olmayan her şeyi alt edecek kadar dirençli ve Spartalı bir şekilde yaşamak istedim.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100504, author: "Henry David Thoreau", category: "discipline", tags: ["discipline","focus"],
    text: "Simplicity, simplicity, simplicity!",
    textTr: "Sadelik, sadelik, sadelik!",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100505, author: "Henry David Thoreau", category: "identity", tags: ["wisdom","focus"],
    text: "To be awake is to be alive. I have never yet met a man who was quite awake.",
    textTr: "Uyanık olmak, canlı olmaktır. Bugüne dek gerçekten uyanık bir insanla hiç karşılaşmadım.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100506, author: "Henry David Thoreau", category: "wisdom", tags: ["peace","wisdom"],
    text: "I find it wholesome to be alone the greater part of the time.",
    textTr: "Vaktimin çoğunu yalnız geçirmeyi sağlıklı buluyorum.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100507, author: "Henry David Thoreau", category: "identity", tags: ["peace","focus"],
    text: "I love to be alone. I never found the companion that was so companionable as solitude.",
    textTr: "Yalnız olmayı severim. Yalnızlık kadar iyi bir arkadaş hiç bulamadım.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100508, author: "Henry David Thoreau", category: "identity", tags: ["wisdom","focus"],
    text: "No man ever followed his genius till it misled him.",
    textTr: "Hiçbir insan, kendi dehasının peşinden gidip de yolunu şaşırmadan edemez.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100509, author: "Henry David Thoreau", category: "discipline", tags: ["discipline","wisdom"],
    text: "From exertion come wisdom and purity; from sloth ignorance and sensuality.",
    textTr: "Çabadan bilgelik ve arınmışlık doğar; tembellikten ise cehalet ve şehvet.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100510, author: "Henry David Thoreau", category: "identity", tags: ["motivation","focus"],
    text: "If a man does not keep pace with his companions, perhaps it is because he hears a different drummer.",
    textTr: "Bir insan arkadaşlarına ayak uyduramıyorsa, belki de farklı bir davulun sesini duyduğu içindir.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100511, author: "Henry David Thoreau", category: "resilience", tags: ["resilience","motivation"],
    text: "However mean your life is, meet it and live it; do not shun it and call it hard names.",
    textTr: "Hayatın ne kadar sıradan olursa olsun, onunla yüzleş ve onu yaşa; ondan kaçıp kötü isimler takma.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100512, author: "Henry David Thoreau", category: "fire", tags: ["motivation","resilience"],
    text: "If one advances confidently in the direction of his dreams, and endeavors to live the life which he has imagined, he will meet with a success unexpected in common hours.",
    textTr: "Bir insan hayallerinin yönünde kendinden emin adımlarla ilerler ve hayal ettiği hayatı yaşamaya çalışırsa, sıradan zamanlarda beklenmedik bir başarıyla karşılaşır.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100513, author: "Henry David Thoreau", category: "fire", tags: ["motivation","discipline"],
    text: "If you have built castles in the air, your work need not be lost; that is where they should be. Now put the foundations under them.",
    textTr: "Havada kaleler kurduysan, emeğin boşa gitmiş sayılmaz; zaten onların yeri orasıdır. Şimdi sıra o kalelerin altına temel atmakta.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100514, author: "Ralph Waldo Emerson", category: "identity", tags: ["motivation","resilience"],
    text: "Trust thyself: every heart vibrates to that iron string.",
    textTr: "Kendine güven: her kalp o demir tele göre titreşir.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100515, author: "Ralph Waldo Emerson", category: "wisdom", tags: ["wisdom","focus"],
    text: "To believe your own thought, to believe that what is true for you in your private heart is true for all men,—that is genius.",
    textTr: "Kendi düşüncene inanmak, kendi yüreğinde doğru olanın bütün insanlar için de doğru olduğuna inanmak — işte dehâ budur.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100516, author: "Ralph Waldo Emerson", category: "identity", tags: ["wisdom","discipline"],
    text: "Nothing is at last sacred but the integrity of your own mind.",
    textTr: "Sonunda kutsal olan tek şey, kendi zihninin bütünlüğüdür.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100517, author: "Ralph Waldo Emerson", category: "wisdom", tags: ["wisdom","focus"],
    text: "A foolish consistency is the hobgoblin of little minds, adored by little statesmen and philosophers and divines.",
    textTr: "Aptalca bir tutarlılık, küçük zihinlerin taptığı küçük bir cindir; küçük devlet adamları, filozoflar ve din adamları tarafından kutsanır.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100518, author: "Ralph Waldo Emerson", category: "identity", tags: ["resilience","legacy"],
    text: "To be great is to be misunderstood.",
    textTr: "Büyük olmak, yanlış anlaşılmaktır.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100519, author: "Ralph Waldo Emerson", category: "identity", tags: ["motivation","resilience"],
    text: "Whoso would be a man, must be a nonconformist.",
    textTr: "Gerçek bir insan olmak isteyen, uyumsuz olmayı göze almalıdır.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100520, author: "Ralph Waldo Emerson", category: "discipline", tags: ["peace","discipline"],
    text: "The great man is he who in the midst of the crowd keeps with perfect sweetness the independence of solitude.",
    textTr: "Büyük insan, kalabalığın ortasındayken bile yalnızlığın bağımsızlığını tam bir sükûnetle koruyabilendir.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100521, author: "Ralph Waldo Emerson", category: "resilience", tags: ["resilience","wisdom"],
    text: "Our strength grows out of our weakness.",
    textTr: "Gücümüz, zayıflığımızdan doğar.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100522, author: "Ralph Waldo Emerson", category: "suffering", tags: ["resilience","wisdom"],
    text: "When he is pushed, tormented, defeated, he has a chance to learn something; he has been put on his wits, on his manhood.",
    textTr: "İnsan itilip kakıldığında, eziyet gördüğünde, yenilgiye uğradığında bir şey öğrenme fırsatı yakalar; aklını ve olgunluğunu sınamak zorunda kalır.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100523, author: "Ralph Waldo Emerson", category: "fire", tags: ["motivation","focus"],
    text: "Nothing great was ever achieved without enthusiasm.",
    textTr: "Hiçbir büyük şey coşku olmadan başarılmamıştır.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100524, author: "Ralph Waldo Emerson", category: "resilience", tags: ["resilience","discipline"],
    text: "Valor consists in the power of self-recovery, so that a man cannot have his flank turned, cannot be out-generalled, but put him where you will, he stands.",
    textTr: "Yiğitlik, kendini yeniden ayağa kaldırma gücünde yatar; öyle ki insan nereye konulursa konulsun sağlam durur, ne alt edilebilir ne de gafil avlanabilir.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100525, author: "Ralph Waldo Emerson", category: "legacy", tags: ["legacy","wisdom"],
    text: "A man's fortunes are the fruit of his character.",
    textTr: "İnsanın kaderi, karakterinin meyvesidir.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100526, author: "Ralph Waldo Emerson", category: "wisdom", tags: ["wisdom","focus"],
    text: "So far as a man thinks, he is free.",
    textTr: "İnsan, düşündüğü ölçüde özgürdür.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100527, author: "Ralph Waldo Emerson", category: "fire", tags: ["motivation","peace"],
    text: "Write it on your heart that every day is the best day in the year.",
    textTr: "Kalbine kazı: yılın en iyi günü, o gün içinde bulunduğun gündür.",
    origin: "ABD", originEmoji: "🇺🇸", era: "modern", packId: "modern-philosophy" },
  { id: 100528, author: "Michel de Montaigne", category: "wisdom", tags: ["wisdom","resilience"],
    text: "The premeditation of death is the premeditation of liberty; he who has learned to die has unlearned to serve.",
    textTr: "Ölümü önceden düşünmek, özgürlüğü önceden düşünmektir; ölmeyi öğrenen, kul olmayı unutmuştur.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100529, author: "Michel de Montaigne", category: "wisdom", tags: ["wisdom","focus"],
    text: "The utility of living consists not in the length of days, but in the use of time.",
    textTr: "Yaşamanın değeri, günlerin uzunluğunda değil, zamanın nasıl kullanıldığındadır.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100530, author: "Michel de Montaigne", category: "suffering", tags: ["resilience","wisdom"],
    text: "Let us disarm him of his novelty and strangeness, let us converse and be familiar with him.",
    textTr: "Onu yabancılığından ve tuhaflığından arındıralım; onunla konuşalım, ona alışalım.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100531, author: "Michel de Montaigne", category: "identity", tags: ["wisdom","reckoning"],
    text: "You yourself only know if you are cowardly and cruel, loyal and devout; others see you not, and only guess at you by uncertain conjectures.",
    textTr: "Korkak mı yoksa zalim mi, sadık mı yoksa vefalı mı olduğunu yalnızca sen bilirsin; başkaları seni göremez, seni ancak belirsiz tahminlerle sezebilir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100532, author: "Michel de Montaigne", category: "regret", tags: ["reckoning","peace"],
    text: "I very rarely repent, and that my conscience is satisfied with itself.",
    textTr: "Çok nadiren pişman olurum; vicdanım kendinden hoşnuttur.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100533, author: "Michel de Montaigne", category: "regret", tags: ["reckoning","peace"],
    text: "Were I to live my life over again, I should live it just as I have lived it.",
    textTr: "Hayatımı yeniden yaşayacak olsam, onu tıpkı yaşadığım gibi yaşardım.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100534, author: "Michel de Montaigne", category: "discipline", tags: ["discipline","wisdom"],
    text: "The virtue of the soul does not consist in flying high, but in walking orderly.",
    textTr: "Ruhun erdemi yükseklerde uçmakta değil, düzenli adımlarla yürümektedir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100535, author: "Michel de Montaigne", category: "legacy", tags: ["wisdom","legacy"],
    text: "Age imprints more wrinkles in the mind than it does on the face.",
    textTr: "Yaş, yüzden çok zihinde kırışıklık bırakır.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100536, author: "Michel de Montaigne", category: "wisdom", tags: ["wisdom","focus"],
    text: "There is no desire more natural than that of knowledge.",
    textTr: "Bilgiden daha doğal bir arzu yoktur.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100537, author: "Michel de Montaigne", category: "identity", tags: ["wisdom","focus"],
    text: "I study myself more than any other subject; 'tis my metaphysic, my physic.",
    textTr: "Kendimi başka her şeyden çok incelerim; benim metafiziğim de fiziğim de budur.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100538, author: "Michel de Montaigne", category: "suffering", tags: ["resilience","discipline"],
    text: "We must learn to suffer what we cannot evade.",
    textTr: "Kaçamayacağımız şeye katlanmayı öğrenmeliyiz.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100539, author: "Michel de Montaigne", category: "identity", tags: ["wisdom","resilience"],
    text: "The greatest thing in the world is for a man to know that he is his own.",
    textTr: "Dünyadaki en büyük şey, insanın kendine ait olduğunu bilmesidir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100540, author: "Michel de Montaigne", category: "discipline", tags: ["discipline","peace"],
    text: "Retire yourself into yourself, but first prepare yourself there to receive yourself.",
    textTr: "Kendi içine çekil; ama önce kendini orada karşılamaya hazırla.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100541, author: "René Descartes", category: "wisdom", tags: ["wisdom","focus"],
    text: "Good sense is, of all things among men, the most equally distributed.",
    textTr: "Sağduyu, insanlar arasında en eşit dağıtılmış şeydir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100542, author: "René Descartes", category: "discipline", tags: ["discipline","focus"],
    text: "To be possessed of a vigorous mind is not enough; the prime requisite is rightly to apply it.",
    textTr: "Güçlü bir zihne sahip olmak yetmez; asıl olan onu doğru biçimde kullanabilmektir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100543, author: "René Descartes", category: "discipline", tags: ["discipline","resilience"],
    text: "My second maxim was to be as firm and resolute in my actions as I was able.",
    textTr: "İkinci ilkem, eylemlerimde elimden geldiğince kararlı ve azimli olmaktı.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100544, author: "René Descartes", category: "resilience", tags: ["resilience","peace"],
    text: "To conquer myself rather than fortune, and change my desires rather than the order of the world.",
    textTr: "Talihi değil kendimi yenmeyi; dünyanın düzenini değil kendi arzularımı değiştirmeyi yeğledim.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100545, author: "René Descartes", category: "identity", tags: ["wisdom","focus"],
    text: "I think, therefore I am.",
    textTr: "Düşünüyorum, öyleyse varım.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100546, author: "René Descartes", category: "wisdom", tags: ["wisdom","discipline"],
    text: "It is the part of prudence not to place absolute confidence in that by which we have even once been deceived.",
    textTr: "Bizi bir kez bile aldatmış olan bir şeye tam güven duymamak, sağduyunun gereğidir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100547, author: "René Descartes", category: "identity", tags: ["wisdom","focus"],
    text: "I am — I exist: this is certain; but how often? As often as I think.",
    textTr: "Ben varım — bu kesin; ama ne zaman? Düşündüğüm her an.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100548, author: "René Descartes", category: "identity", tags: ["wisdom","focus"],
    text: "It is I who doubt, I who understand, and I who desire.",
    textTr: "Şüphe eden benim, anlayan benim, arzu eden benim.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100549, author: "René Descartes", category: "discipline", tags: ["discipline","wisdom"],
    text: "The knowledge of the understanding ought always to precede the determination of the will.",
    textTr: "Anlığın bilgisi, iradenin kararından her zaman önce gelmelidir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100550, author: "René Descartes", category: "identity", tags: ["wisdom","focus"],
    text: "It is certain that I, that is, my mind, is entirely and truly distinct from my body.",
    textTr: "Benim, yani zihnimin, bedenimden tamamen ve gerçekten ayrı olduğu kesindir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "modern", packId: "modern-philosophy" },
  { id: 100551, author: "Friedrich Nietzsche", category: "identity", tags: ["motivation","resilience"],
    text: "Man is something that is to be surpassed.",
    textTr: "İnsan, aşılması gereken bir şeydir.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100552, author: "Friedrich Nietzsche", category: "identity", tags: ["wisdom","motivation"],
    text: "What is great in man is that he is a bridge and not a goal.",
    textTr: "İnsanda büyük olan şey, onun bir amaç değil bir köprü olmasıdır.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100553, author: "Friedrich Nietzsche", category: "fire", tags: ["motivation","focus"],
    text: "One must still have chaos in one, to give birth to a dancing star.",
    textTr: "Dans eden bir yıldız doğurabilmek için insanın içinde hâlâ kaos taşıması gerekir.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100554, author: "Friedrich Nietzsche", category: "fire", tags: ["motivation","discipline"],
    text: "Write with blood, and thou wilt find that blood is spirit.",
    textTr: "Kanla yaz, göreceksin ki kan ruhtur.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100555, author: "Friedrich Nietzsche", category: "resilience", tags: ["resilience","discipline"],
    text: "Thou shalt, is the great dragon called. But the spirit of the lion saith, I will.",
    textTr: "Büyük ejderhanın adı 'Yapmalısın'dır. Ama aslanın ruhu 'İsterim' der.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100556, author: "Friedrich Nietzsche", category: "fire", tags: ["motivation","resilience"],
    text: "Let your work be a fight, let your peace be a victory!",
    textTr: "Çalışman bir mücadele olsun, huzurun ise bir zafer!",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100557, author: "Friedrich Nietzsche", category: "wisdom", tags: ["wisdom","focus"],
    text: "If a man knows the wherefore of his existence, then the manner of it can take care of itself.",
    textTr: "İnsan var oluşunun nedenini bilirse, nasıl yaşayacağı kendiliğinden hallolur.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100558, author: "Friedrich Nietzsche", category: "discipline", tags: ["discipline","reckoning"],
    text: "A man should not play the coward to his deeds. He should not repudiate them once performed.",
    textTr: "İnsan, yaptıklarının önünde korkak olmamalı. Bir kez yapılan şeyi inkâr etmemeli.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100559, author: "Friedrich Nietzsche", category: "resilience", tags: ["resilience","discipline"],
    text: "One should adopt only those situations in which one must either fall or stand—or escape.",
    textTr: "İnsan yalnızca ya düşeceği ya ayakta kalacağı —ya da kaçacağı— durumları göze almalıdır.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100560, author: "Friedrich Nietzsche", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Wisdom sets bounds even to knowledge.",
    textTr: "Bilgelik, bilginin bile önüne sınır koyar.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100561, author: "Friedrich Nietzsche", category: "wisdom", tags: ["focus","wisdom"],
    text: "Only those thoughts that come by walking have any value.",
    textTr: "Yalnızca yürüyerek gelen düşüncelerin bir değeri vardır.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100562, author: "Friedrich Nietzsche", category: "identity", tags: ["wisdom","reckoning"],
    text: "Each one is the farthest away from himself.",
    textTr: "Herkes kendine en uzak olandır.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100563, author: "Friedrich Nietzsche", category: "identity", tags: ["wisdom","reckoning"],
    text: "We have never searched for ourselves—how should it then come to pass, that we should ever find ourselves?",
    textTr: "Kendimizi hiç aramadık ki — o hâlde kendimizi nasıl bulmuş olalım?",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100564, author: "Friedrich Nietzsche", category: "suffering", tags: ["reckoning","wisdom"],
    text: "How much blood and cruelty is the foundation of all good things!",
    textTr: "Bütün iyi şeylerin temelinde ne kadar çok kan ve zulüm var!",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100565, author: "Friedrich Nietzsche", category: "identity", tags: ["peace","focus"],
    text: "Every select man strives instinctively for a citadel and a privacy, where he is free from the crowd, the many, the majority.",
    textTr: "Seçkin her insan, içgüdüsel olarak kalabalıktan, çoğunluktan uzak, kendi kalesini ve mahremiyetini arar.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100566, author: "Friedrich Nietzsche", category: "legacy", tags: ["legacy","wisdom"],
    text: "A man that justifies the existence of man would give cause for hope.",
    textTr: "İnsanın var oluşunu haklı çıkaracak bir insan, umut için bir sebep olurdu.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100567, author: "Immanuel Kant", category: "wisdom", tags: ["wisdom","peace"],
    text: "Two things fill the mind with ever new and increasing admiration and awe, the oftener and the more steadily we reflect on them: the starry heavens above me, and the moral law within me.",
    textTr: "İki şey, üzerlerine ne kadar sık ve ısrarla düşünürsem düşüneyim zihnimi her seferinde yeni bir hayranlık ve derin bir saygıyla doldurur: üstümdeki yıldızlı gökyüzü ve içimdeki ahlak yasası.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100568, author: "Immanuel Kant", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Nothing can possibly be conceived in the world, or even out of it, which can be called good, without qualification, except a good will.",
    textTr: "Dünyada, hatta dünyanın dışında bile, hiçbir koşula bağlı olmaksızın iyi diye adlandırılabilecek tek şey iyi bir istençtir.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100569, author: "Immanuel Kant", category: "discipline", tags: ["discipline","wisdom"],
    text: "Act only on that maxim whereby thou canst at the same time will that it should become a universal law.",
    textTr: "Yalnızca, aynı zamanda evrensel bir yasa olmasını isteyebileceğin ilkeye göre davran.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100570, author: "Immanuel Kant", category: "identity", tags: ["wisdom","legacy"],
    text: "Man exists as an end in himself, not merely as a means to be arbitrarily used by this or that will.",
    textTr: "İnsan, şu ya da bu istencin keyfince kullanacağı bir araç değil, kendinde bir amaç olarak var olur.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100571, author: "Immanuel Kant", category: "discipline", tags: ["discipline","focus"],
    text: "Duty is the necessity of acting from respect for the law.",
    textTr: "Ödev, yasaya duyulan saygıdan hareketle davranma zorunluluğudur.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100572, author: "Immanuel Kant", category: "wisdom", tags: ["reckoning","wisdom"],
    text: "It is a call to reason, again to undertake the most laborious of all tasks—that of self-examination.",
    textTr: "Bu, aklın en zahmetli görevini —kendini sınama görevini— yeniden üstlenmesine yapılan bir çağrıdır.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100573, author: "Immanuel Kant", category: "wisdom", tags: ["wisdom","focus"],
    text: "That all our knowledge begins with experience there can be no doubt.",
    textTr: "Bütün bilgimizin deneyimle başladığından hiç kuşku yoktur.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100574, author: "Immanuel Kant", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Our age is the age of criticism, to which everything must be subjected.",
    textTr: "Çağımız, her şeyin tabi tutulması gereken bir eleştiri çağıdır.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100575, author: "Immanuel Kant", category: "wisdom", tags: ["wisdom","focus"],
    text: "Freedom, however, is the only one of all the ideas of the speculative reason of which we know the possibility a priori.",
    textTr: "Oysa özgürlük, olanaklılığını a priori olarak bildiğimiz, spekülatif aklın tüm fikirleri arasındaki tek fikirdir.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100576, author: "Immanuel Kant", category: "discipline", tags: ["discipline","wisdom"],
    text: "The autonomy of the will is the sole principle of all moral laws and of all duties which conform to them.",
    textTr: "İstencin özerkliği, bütün ahlak yasalarının ve onlara uygun ödevlerin tek ilkesidir.",
    origin: "Almanya", originEmoji: "🇩🇪", era: "modern", packId: "modern-philosophy" },
  { id: 100577, author: "Baruch Spinoza", category: "wisdom", tags: ["wisdom","peace"],
    text: "Blessedness is not the reward of virtue, but virtue itself.",
    textTr: "Mutluluk, erdemin ödülü değil, erdemin kendisidir.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100578, author: "Baruch Spinoza", category: "discipline", tags: ["discipline","peace"],
    text: "The mind has greater power over the emotions and is less subject thereto, in so far as it understands all things as necessary.",
    textTr: "Zihin, her şeyi zorunlu olarak kavradığı ölçüde duygular üzerinde daha büyük bir güce sahip olur ve onlara daha az bağımlı kalır.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100579, author: "Baruch Spinoza", category: "wisdom", tags: ["wisdom","discipline"],
    text: "An emotion, which is a passion, ceases to be a passion, as soon as we form a clear and distinct idea thereof.",
    textTr: "Bir tutku olan duygu, onun açık ve seçik bir fikrini oluşturduğumuz anda tutku olmaktan çıkar.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100580, author: "Baruch Spinoza", category: "wisdom", tags: ["peace","wisdom"],
    text: "The wise man is scarcely at all disturbed in spirit.",
    textTr: "Bilge insanın ruhu neredeyse hiç sarsılmaz.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100581, author: "Baruch Spinoza", category: "suffering", tags: ["reckoning","wisdom"],
    text: "The force whereby a man persists in existing is limited, and is infinitely surpassed by the power of external causes.",
    textTr: "İnsanın var olmayı sürdürdüğü güç sınırlıdır ve dış nedenlerin gücü tarafından sonsuzca aşılır.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100582, author: "Baruch Spinoza", category: "discipline", tags: ["discipline","resilience"],
    text: "An emotion can only be controlled or destroyed by another emotion contrary thereto, and with more power for controlling emotion.",
    textTr: "Bir duygu, ancak ona karşıt ve onu denetleme gücü daha fazla olan başka bir duyguyla denetlenebilir ya da ortadan kaldırılabilir.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100583, author: "Baruch Spinoza", category: "wisdom", tags: ["peace","wisdom"],
    text: "He who lives under the guidance of reason strives, as far as possible, to render back love for other men's hatred.",
    textTr: "Aklın rehberliğinde yaşayan kişi, elinden geldiğince başkalarının nefretine sevgiyle karşılık vermeye çalışır.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100584, author: "Baruch Spinoza", category: "discipline", tags: ["discipline","focus"],
    text: "Desire which springs from reason cannot be excessive.",
    textTr: "Akıldan doğan arzu asla aşırıya kaçamaz.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100585, author: "Baruch Spinoza", category: "identity", tags: ["wisdom","focus"],
    text: "That thing is called free, which exists solely by the necessity of its own nature.",
    textTr: "Özgür denen şey, yalnızca kendi doğasının zorunluluğuyla var olan şeydir.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
  { id: 100586, author: "Baruch Spinoza", category: "wisdom", tags: ["wisdom","legacy"],
    text: "The mind's highest good is the knowledge of God, and the mind's highest virtue is to know God.",
    textTr: "Zihnin en yüksek iyiliği Tanrı bilgisidir, en yüksek erdemi ise Tanrı'yı bilmektir.",
    origin: "Hollanda", originEmoji: "🇳🇱", era: "modern", packId: "modern-philosophy" },
];

