const ASIAN_PROVERBS_QUOTES = [
  { id: 201401, author: "Çin Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "When the old man at the frontier lost his horse, who could say it was not a blessing?",
    textTr: "Sınırdaki yaşlı adam atını kaybettiğinde, bunun bir nimet olmadığını kim söyleyebilirdi?",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201402, author: "Çin Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Bend a hundred times, yet never yield.",
    textTr: "Yüz kez eğil, yine de asla boyun eğme.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201403, author: "Çin Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Grind an iron rod long enough, and it becomes a needle.",
    textTr: "Bir demir çubuğu yeterince bilersen, sonunda iğneye dönüşür.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201404, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "The foolish old man who moved the mountains.",
    textTr: "Dağları yerinden oynatan aptal ihtiyar.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201405, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Like the Jingwei bird, who kept dropping twigs to fill up the sea.",
    textTr: "Denizi doldurmak için dal taşımaya devam eden Jingwei kuşu gibi.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201406, author: "Çin Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Sleep upon brushwood and taste gall, until the debt is repaid.",
    textTr: "Borç ödenene kadar çalı çırpı üstünde uyu, öd tadına bak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201407, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Break the cooking pots and sink the boats — leave no way back.",
    textTr: "Kazanları kır, gemileri batır; geri dönüşü olmasın.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201408, author: "Çin Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Ceaselessly make yourself stronger.",
    textTr: "Durmadan kendini daha güçlü kıl.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201409, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Hack through the brambles and cut down the thorns.",
    textTr: "Dikenleri kes, çalıları yara yara ilerle.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201410, author: "Çin Atasözü", category: "resilience", tags: ["resilience","focus"],
    text: "Face danger without a trace of fear.",
    textTr: "Tehlikeyle yüz yüze gel, korkma.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201411, author: "Çin Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Know the difficulty, and press forward anyway.",
    textTr: "Zorluğu bil, yine de ileri atıl.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201412, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Pull back the raging tide with one's own two hands.",
    textTr: "Azgın dalgayı iki elinle geri çevir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201413, author: "Çin Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Unbending, unbroken, whatever comes.",
    textTr: "Ne olursa olsun eğilmeyen, kırılmayan.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201414, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Advance without ever looking back.",
    textTr: "Hiç arkana bakmadan ileri git.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201415, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Cross the mountains, wade through the rivers.",
    textTr: "Dağları aş, nehirleri geç.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201416, author: "Çin Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "A boat against the current must keep rowing, or be swept back.",
    textTr: "Akıntıya karşı giden bir tekne kürek çekmeye devam etmeli, yoksa geri sürüklenir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201417, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "When hearts unite, they build a wall of bronze.",
    textTr: "Yürekler birleştiğinde tunçtan bir sur örer.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201418, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Advance bravely straight into the rushing current.",
    textTr: "Coşkun akıntının içine cesurca ilerle.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201419, author: "Çin Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Gather thickly for a long while, so the release, when it comes, is sudden and sure.",
    textTr: "Uzun süre biriktir; geldiğinde patlama ani ve kesin olsun.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201420, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "When the water arrives, the channel forms itself.",
    textTr: "Su ulaştığında kanal kendiliğinden oluşur.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201421, author: "Çin Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "When misfortune reaches its very peak, good fortune is sure to follow.",
    textTr: "Kötü talih doruğuna ulaştığında, iyi talih mutlaka ardından gelir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201422, author: "Çin Atasözü", category: "suffering", tags: ["resilience","peace"],
    text: "When the bitterness is spent, the sweetness comes.",
    textTr: "Acı tükendiğinde tatlılık gelir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201423, author: "Çin Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Willows in shadow, blossoms in light — and suddenly, another village.",
    textTr: "Söğütler gölgede, çiçekler ışıkta — ve birden, bir köy daha.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201424, author: "Çin Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "If you do not enter the tiger's den, how will you ever catch its cub?",
    textTr: "Kaplanın inine girmezsen, yavrusunu nasıl yakalarsın?",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201425, author: "Çin Atasözü", category: "suffering", tags: ["resilience","discipline"],
    text: "Chew on bitterness, swallow the hardship, and carry on.",
    textTr: "Acıyı çiğne, zorluğu yut, yoluna devam et.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201426, author: "Çin Atasözü", category: "suffering", tags: ["resilience","discipline"],
    text: "Bear the humiliation and carry the heavy burden all the same.",
    textTr: "Aşağılanmaya katlan, ağır yükü yine de taşı.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201427, author: "Çin Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Throw the whole of your strength into it.",
    textTr: "Bütün gücünü ortaya koy.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201428, author: "Çin Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Never refuse the toil, however hard it comes.",
    textTr: "Zorluk ne kadar ağır olursa olsun emekten kaçınma.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201429, author: "Çin Atasözü", category: "resilience", tags: ["resilience","reckoning"],
    text: "Driven by injustice to take the mountain road to Liangshan.",
    textTr: "Haksızlık yüzünden Liangshan dağına çıkmaya zorlanmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201430, author: "Çin Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Ten years beside the cold window before the light of success.",
    textTr: "Başarının ışığından önce soğuk pencerede geçen on yıl.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201431, author: "Çin Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Whip the fast horse onward still faster.",
    textTr: "Hızlı atı daha da hızlandırmak için kırbaçla.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201432, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","resilience"],
    text: "A single beam cannot hold up the whole house.",
    textTr: "Tek bir kiriş bütün evi ayakta tutamaz.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201433, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "The sea is vast because it refuses no river.",
    textTr: "Deniz, hiçbir nehri geri çevirmediği için engindir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201434, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Know what is enough, and joy will last.",
    textTr: "Yeterince olanı bil, sevinç kalıcı olsun.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201435, author: "Çin Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "One wave breaks into three folds before it reaches the shore.",
    textTr: "Bir dalga kıyıya varmadan üç kez kırılır.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201436, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "When a thing reaches its extreme, it turns into its opposite.",
    textTr: "Bir şey aşırıya ulaştığında, tam tersine döner.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201437, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "When the melon ripens, the stem lets go on its own.",
    textTr: "Kavun olgunlaştığında, sapı kendiliğinden düşer.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201438, author: "Çin Atasözü", category: "identity", tags: ["peace","wisdom"],
    text: "With the four seas as home, no single shore can hold you.",
    textTr: "Dört deniz senin evinse, hiçbir kıyı seni tutamaz.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201439, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Going too far is no better than not going far enough.",
    textTr: "Fazla ileri gitmek, yeterince ileri gitmemekten daha iyi değildir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201440, author: "Çin Atasözü", category: "identity", tags: ["peace","wisdom"],
    text: "Walk slowly, and let that be your carriage.",
    textTr: "Yavaşça yürü; bu senin arabana yetsin.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201441, author: "Çin Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Settle in peace, and take joy in your work.",
    textTr: "Huzur içinde yerleş, işinde sevinç bul.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201442, author: "Çin Atasözü", category: "suffering", tags: ["resilience","wisdom"],
    text: "Weathered by every upheaval the world can offer.",
    textTr: "Dünyanın sunabileceği her sarsıntıyla yıpranmış.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201443, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Where the blue sea once rolled, mulberry fields now grow.",
    textTr: "Bir zamanlar mavi denizin dalgalandığı yerde şimdi dut tarlaları var.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201444, author: "Çin Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Follow things as they naturally are.",
    textTr: "Her şeyi kendi doğal akışında bırak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201445, author: "Çin Atasözü", category: "fire", tags: ["reckoning","wisdom"],
    text: "To carry firewood in hopes of putting out a fire.",
    textTr: "Ateşi söndürmek umuduyla odun taşımak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201446, author: "Çin Atasözü", category: "fire", tags: ["reckoning","discipline"],
    text: "To draw the fire that burns oneself.",
    textTr: "Kendini yakacak ateşi kendi eliyle çağırmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201447, author: "Çin Atasözü", category: "fire", tags: ["wisdom","focus"],
    text: "To watch the fire burn from the far bank of the river.",
    textTr: "Ateşin karşı kıyıdan yanışını izlemek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201448, author: "Çin Atasözü", category: "fire", tags: ["focus","wisdom"],
    text: "To see through it as clearly as watching a fire in the dark.",
    textTr: "Karanlıkta yanan bir ateşi izler gibi her şeyi apaçık görmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201449, author: "Çin Atasözü", category: "fire", tags: ["reckoning","wisdom"],
    text: "When fire breaks out at the city gate, even the fish in the moat suffer for it.",
    textTr: "Şehir kapısında yangın çıktığında, hendekteki balıklar bile bundan zarar görür.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201450, author: "Çin Atasözü", category: "fire", tags: ["reckoning","discipline"],
    text: "Like a moth that flings itself into the flame.",
    textTr: "Alevin içine kendini atan bir güve gibi.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201451, author: "Çin Atasözü", category: "fire", tags: ["reckoning","focus"],
    text: "Anger rising like flames three zhang high.",
    textTr: "Öfke, üç zhang boyunda alevler gibi yükseliyor.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201452, author: "Çin Atasözü", category: "fire", tags: ["focus","discipline"],
    text: "The furnace fire has turned pure blue — mastery achieved.",
    textTr: "Ocaktaki ateş artık som mavi — ustalığa ulaşıldı.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201453, author: "Çin Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "To wade through boiling water and walk through fire, whatever it takes.",
    textTr: "Ne gerekiyorsa yap; kaynar suda yürü, ateşte adım at.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201454, author: "Çin Atasözü", category: "fire", tags: ["reckoning","discipline"],
    text: "Play with fire, and you will burn yourself.",
    textTr: "Ateşle oynarsan, kendini yakarsın.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201455, author: "Çin Atasözü", category: "fire", tags: ["reckoning","focus"],
    text: "Pouring oil onto a fire already burning.",
    textTr: "Zaten yanan bir ateşin üzerine yağ dökmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201456, author: "Çin Atasözü", category: "fire", tags: ["focus","motivation"],
    text: "A heart so anxious it feels as if it is burning.",
    textTr: "Öylesine tedirgin bir kalp ki sanki yanıyor.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201457, author: "Çin Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "Blazing like fire, flourishing like the white reed-flowers in bloom.",
    textTr: "Ateş gibi alev alev, çiçek açan sazlar gibi coşkuyla.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201458, author: "Çin Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "At the rooster's first crow, rise and practice the sword.",
    textTr: "Horoz ilk ötüşünde kalk ve kılıç talimine başla.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201459, author: "Çin Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Knowledge and action are one and the same.",
    textTr: "Bilgi ve eylem tek ve aynı şeydir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201460, author: "Çin Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Heaven's way is to reward the diligent.",
    textTr: "Göğün yolu, çalışkanı ödüllendirmektir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201461, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Toss out a brick to draw back a piece of jade.",
    textTr: "Bir tuğla at ki karşılığında bir yeşim taşı gelsin.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201462, author: "Çin Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "The clumsy bird takes flight first.",
    textTr: "Beceriksiz kuş önce uçar.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201463, author: "Çin Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "Keep a mind as open and humble as a valley.",
    textTr: "Zihnini bir vadi kadar açık ve alçakgönüllü tut.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201464, author: "Çin Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Carry your own cup over and ask humbly to be taught.",
    textTr: "Kendi kadehini al, git ve alçakgönüllülükle öğret diye rica et.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201465, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "To view the sky through a tube and measure the sea with a gourd.",
    textTr: "Gökyüzünü bir borudan bakıp denizi bir kabakla ölçmeye çalışmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201466, author: "Çin Atasözü", category: "identity", tags: ["peace","wisdom"],
    text: "Neither servile nor arrogant — dignity held steady.",
    textTr: "Ne köle gibi eğilmek ne kibirlenmek — onuru sağlam tut.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201467, author: "Çin Atasözü", category: "regret", tags: ["reckoning","resilience"],
    text: "Songs of Chu rising from every side — surrounded, with no way out.",
    textTr: "Her yandan yükselen Chu şarkıları — çepeçevre kuşatılmış, çıkış yok.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201468, author: "Çin Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Mend the roof and gather the thatch before the rain ever falls.",
    textTr: "Yağmur yağmadan önce çatıyı onar, sazları topla.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201469, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Before the brush touches paper, the whole bamboo already stands complete in the painter's chest.",
    textTr: "Fırça kağıda değmeden önce, bambu ressamın göğsünde çoktan tamamlanmıştır.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201470, author: "Çin Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Tie your hair to the rafter, prick your thigh with an awl — whatever it takes to stay awake and study.",
    textTr: "Saçını tavan kirişine bağla, uyluğunu bizle dürt — çalışmaya devam etmek için ne gerekiyorsa yap.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201471, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To discuss warfare only on paper, and never on the battlefield.",
    textTr: "Savaşı yalnızca kağıt üzerinde tartışmak, hiç meydanda değil.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201472, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Mend the pen after the sheep has already gone missing — better late than never.",
    textTr: "Koyun kaybolduktan sonra ağılı onarmak — geç olsun da güç olmasın.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201473, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "Dongshi copies the beauty's frown, and only makes herself absurd.",
    textTr: "Dongshi, güzelin kaşlarını çatışını taklit eder ama sadece kendini gülünç duruma düşürür.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201474, author: "Çin Atasözü", category: "legacy", tags: ["legacy","motivation"],
    text: "A name that hangs forever in the pages of history.",
    textTr: "Tarihin sayfalarında sonsuza dek asılı kalan bir isim.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201475, author: "Çin Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "A fragrance that lingers for a hundred generations.",
    textTr: "Yüz nesil boyunca süren bir koku.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201476, author: "Çin Atasözü", category: "legacy", tags: ["legacy","motivation"],
    text: "Known and named across the entire world.",
    textTr: "Bütün dünyada bilinen ve adı geçen.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201477, author: "Çin Atasözü", category: "legacy", tags: ["legacy","focus"],
    text: "The eyes of the whole world fixed on it.",
    textTr: "Bütün dünyanın gözleri onun üzerinde.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201478, author: "Çin Atasözü", category: "legacy", tags: ["legacy","focus"],
    text: "The first finger bent when counting the best.",
    textTr: "En iyiler sayılırken önce bükülen parmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201479, author: "Çin Atasözü", category: "legacy", tags: ["legacy","motivation"],
    text: "To rise head and shoulders above the crowd.",
    textTr: "Kalabalığın baş ve omuz üstünde yükselmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201480, author: "Çin Atasözü", category: "legacy", tags: ["legacy","motivation"],
    text: "Talented people emerge, generation after generation.",
    textTr: "Yetenekli insanlar nesilden nesile ortaya çıkar.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201481, author: "Çin Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "A resolute will can even overcome heaven itself.",
    textTr: "Kararlı bir irade, göğü bile yenebilir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201482, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Show one corner, and let the mind infer the other three.",
    textTr: "Bir köşeyi göster, zihin diğer üçünü çıkarsın.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201483, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Gather every mind's thoughts, and the benefit grows wide.",
    textTr: "Her zihnin düşüncesini topla, fayda genişlesin.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201484, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "An open spear is easy to dodge; a hidden arrow is hard to guard against.",
    textTr: "Açık mızraktan kaçmak kolaydır; gizli okdan korunmak zordur.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201485, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Follow the vine, and your hand will find the melon.",
    textTr: "Sarmaşığı takip et, elin kavunu bulur.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201486, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Sharp enough to perceive the down of an autumn hair.",
    textTr: "Sonbahar tüyünün en incesini bile fark edecek kadar keskin.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201487, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "A mind clear as a polished mirror, still as unmoving water.",
    textTr: "Cilalı bir ayna kadar berrak, durgun bir su kadar sakin bir zihin.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201488, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "The wise man knows how to keep himself out of harm's way.",
    textTr: "Bilge kişi kendini zarardan uzak tutmayı bilir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201489, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "To think oneself clever, and be a fool for it.",
    textTr: "Kendini akıllı sanmak, ama bu yüzden aptal olmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201490, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "The fox borrows the tiger's terror to seem fearsome itself.",
    textTr: "Tilki, korkunç görünmek için kaplanın gücünü ödünç alır.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201491, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "Steal the beam away, and replace it with a false pillar.",
    textTr: "Kirişi çal, yerine sahte bir direk koy.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201492, author: "Çin Atasözü", category: "identity", tags: ["focus","wisdom"],
    text: "A single leaf held before the eyes can block out the whole mountain.",
    textTr: "Göze tutulan tek bir yaprak, koca dağı bile gizleyebilir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201493, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To finish painting the snake, and then ruin it by adding legs.",
    textTr: "Yılan resmini bitirip sonra bacak ekleyerek onu berbat etmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201494, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "To offer flowers one has borrowed, as if the gift were one's own.",
    textTr: "Ödünç aldığın çiçekleri, sanki kendi hediyenmiş gibi sunmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201495, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "Three men repeat a lie, and a tiger walks the marketplace.",
    textTr: "Üç kişi bir yalanı tekrarlarsa, çarşıda bir kaplan dolaşmaya başlar.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201496, author: "Çin Atasözü", category: "identity", tags: ["reckoning","peace"],
    text: "To mistake a bow's reflection in the wine cup for a snake.",
    textTr: "Kadehteki yayın yansımasını yılan sanmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201497, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "To contradict one's own spear with one's own shield.",
    textTr: "Kendi mızrağıyla kendi kalkanını çelişkiye düşürmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201498, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "Lord Ye loved dragons — until a real one came to his door.",
    textTr: "Lord Ye ejderhaları severdi — ta ki gerçek biri kapısına gelene kadar.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201499, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "The small kingdom of Yelang believed itself the greatest under heaven.",
    textTr: "Küçük Yelang krallığı kendini göğün altındaki en büyük yer sanırdı.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201500, author: "Çin Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "Dot in the eyes, and the painted dragon comes alive.",
    textTr: "Gözleri çiz, resmedilen ejderha canlansın.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201501, author: "Çin Atasözü", category: "identity", tags: ["motivation","focus"],
    text: "When no one else steps forward, recommend yourself.",
    textTr: "Kimse öne çıkmadığında, kendini öner.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201502, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "The donkey of Qian has finally run out of tricks.",
    textTr: "Qian'ın eşeği artık bütün numaralarını tüketti.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201503, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Guard the tree stump, waiting for another rabbit to run into it.",
    textTr: "Ağaç kütüğünü bekle, bir tavşanın daha ona çarpmasını bekleyerek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201504, author: "Çin Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "A frog at the bottom of a well thinks the sky is only as wide as its rim.",
    textTr: "Kuyunun dibindeki kurbağa, gökyüzünün yalnızca kuyunun ağzı kadar geniş olduğunu sanır.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201505, author: "Çin Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "To play the finest music for a cow.",
    textTr: "En güzel müziği bir inek için çalmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201506, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To carve a mark on the boat to remember where the sword fell into the river.",
    textTr: "Kılıcın nehre düştüğü yeri hatırlamak için teknenin üstüne bir çentik atmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201507, author: "Çin Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "To show off one's axework at the door of master carpenter Lu Ban.",
    textTr: "Usta marangoz Lu Ban'ın kapısında baltacılık taslamak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201508, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "Three in the morning, four in the evening — and the monkeys were satisfied, though the total never changed.",
    textTr: "Sabah üç, akşam dört — toplam hiç değişmediği halde maymunlar tatmin oldu.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201509, author: "Çin Atasözü", category: "suffering", tags: ["reckoning","peace"],
    text: "A bird once startled by a bowstring flinches at the sound forever after.",
    textTr: "Bir zamanlar yay sesiyle ürken kuş, ondan sonra o sesi her duyduğunda irkilir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201510, author: "Çin Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "A whole lifetime dreamed away before the millet finishes cooking.",
    textTr: "Darı pişmeden önce koca bir ömür rüyada yaşanıp bitti.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201511, author: "Çin Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Better to go home and weave a net than stand by the pond envying the fish.",
    textTr: "Havuzun kenarında balığa özenmektense, eve gidip ağ örmek daha iyidir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201512, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "The man of Zheng trusted his paper measurements over his own feet.",
    textTr: "Zheng'li adam, kendi ayaklarından çok kağıda yazdığı ölçüye güvendi.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201513, author: "Çin Atasözü", category: "legacy", tags: ["reckoning","legacy"],
    text: "A gate so deserted that sparrows could be netted right at the door.",
    textTr: "Kapı öylesine ıssız ki, tam eşiğinde serçe avlanabilir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201514, author: "Çin Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "To quench one's thirst with poisoned wine.",
    textTr: "Susuzluğunu zehirli şarapla gidermek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201515, author: "Çin Atasözü", category: "identity", tags: ["reckoning","focus"],
    text: "When two tigers fight, one of them is bound to be wounded.",
    textTr: "İki kaplan dövüştüğünde, biri mutlaka yaralanır.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201516, author: "Çin Atasözü", category: "identity", tags: ["reckoning","resilience"],
    text: "Once you are riding the tiger, it is hard to dismount.",
    textTr: "Bir kez kaplana binince, inmek zordur.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201517, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To bargain with the tiger for its own hide.",
    textTr: "Kaplanla kendi postu için pazarlık etmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201518, author: "Çin Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "A tiger's head that tapers away into a snake's tail.",
    textTr: "Bir kaplan başıyla başlayıp bir yılan kuyruğuyla biten.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201519, author: "Çin Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "Like a tiger given wings.",
    textTr: "Kanatlanmış bir kaplan gibi.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201520, author: "Çin Atasözü", category: "identity", tags: ["peace","wisdom"],
    text: "The man of Qi who feared the very sky might fall.",
    textTr: "Qi'li adam, gökyüzünün başına düşeceğinden korkardı.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201521, author: "Çin Atasözü", category: "suffering", tags: ["reckoning","peace"],
    text: "Seeing an enemy soldier in every blade of grass and every tree.",
    textTr: "Her otta, her ağaçta bir düşman askeri görmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201522, author: "Çin Atasözü", category: "suffering", tags: ["reckoning","peace"],
    text: "Mistaking the wind's sound and a crane's cry for the enemy's approach.",
    textTr: "Rüzgarın sesini ve turnanın çığlığını düşmanın yaklaşması sanmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201523, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Beyond the narrow entrance, an unexpected paradise opens up.",
    textTr: "Dar girişin ötesinde, beklenmedik bir cennet açılır.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201524, author: "Çin Atasözü", category: "legacy", tags: ["legacy","motivation"],
    text: "To break through the ancient wasteland and achieve what none before ever did.",
    textTr: "Kadim çorak toprağı kırıp daha önce kimsenin başaramadığını başarmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201525, author: "Çin Atasözü", category: "identity", tags: ["reckoning","focus"],
    text: "To hold the chess piece in hand, unable to decide where it falls.",
    textTr: "Satranç taşını elde tutup nereye koyacağına karar verememek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201526, author: "Çin Atasözü", category: "identity", tags: ["reckoning","focus"],
    text: "One foot in each of two separate boats.",
    textTr: "Bir ayağı bir teknede, öbür ayağı başka bir teknede.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201527, author: "Çin Atasözü", category: "discipline", tags: ["focus","reckoning"],
    text: "Tend to this, and lose hold of that.",
    textTr: "Buna dikkat edip, ötekini kaçırmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201528, author: "Çin Atasözü", category: "identity", tags: ["reckoning","peace"],
    text: "So carried away by the moment that one forgets who one is.",
    textTr: "Anın etkisiyle kendini o kadar kaptırmak ki kim olduğunu unutmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201529, author: "Çin Atasözü", category: "identity", tags: ["reckoning","legacy"],
    text: "To grow arrogant, leaning on one's own past achievements.",
    textTr: "Geçmiş başarılarına yaslanıp kibirlenmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201530, author: "Çin Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "To reach for distant, lofty goals while the ground beneath the feet goes unattended.",
    textTr: "Ayaklarının bastığı zemini ihmal ederken uzak ve yüce hedeflere uzanmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201531, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "A gaze so proud that it sees no one else in the room.",
    textTr: "Öylesine kibirli bir bakış ki odada başka kimseyi görmez.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201532, author: "Çin Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "To command others with nothing more than a tilt of the chin.",
    textTr: "Başkalarını yalnızca çenesini kaldırarak yönetmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201533, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Every cause carries its own consequence.",
    textTr: "Her sebep kendi sonucunu taşır.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201534, author: "Çin Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "Spilled water cannot be gathered back into the cup.",
    textTr: "Dökülen su kadehe geri toplanamaz.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201535, author: "Çin Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "The string of evil deeds has finally been pulled taut and full.",
    textTr: "Kötülük ipi sonunda gerilip dolmuş.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201536, author: "Çin Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "To carry thorns upon one's own back and beg forgiveness.",
    textTr: "Sırtında dikenler taşıyıp af dilemek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201537, author: "Çin Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "To eat, in the end, the very fruit one has sown.",
    textTr: "Sonunda kendi ektiğin meyveyi yemek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201538, author: "Çin Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Undeterred, whether by wind or by rain.",
    textTr: "İster rüzgar ister yağmur olsun, yıldırılmadan.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201539, author: "Çin Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "To fight for every minute, to seize every second.",
    textTr: "Her dakika için mücadele etmek, her saniyeyi ele geçirmek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201540, author: "Çin Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Feet planted firmly on solid ground.",
    textTr: "Ayaklar sağlam zemine sıkıca basılı.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201541, author: "Çin Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "With one heart and one mind, wholly devoted to the task.",
    textTr: "Tek bir yürek ve tek bir zihinle, göreve tamamen adanmış.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201542, author: "Çin Atasözü", category: "legacy", tags: ["legacy","discipline"],
    text: "Bow low and give one's utmost, until only death can end the labor.",
    textTr: "Eğil ve elinden gelenin tamamını ver; ancak ölüm bu emeği bitirebilir.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201543, author: "Çin Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "The burden is heavy, and the road ahead is long.",
    textTr: "Yük ağır, önündeki yol uzun.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201544, author: "Çin Atasözü", category: "suffering", tags: ["resilience","discipline"],
    text: "To eat in the open wind and sleep beneath the dew.",
    textTr: "Açık rüzgarda yemek yemek, çiy altında uyumak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201545, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","resilience"],
    text: "The old horse still remembers the way home.",
    textTr: "Yaşlı at, eve giden yolu hâlâ hatırlar.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201546, author: "Çin Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "When you drink the water, remember who dug the well.",
    textTr: "Suyu içerken, kuyuyu kimin kazdığını hatırla.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201547, author: "Çin Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "Like the spring wind and its gentle rain, quietly nourishing what it touches.",
    textTr: "Bahar rüzgarı ve nazik yağmuru gibi, dokunduğunu sessizce besleyerek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201548, author: "Çin Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "The season turns, and fortune turns along with it.",
    textTr: "Mevsim döner, talih de onunla birlikte döner.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201549, author: "Çin Atasözü", category: "legacy", tags: ["legacy","motivation"],
    text: "The rare meeting of wind and cloud that gives rise to a hero.",
    textTr: "Bir kahramanı doğuran, rüzgar ile bulutun ender buluşması.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201550, author: "Çin Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "A tune too refined finds few voices able to join it.",
    textTr: "Fazla incelikli bir ezgiye eşlik edebilecek pek az ses vardır.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201551, author: "Çin Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "To sleep with one's spear as a pillow, waiting for the dawn.",
    textTr: "Mızrağı yastık yapıp şafağı beklemek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201552, author: "Çin Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "To renew one's own strength, relying on no one else.",
    textTr: "Başka kimseye güvenmeden kendi gücünü yenilemek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201553, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "See the smallest sign, and already know the whole.",
    textTr: "En küçük belirtiyi gör, bütünü çoktan bilmiş ol.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201554, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Trace the stream all the way back to its very source.",
    textTr: "Nehri kaynağına dek geriye takip et.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201555, author: "Çin Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Advance step by step, fortifying a camp at every stop.",
    textTr: "Adım adım ilerle, her durakta bir karargah kur.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201556, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To swallow the whole date without ever chewing it.",
    textTr: "Hurmayı hiç çiğnemeden bütün yutmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201557, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To scratch an itch through the boot, and never quite reach it.",
    textTr: "Kaşıntıyı çizmenin üzerinden kaşımak, asla tam olarak ulaşamadan.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201558, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Blind men each touch a different part of the elephant, and each swears he knows the whole beast.",
    textTr: "Kör adamlar filin farklı bir yerine dokunur, her biri bütün hayvanı bildiğine yemin eder.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201559, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To search for a fine horse by matching it exactly to an old picture.",
    textTr: "İyi bir atı, eski bir resme harfiyen uydurarak aramak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201560, author: "Çin Atasözü", category: "legacy", tags: ["legacy","motivation"],
    text: "To rise above one's own kind and stand out from all the rest.",
    textTr: "Kendi türünün üstüne çıkıp geri kalan herkesten sıyrılmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201561, author: "Çin Atasözü", category: "identity", tags: ["peace","wisdom"],
    text: "An ordinary man troubles himself over what was never a problem at all.",
    textTr: "Sıradan bir adam, hiç sorun olmayan bir şey yüzünden kendini üzer.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201562, author: "Çin Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Let one's words and one's deeds walk the very same road.",
    textTr: "Sözlerinle eylemlerin aynı yoldan yürüsün.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201563, author: "Çin Atasözü", category: "identity", tags: ["discipline","peace"],
    text: "To hold her through the night and let one's heart remain undisturbed.",
    textTr: "Onu bütün gece kollarında tutup yüreğini yine de bozmadan tutmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201564, author: "Çin Atasözü", category: "identity", tags: ["discipline","legacy"],
    text: "To be true to one's own word.",
    textTr: "Kendi sözüne sadık kalmak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201565, author: "Çin Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To let words pour out carelessly, like a river breaking its banks.",
    textTr: "Sözlerin, bir nehrin setlerini yıkması gibi dikkatsizce akmasına izin vermek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201566, author: "Çin Atasözü", category: "identity", tags: ["peace","wisdom"],
    text: "To open one's sincerity and lay one's fairness bare for all to see.",
    textTr: "İçtenliğini açmak, adaletini herkesin görebileceği şekilde ortaya sermek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201567, author: "Çin Atasözü", category: "identity", tags: ["peace","discipline"],
    text: "To labor in silence, unknown to the world.",
    textTr: "Dünyaya bilinmeden, sessizce emek vermek.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201568, author: "Çin Atasözü", category: "identity", tags: ["discipline","legacy"],
    text: "To hold fast to what is right, and bend for no one.",
    textTr: "Doğru olana sıkı sıkıya sarıl, kimseye eğilme.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201569, author: "Çin Atasözü", category: "legacy", tags: ["legacy","discipline"],
    text: "The jade returned to Zhao whole and unbroken.",
    textTr: "Yeşim taşı Zhao'ya bütün ve kırılmadan geri döndü.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201570, author: "Çin Atasözü", category: "legacy", tags: ["legacy","discipline"],
    text: "A single promise, worth a thousand pieces of gold.",
    textTr: "Tek bir söz, bin altın değerinde.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201571, author: "Çin Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "To pluck it effortlessly from a hand already full of mastery.",
    textTr: "Ustalıkla dolu bir elden onu zahmetsizce çekip almak.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201572, author: "Çin Atasözü", category: "legacy", tags: ["legacy","discipline"],
    text: "Three humble visits to a thatched cottage, to win over a reluctant sage.",
    textTr: "İnatçı bir bilgeyi kazanmak için saz kulübeye üç kez alçakgönüllü ziyaret.",
    origin: "Çin", originEmoji: "🇨🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201573, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Good medicine tastes bitter to the mouth.",
    textTr: "İyi ilaç ağza acı gelir.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201574, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Trying to straighten the horns kills the ox.",
    textTr: "Boynuzu doğrultmaya çalışmak öküzü öldürür.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201575, author: "Japon Atasözü", category: "identity", tags: ["wisdom"],
    text: "In a village with no birds, the bat is king.",
    textTr: "Kuşu olmayan köyde yarasa kral kesilir.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201576, author: "Japon Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "If you've eaten the poison, lick the plate too.",
    textTr: "Zehri yuttuysan tabağı da yala.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201577, author: "Japon Atasözü", category: "discipline", tags: ["discipline"],
    text: "Rising early is worth three coins of virtue.",
    textTr: "Erken kalkmak üç meteliklik erdem kazandırır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201578, author: "Japon Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "The foolish old man moves the mountain.",
    textTr: "Ahmak ihtiyar dağı yerinden oynatır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201579, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Even a mutter alone in a well is known after three years.",
    textTr: "Kuyuda kendi kendine söylenen fısıltı bile üç yıl sonra duyulur.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201580, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The wisdom of age outweighs the shell of the tortoise.",
    textTr: "Yaşın bilgeliği kaplumbağanın kabuğundan ağır basar.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201581, author: "Japon Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "One inch ahead of you lies only darkness.",
    textTr: "Bir parmak ötesi zaten karanlıktır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201582, author: "Japon Atasözü", category: "identity", tags: ["legacy"],
    text: "The fruit falls back to the roots of its tree.",
    textTr: "Meyve, kendi ağacının köküne düşer.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201583, author: "Japon Atasözü", category: "legacy", tags: ["legacy"],
    text: "A bird in flight leaves no mess behind.",
    textTr: "Uçup giden kuş arkasında pislik bırakmaz.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201584, author: "Japon Atasözü", category: "identity", tags: ["legacy"],
    text: "Such a father, such a child.",
    textTr: "Öyle baba, öyle evlat.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201585, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The eyes speak as much as the mouth.",
    textTr: "Gözler, ağız kadar çok şey söyler.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201586, author: "Japon Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "The mouth is the root of misfortune.",
    textTr: "Ağız, felaketin köküdür.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201587, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Not knowing is Buddha.",
    textTr: "Bilmemek Buda olmaktır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201588, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "It is darkest at the base of the lighthouse.",
    textTr: "Deniz fenerinin dibi karanlıktır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201589, author: "Japon Atasözü", category: "identity", tags: ["wisdom"],
    text: "Ten people, ten colors.",
    textTr: "On kişi, on renk.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201590, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Study the old to know the new.",
    textTr: "Yeniyi bilmek için eskiyi incele.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201591, author: "Japon Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Cutting and polishing each other, like gems.",
    textTr: "Mücevherler gibi birbirini yontup parlatmak.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201592, author: "Japon Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Dripping water wears through stone.",
    textTr: "Damlayan su taşı deler.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201593, author: "Japon Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "Take up your position with your back to the river.",
    textTr: "Sırtını nehre dayamış saflar kur.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201594, author: "Japon Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Those who meet are destined to part.",
    textTr: "Buluşanların ayrılması alın yazısıdır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201595, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Reciting sutras into a horse's ear.",
    textTr: "Atın kulağına dua okumak.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201596, author: "Japon Atasözü", category: "identity", tags: ["legacy"],
    text: "A frog's child is a frog.",
    textTr: "Kurbağanın yavrusu kurbağadır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201597, author: "Japon Atasözü", category: "regret", tags: ["reckoning","motivation"],
    text: "Time flies like an arrow.",
    textTr: "Zaman ok gibi uçar.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201598, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "One time, one meeting.",
    textTr: "Bir an, bir buluşma.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201599, author: "Japon Atasözü", category: "discipline", tags: ["discipline"],
    text: "A monk for three days.",
    textTr: "Üç günlük keşiş.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201600, author: "Japon Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Better to grow accustomed to it than merely to learn it.",
    textTr: "Öğrenmektense alışmak daha iyidir.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201601, author: "Japon Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "Charging forward like a wild boar.",
    textTr: "Yaban domuzu gibi ileri atılmak.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201602, author: "Japon Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "One stroke, two clean halves.",
    textTr: "Tek darbeyle ikiye ayırmak.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201603, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Suspicion breeds demons in the dark.",
    textTr: "Kuşku, karanlıkta hayaletler doğurur.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201604, author: "Japon Atasözü", category: "resilience", tags: ["resilience"],
    text: "Nine deaths for one life.",
    textTr: "Dokuz ölüm, bir hayat.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201605, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Cause brings its own effect.",
    textTr: "Sebep, kendi sonucunu doğurur.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201606, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Not seeing it is the flower.",
    textTr: "Görmemek, çiçeğin ta kendisidir.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201607, author: "Japon Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "Giving birth is easier than fearing it.",
    textTr: "Doğurmak, ondan korkmaktan daha kolaydır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201608, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Gold coins offered to a cat.",
    textTr: "Kediye altın para vermek.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201609, author: "Japon Atasözü", category: "discipline", tags: ["discipline"],
    text: "Three years sitting on a stone.",
    textTr: "Bir taşın üstünde üç yıl oturmak.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201610, author: "Japon Atasözü", category: "resilience", tags: ["resilience"],
    text: "After the rain, the ground hardens.",
    textTr: "Yağmurdan sonra toprak sertleşir.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201611, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Fortune comes to the house that laughs.",
    textTr: "Talih, güldüğü kapıya gelir.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201612, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Tomorrow is tomorrow, today is today.",
    textTr: "Yarın yarındır, bugün bugündür.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201613, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Hiding the head while the tail shows.",
    textTr: "Başını saklayıp kuyruğunu saklayamamak.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201614, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Fortune lies in what others leave behind.",
    textTr: "Talih, başkalarının artakalanında saklıdır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201615, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "If the fish is kind to the water, the water is kind to the fish.",
    textTr: "Balık suya iyi davranırsa, su da balığa iyi davranır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201616, author: "Japon Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "To eat rice from the same pot.",
    textTr: "Aynı kazandan pilav yemek.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201617, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "When three gather, the wisdom of a sage appears.",
    textTr: "Üç kişi bir araya gelince bilgelik doğar.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201618, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A nearby stranger is worth more than a distant relative.",
    textTr: "Yakındaki yabancı, uzaktaki akrabadan değerlidir.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201619, author: "Japon Atasözü", category: "suffering", tags: ["resilience"],
    text: "A bee stings the face that is already crying.",
    textTr: "Ağlayan yüze bir de arı sokar.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201620, author: "Japon Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "Without entering the tiger's den, you cannot catch its cub.",
    textTr: "Kaplanın inine girmeden yavrusunu yakalayamazsın.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201621, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Your own deeds bring their own reward.",
    textTr: "Kendi işin, kendi karşılığındır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201622, author: "Japon Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Never forget the spirit you had as a beginner.",
    textTr: "Acemilik ruhunu asla unutma.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201623, author: "Japon Atasözü", category: "legacy", tags: ["legacy"],
    text: "The strength holding up the floor from beneath.",
    textTr: "Döşemeyi altından tutan güç.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201624, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Watch others' conduct and correct your own.",
    textTr: "Başkalarının haline bak, kendi halini düzelt.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201625, author: "Japon Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "Jumping off the stage at Kiyomizu Temple.",
    textTr: "Kiyomizu Tapınağı'nın sahnesinden atlamak.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201626, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "To lose is sometimes to win.",
    textTr: "Bazen kaybetmek, kazanmaktır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201627, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "One blind man leads the crowd.",
    textTr: "Bir kör, kalabalığa yol gösterir.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201628, author: "Japon Atasözü", category: "suffering", tags: ["resilience","wisdom"],
    text: "True friends are known only in hardship.",
    textTr: "Gerçek dostlar ancak zorlukta tanınır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201629, author: "Japon Atasözü", category: "suffering", tags: ["resilience","peace"],
    text: "Where there is hardship, there is also ease.",
    textTr: "Zorluğun olduğu yerde rahatlık da vardır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201630, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The weak become the meat of the strong.",
    textTr: "Zayıf, güçlünün eti olur.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201631, author: "Japon Atasözü", category: "regret", tags: ["reckoning"],
    text: "The dead have no mouths to speak.",
    textTr: "Ölülerin konuşacak ağzı yoktur.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201632, author: "Japon Atasözü", category: "regret", tags: ["reckoning"],
    text: "A single hair separates crisis from safety.",
    textTr: "Tehlikeyle güvenlik arasında sadece tek bir kıl payı vardır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201633, author: "Japon Atasözü", category: "discipline", tags: ["discipline"],
    text: "A dragon's head, but a serpent's tail.",
    textTr: "Ejderha başı, yılan kuyruğu.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201634, author: "Japon Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "It is the ship you have already boarded.",
    textTr: "Artık bindiğin gemidir; geri dönemezsin.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201635, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Bad news travels a thousand miles.",
    textTr: "Kötü haber bin mil koşar.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201636, author: "Japon Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Even the light of Buddha depends on money.",
    textTr: "Buda'nın ışığı bile paraya bağlıdır.",
    origin: "Japonya", originEmoji: "🇯🇵", era: "ancient", packId: "asian-proverbs" },
  { id: 201637, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "If the words you send are kind, the words that return are kind.",
    textTr: "Gönderdiğin söz nazikse, sana dönen söz de nazik olur.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201638, author: "Kore Atasözü", category: "suffering", tags: ["resilience"],
    text: "The further you go, the bigger the mountain ahead.",
    textTr: "Gittikçe önündeki dağ büyür.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201639, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Watching the fire as if from across the river.",
    textTr: "Irmağın karşısından yangını seyreder gibi.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201640, author: "Kore Atasözü", category: "identity", tags: ["wisdom"],
    text: "The frog forgets the days it was a tadpole.",
    textTr: "Kurbağa, iribaş olduğu günleri unutur.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201641, author: "Kore Atasözü", category: "fire", tags: ["motivation","legacy"],
    text: "A dragon rises from a small stream.",
    textTr: "Küçük bir dereden bir ejderha çıkar.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201642, author: "Kore Atasözü", category: "discipline", tags: ["discipline"],
    text: "Trying to run before you can walk.",
    textTr: "Yürümeden önce koşmaya çalışmak.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201643, author: "Kore Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "A tower built with devotion does not crumble.",
    textTr: "Emekle örülen kule yıkılmaz.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201644, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The old official was the good official.",
    textTr: "Eski memur, iyi memurdur.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201645, author: "Kore Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Even three pecks of beads are worthless unless strung together.",
    textTr: "Üç kile boncuk bile dizilmeden hazine olmaz.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201646, author: "Kore Atasözü", category: "regret", tags: ["reckoning"],
    text: "The thief's own feet feel numb with guilt.",
    textTr: "Hırsızın kendi ayakları suçluluktan uyuşur.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201647, author: "Kore Atasözü", category: "identity", tags: ["legacy"],
    text: "A tree destined to bear fruit shows it from its first leaves.",
    textTr: "Meyve verecek ağaç, ilk yapraklarından bellidir.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201648, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Above the one who runs, there is one who flies.",
    textTr: "Koşanın üstünde uçan vardır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201649, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A single word can repay a debt of a thousand nyang.",
    textTr: "Tek bir söz, bin altınlık borcu öder.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201650, author: "Kore Atasözü", category: "identity", tags: ["discipline","wisdom"],
    text: "The cornered stone gets the chisel.",
    textTr: "Köşeli taş, kalemi yer.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201651, author: "Kore Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "The thirsty one digs the well.",
    textTr: "Susayan kişi kuyuyu kendi kazar.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201652, author: "Kore Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "Struck in the foot by the axe you trusted.",
    textTr: "Güvendiğin baltayla kendi ayağını kesersin.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201653, author: "Kore Atasözü", category: "suffering", tags: ["resilience"],
    text: "Pouring water into a jar with no bottom.",
    textTr: "Dipsiz küpe su dökmek.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201654, author: "Kore Atasözü", category: "identity", tags: ["wisdom"],
    text: "The riper the rice, the lower it bows its head.",
    textTr: "Pirinç olgunlaştıkça başını daha çok eğer.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201655, author: "Kore Atasözü", category: "resilience", tags: ["resilience"],
    text: "The ground grows firmer after the rain.",
    textTr: "Yağmurdan sonra toprak daha da sağlamlaşır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201656, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "An empty cart rattles the loudest.",
    textTr: "Boş araba en çok gıcırdar.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201657, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "With too many boatmen, the boat climbs the mountain.",
    textTr: "Dümenci çok olursa gemi dağa çıkar.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201658, author: "Kore Atasözü", category: "discipline", tags: ["discipline"],
    text: "Even a dog at the village school for three years will recite verse.",
    textTr: "Üç yıl köy okulunda kalan köpek bile şiir okur.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201659, author: "Kore Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "A habit at three lasts until eighty.",
    textTr: "Üç yaşındaki alışkanlık seksene kadar sürer.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201660, author: "Kore Atasözü", category: "regret", tags: ["reckoning"],
    text: "Mending the barn after losing the cow.",
    textTr: "İneği kaybettikten sonra ahırı onarmak.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201661, author: "Kore Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Ask the way even on a road you already know.",
    textTr: "Bildiğin yolu bile sora sora git.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201662, author: "Kore Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "No tree falls without ten strikes of the axe.",
    textTr: "On kez vurulup da devrilmeyen ağaç yoktur.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201663, author: "Kore Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "If you dig a well, dig only one.",
    textTr: "Kuyu kazacaksan, tek bir kuyu kaz.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201664, author: "Kore Atasözü", category: "regret", tags: ["reckoning"],
    text: "Enemies meet on a single-log bridge.",
    textTr: "Düşmanlar, tek kütüklü bir köprüde karşılaşır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201665, author: "Kore Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "If the upper water is clear, the lower water is clear too.",
    textTr: "Üstteki su berraksa, alttaki su da berrak olur.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201666, author: "Kore Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "Even a mouse hole will have its sunny day.",
    textTr: "Fare deliğine bile güneşin doğacağı bir gün gelir.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201667, author: "Kore Atasözü", category: "identity", tags: ["resilience"],
    text: "Even a worm will writhe if you step on it.",
    textTr: "Solucan bile üstüne basılınca kıvranır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201668, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Plant beans and beans will grow; plant red beans and red beans will grow.",
    textTr: "Fasulye ekersen fasulye, börülce ekersen börülce biter.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201669, author: "Kore Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Even if the sky falls, there is a hole to climb out of.",
    textTr: "Gök çökse bile, çıkacak bir delik vardır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201670, author: "Kore Atasözü", category: "resilience", tags: ["resilience","focus"],
    text: "Even carried off by a tiger, you survive if you keep your wits about you.",
    textTr: "Kaplan seni kapsa bile, aklını toplarsan kurtulursun.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201671, author: "Kore Atasözü", category: "suffering", tags: ["resilience","peace"],
    text: "At the end of hardship comes joy.",
    textTr: "Zorluğun sonunda mutluluk gelir.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201672, author: "Kore Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "When cornered, a way opens.",
    textTr: "Çaresiz kalınca bir yol açılır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201673, author: "Kore Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "Where there is a will, there is a road.",
    textTr: "Niyetin olduğu yerde yol da vardır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201674, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Like a blind man feeling an elephant.",
    textTr: "Kör bir adamın fili yoklaması gibi.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201675, author: "Kore Atasözü", category: "suffering", tags: ["wisdom"],
    text: "A widow's sorrow is known only by a widower.",
    textTr: "Dul bir kadının kederini, dul bir erkek bilir.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201676, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Even a sheet of paper is lighter when lifted together.",
    textTr: "Bir kağıt yaprağı bile birlikte tutulursa daha hafif olur.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201677, author: "Kore Atasözü", category: "legacy", tags: ["legacy"],
    text: "The tiger dies and leaves its hide; the person dies and leaves their name.",
    textTr: "Kaplan ölünce postunu, insan ölünce adını bırakır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201678, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "You cannot eat the rice cake drawn in a painting.",
    textTr: "Resimde çizilen pirinç kekini yiyemezsin.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201679, author: "Kore Atasözü", category: "fire", tags: ["motivation"],
    text: "It is like plucking a star from the sky.",
    textTr: "Gökten yıldız koparmak gibidir.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201680, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Spit while lying on your back, and it falls on your own face.",
    textTr: "Sırtüstü yatıp tükürürsen, tükürük kendi yüzüne düşer.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201681, author: "Kore Atasözü", category: "suffering", tags: ["resilience"],
    text: "Striking a rock with an egg.",
    textTr: "Kayaya yumurtayla vurmak.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201682, author: "Kore Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Birds hear the words spoken by day, mice hear the words spoken by night.",
    textTr: "Gündüz sözünü kuşlar, gece sözünü fareler duyar.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201683, author: "Kore Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Look at where you will lie before you stretch your legs.",
    textTr: "Bacaklarını uzatmadan önce yatacağın yere bak.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201684, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Smoke does not rise from a chimney that was never lit.",
    textTr: "Yakılmamış bacadan duman çıkmaz.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201685, author: "Kore Atasözü", category: "regret", tags: ["reckoning"],
    text: "There is no grave without an excuse.",
    textTr: "Bahanesiz mezar olmaz.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201686, author: "Kore Atasözü", category: "identity", tags: ["wisdom"],
    text: "A puppy born yesterday does not fear the tiger.",
    textTr: "Daha dün doğmuş yavru köpek kaplandan korkmaz.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201687, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Where there is no tiger, the fox plays king.",
    textTr: "Kaplanın olmadığı yerde tilki kral kesilir.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201688, author: "Kore Atasözü", category: "identity", tags: ["wisdom"],
    text: "The arm bends inward, not outward.",
    textTr: "Kol, dışa değil içe doğru kıvrılır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201689, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Cheap goods are nothing but bean-curd cakes.",
    textTr: "Ucuz olan, posadan yapılma bir pastadır.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201690, author: "Kore Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "Can a sparrow fly past the mill without stopping in?",
    textTr: "Serçe, değirmenin önünden hiç uğramadan geçer mi?",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201691, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "If the price is the same, choose the crimson skirt.",
    textTr: "Fiyat aynıysa, kırmızı eteği seç.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201692, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The rolling stone dislodges the one already set in place.",
    textTr: "Yuvarlanan taş, yerleşmiş taşı yerinden söker.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201693, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Even Mount Geumgang is best seen after a meal.",
    textTr: "Geumgang Dağı bile ancak karın doyunca güzel görünür.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201694, author: "Kore Atasözü", category: "identity", tags: ["wisdom"],
    text: "Acorns arguing over whose is tallest.",
    textTr: "Meşe palamutlarının boy ölçüşmesi.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201695, author: "Kore Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Someone else's rice cake always looks bigger.",
    textTr: "Başkasının pirinç keki her zaman daha büyük görünür.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201696, author: "Kore Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "The crying child gets the milk.",
    textTr: "Ağlayan çocuğa süt verilir.",
    origin: "Kore", originEmoji: "🇰🇷", era: "ancient", packId: "asian-proverbs" },
  { id: 201697, author: "Hint Atasözü", category: "discipline", tags: ["motivation","discipline"],
    text: "Where there is a will, there is a way.",
    textTr: "Nerede azim varsa, orada bir yol vardır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201698, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Better late than never.",
    textTr: "Geç olsun da güç olmasın.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201699, author: "Hint Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "A bad workman blames his tools.",
    textTr: "Kötü işçi, aletlerini suçlar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201700, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Whoever owns the stick, owns the buffalo.",
    textTr: "Sopa kimdeyse, manda da onundur.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201701, author: "Hint Atasözü", category: "regret", tags: ["reckoning"],
    text: "What is the use of crying when the birds have already eaten the whole field?",
    textTr: "Kuşlar tüm tarlayı yiyip bitirdikten sonra ağlamanın ne faydası var?",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201702, author: "Hint Atasözü", category: "regret", tags: ["reckoning"],
    text: "One who is burned by hot milk blows even on buttermilk.",
    textTr: "Sütle ağzı yanan, ayranı bile üfleyerek içer.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201703, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "An insider can bring down even a prosperous city.",
    textTr: "İçerideki biri, gelişmiş bir şehri bile yerle bir edebilir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201704, author: "Hint Atasözü", category: "regret", tags: ["reckoning"],
    text: "As you sow, so shall you reap.",
    textTr: "Ne ekersen onu biçersin.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201705, author: "Hint Atasözü", category: "wisdom", tags: ["peace"],
    text: "All's well that ends well.",
    textTr: "Sonu iyi biten her şey iyidir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201706, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Distant drums sound sweeter.",
    textTr: "Uzaktaki davulun sesi daha hoş gelir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201707, author: "Hint Atasözü", category: "suffering", tags: ["resilience"],
    text: "A drowning man catches at a straw.",
    textTr: "Boğulmakta olan adam, saman çöpüne bile sarılır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201708, author: "Hint Atasözü", category: "fire", tags: ["focus","discipline"],
    text: "A single blow of the blacksmith's hammer is worth a hundred of the goldsmith's.",
    textTr: "Demircinin bir vuruşu, kuyumcunun yüz vuruşuna bedeldir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201709, author: "Hint Atasözü", category: "legacy", tags: ["legacy"],
    text: "Do good and cast it into the river.",
    textTr: "İyilik yap, nehre at; karşılığını bekleme.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201710, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Ram in the mouth, a dagger in the armpit.",
    textTr: "Ağzında dua, koltuğunun altında hançer.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201711, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "All that glitters is not gold; a fine shop may serve tasteless food.",
    textTr: "Parlayan her şey altın değildir; gösterişli dükkânın yemeği tatsız olabilir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201712, author: "Hint Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Your own hand is your own god.",
    textTr: "Kendi elin, kendi Tanrın'dır; işini kendin gör.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201713, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Barking dogs do not bite.",
    textTr: "Havlayan köpek ısırmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201714, author: "Hint Atasözü", category: "fire", tags: ["wisdom"],
    text: "Truth fears no flame.",
    textTr: "Gerçek, ateşten korkmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201715, author: "Hint Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "While there is life, there is a world.",
    textTr: "Can varsa, cihan da vardır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201716, author: "Hint Atasözü", category: "regret", tags: ["reckoning"],
    text: "If you plant a thorny babul tree, how can you expect mangoes?",
    textTr: "Dikenli akasya diken, nereden mango bekleyebilir ki?",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201717, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Why does the bangle on your own hand need a mirror?",
    textTr: "Kendi elindeki bileziği görmek için aynaya ne gerek var?",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201718, author: "Hint Atasözü", category: "identity", tags: ["wisdom"],
    text: "Don't ask the caste of a saint.",
    textTr: "Bir ermişin kastını sorma; onu özüyle tanı.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201719, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The thief scolds the policeman.",
    textTr: "Hırsız, kalkıp bekçiyi azarlar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201720, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "What does a monkey know of the taste of ginger?",
    textTr: "Maymun, zencefilin tadından ne anlar?",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201721, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "It is not wise to feud with the crocodile while you live in its water.",
    textTr: "Suyunda yaşadığın timsahla husumete girmek akıllıca değildir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201722, author: "Hint Atasözü", category: "suffering", tags: ["reckoning"],
    text: "A well ahead, a ditch behind.",
    textTr: "Önünde kuyu, arkasında hendek; iki ateş arasında kalmak.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201723, author: "Hint Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A pinch of cumin in a camel's mouth.",
    textTr: "Devenin ağzına bir tutam kimyon; denizde bir damla.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201724, author: "Sanskrit Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Tasks are accomplished through effort, not through mere wishes.",
    textTr: "İşler dilekle değil, çabayla başarılır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201725, author: "Sanskrit Atasözü", category: "discipline", tags: ["discipline"],
    text: "Through exercise, one gains health, longevity, strength, and happiness.",
    textTr: "Bedeni çalıştırmakla sağlık, uzun ömür, güç ve mutluluk kazanılır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201726, author: "Sanskrit Atasözü", category: "identity", tags: ["wisdom"],
    text: "No coronation ceremony is performed for the lion in the forest.",
    textTr: "Ormanda aslana taç giydirilmez; gerçek güç onaya muhtaç değildir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201727, author: "Sanskrit Atasözü", category: "wisdom", tags: ["peace"],
    text: "All people are pleased by the gift of kind words.",
    textTr: "İnsanlar en çok tatlı sözle hoşnut olur.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201728, author: "Sanskrit Atasözü", category: "resilience", tags: ["motivation"],
    text: "Hope is a wondrous chain that binds mankind.",
    textTr: "Umut, insanı bağlayan tuhaf ve şaşırtıcı bir zincirdir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201729, author: "Sanskrit Atasözü", category: "legacy", tags: ["legacy"],
    text: "A mother is an enemy and a father a foe, if their child is left uneducated.",
    textTr: "Çocuğunu eğitmeyen anne düşman, baba ise hasımdır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201730, author: "Tamil Atasözü", category: "identity", tags: ["wisdom","discipline"],
    text: "What won't bend at five will not bend at fifty.",
    textTr: "Beş yaşında eğilmeyen, ellisinde de eğilmez.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201731, author: "Tamil Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "The harder the blow, the faster the ball flies.",
    textTr: "Vuruş ne kadar sertse, top o kadar hızlı uçar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201732, author: "Tamil Atasözü", category: "fire", tags: ["resilience","motivation"],
    text: "Fire burns as long as it flames, earth turns as long as it moves, man is human as long as he strives.",
    textTr: "Ateş yandığı sürece ateştir, toprak döndüğü sürece topraktır, insan da mücadele ettiği sürece insandır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201733, author: "Tamil Atasözü", category: "identity", tags: ["wisdom"],
    text: "The beauty of the soul is known in the face.",
    textTr: "Ruhun güzelliği yüzden anlaşılır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201734, author: "Tamil Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Don't wade in without knowing the depth.",
    textTr: "Derinliğini bilmeden suya girme.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201735, author: "Tamil Atasözü", category: "discipline", tags: ["discipline"],
    text: "Although you are throwing it into the river, measure it first.",
    textTr: "Nehre atacak olsan bile, önce ölçüp öyle at.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201736, author: "Tamil Atasözü", category: "fire", tags: ["reckoning"],
    text: "The cat that has been burned will not go near the hearth again.",
    textTr: "Bir kez ateşte yanan kedi, ocağa bir daha yaklaşmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201737, author: "Tamil Atasözü", category: "identity", tags: ["wisdom"],
    text: "Even if water turns hot, it will still quench fire.",
    textTr: "Su ısınıp kaynasa da, yine ateşi söndürür; öz doğa değişmez.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201738, author: "Tamil Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "Tie a hair and pull the mountain.",
    textTr: "Bir kıl bağla, dağı çek; küçük çaba büyük işi başarır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201739, author: "Tamil Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "If you place step upon step, even a grinding stone will move.",
    textTr: "Adım adım ilerlersen, değirmen taşı bile yerinden oynar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201740, author: "Tamil Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Even an elephant slips sometimes.",
    textTr: "Fil bile bazen ayağı kayar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201741, author: "Tamil Atasözü", category: "suffering", tags: ["peace"],
    text: "Heaven itself helps the helpless.",
    textTr: "Çaresizin yardımcısı gökyüzüdür.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201742, author: "Tamil Atasözü", category: "suffering", tags: ["peace"],
    text: "God Himself is the help of the helpless.",
    textTr: "Çaresizin yardımcısı Tanrı'nın kendisidir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201743, author: "Tamil Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Submission and humility will yield a thousand gold coins.",
    textTr: "Alçakgönüllülük bin altın kazandırır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201744, author: "Tamil Atasözü", category: "discipline", tags: ["discipline"],
    text: "First plant the banana tree, then build the road.",
    textTr: "Önce muz ağacını dik, sonra yolu yap; sırasına uy.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201745, author: "Tamil Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "Will the word 'pumpkin' make a curry?",
    textTr: "Sadece 'kabak' demekle yemek pişer mi? Söz yetmez, eylem gerekir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201746, author: "Tamil Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "It is like the wolf crying because the sheep got drenched in the rain.",
    textTr: "Koyun yağmurda ıslandı diye kurdun ağlaması gibi; sahte şefkat.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201747, author: "Tamil Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Necessity has no law.",
    textTr: "Zorunluluğun kanunu yoktur.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201748, author: "Tamil Atasözü", category: "identity", tags: ["wisdom"],
    text: "All saint without, all devil within.",
    textTr: "Dışı ermiş, içi şeytan.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201749, author: "Tamil Atasözü", category: "discipline", tags: ["discipline"],
    text: "A bamboo stick is king to an unruly snake.",
    textTr: "Azgın yılana bambu sopası kral kesilir; her derde bir çare bulunur.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201750, author: "Tamil Atasözü", category: "discipline", tags: ["focus"],
    text: "Should one make great efforts over a trifle?",
    textTr: "Önemsiz bir şey için bu kadar büyük çaba harcanır mı?",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201751, author: "Tamil Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "It is like making a worthless gift of a thousand acres of sandy riverbank.",
    textTr: "Kumluk nehir kıyısından bin dönüm bağışlamak gibi; boş cömertlik.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201752, author: "Tamil Atasözü", category: "resilience", tags: ["resilience"],
    text: "One cannot walk while weeping.",
    textTr: "Ağlayarak yürünmez; yola devam etmek gerekir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201753, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Barking dogs seldom bite.",
    textTr: "Havlayan köpek nadiren ısırır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201754, author: "Bengal Atasözü", category: "regret", tags: ["reckoning"],
    text: "Grasp all, lose all.",
    textTr: "Her şeyi kapmaya çalışan, her şeyi kaybeder.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201755, author: "Bengal Atasözü", category: "regret", tags: ["reckoning"],
    text: "As you sow, so you reap.",
    textTr: "Nasıl ekersen öyle biçersin.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201756, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "One hand alone cannot clap.",
    textTr: "Tek el alkışlamaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201757, author: "Bengal Atasözü", category: "fire", tags: ["reckoning"],
    text: "The burnt-house cow fears even a red monsoon cloud.",
    textTr: "Evi yanan inek, kızıl bir bulut görünce bile korkar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201758, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Might is right.",
    textTr: "Kimin sopası varsa, toprak da onundur.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201759, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A little learning is a dangerous thing.",
    textTr: "Az bilgi tehlikelidir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201760, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Birds of a feather flock together.",
    textTr: "Aynı tüyden kuşlar bir araya gelir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201761, author: "Bengal Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Hard work is the mother of good fortune.",
    textTr: "Çalışkanlık, talihin anasıdır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201762, author: "Bengal Atasözü", category: "discipline", tags: ["focus"],
    text: "Time and tide wait for no one.",
    textTr: "Zaman ve akıntı kimseyi beklemez.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201763, author: "Bengal Atasözü", category: "legacy", tags: ["legacy"],
    text: "Knowledge is a person's true wealth.",
    textTr: "Bilgi, insanın gerçek servetidir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201764, author: "Bengal Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Constant rubbing wears away even a stone.",
    textTr: "Sürekli sürtünme taşı bile aşındırır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201765, author: "Bengal Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "If at first you don't succeed, try a hundred times.",
    textTr: "Bir seferde başaramazsan, yüz kez dene.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201766, author: "Bengal Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "No pain, no gain.",
    textTr: "Acı çekmeden kazanç olmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201767, author: "Bengal Atasözü", category: "resilience", tags: ["peace","resilience"],
    text: "While there is breath, there is hope.",
    textTr: "Nefes olduğu sürece umut da vardır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201768, author: "Bengal Atasözü", category: "identity", tags: ["legacy"],
    text: "Death is preferable to bondage.",
    textTr: "Esaret altında yaşamaktansa ölüm yeğdir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201769, author: "Bengal Atasözü", category: "resilience", tags: ["resilience"],
    text: "If you save yourself, your father's name lives on.",
    textTr: "Kendini kurtarırsan babanın adı da yaşar; önce kendini koru.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201770, author: "Bengal Atasözü", category: "wisdom", tags: ["peace"],
    text: "Non-violence is the highest virtue.",
    textTr: "Şiddetsizlik en yüce erdemdir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201771, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Honesty is the best policy.",
    textTr: "Dürüstlük en iyi politikadır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201772, author: "Bengal Atasözü", category: "regret", tags: ["reckoning"],
    text: "To err is human.",
    textTr: "Hata yapmak insana özgüdür.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201773, author: "Bengal Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "A stitch in time saves nine.",
    textTr: "Zamanında atılan bir dikiş, dokuz dikişi önler.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201774, author: "Bengal Atasözü", category: "identity", tags: ["wisdom"],
    text: "A tree is known by its fruit.",
    textTr: "Ağaç, meyvesiyle bilinir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201775, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Knowledge is power.",
    textTr: "Bilgi güçtür.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201776, author: "Bengal Atasözü", category: "legacy", tags: ["legacy"],
    text: "United we stand, divided we fall.",
    textTr: "Birlikte ayakta kalırız, ayrılırsak düşeriz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201777, author: "Bengal Atasözü", category: "discipline", tags: ["focus"],
    text: "Oil your own spinning wheel first.",
    textTr: "Önce kendi çıkrığını yağla; kendi işine bak.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201778, author: "Bengal Atasözü", category: "identity", tags: ["wisdom"],
    text: "Washing coal will not remove its blackness.",
    textTr: "Kömürü yıkamak karasını gidermez; öz değişmez.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201779, author: "Bengal Atasözü", category: "discipline", tags: ["discipline"],
    text: "Example is better than precept.",
    textTr: "Örnek olmak, öğüt vermekten iyidir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201780, author: "Bengal Atasözü", category: "identity", tags: ["wisdom"],
    text: "Every dog is a lion on his own turf.",
    textTr: "Her köpek kendi mahallesinde aslan kesilir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201781, author: "Bengal Atasözü", category: "regret", tags: ["reckoning"],
    text: "To strike an axe upon one's own foot.",
    textTr: "Kendi ayağına balta vurmak.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201782, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Out of sight, out of mind.",
    textTr: "Gözden ırak olan, gönülden de ırak olur.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201783, author: "Bengal Atasözü", category: "legacy", tags: ["legacy"],
    text: "Even a dead elephant is worth a hundred thousand rupees.",
    textTr: "Ölü fil bile yüz bin rupi değerindedir; büyüklük harabesinde bile büyüktür.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201784, author: "Bengal Atasözü", category: "legacy", tags: ["legacy"],
    text: "Many hands make light work, like a bundle of sticks.",
    textTr: "Bir demet çubuk gibi, birçok el işi hafifletir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201785, author: "Bengal Atasözü", category: "suffering", tags: ["reckoning"],
    text: "A bolt from the blue.",
    textTr: "Bulutsuz gökten düşen yıldırım; hiç beklenmedik bir felaket.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201786, author: "Bengal Atasözü", category: "discipline", tags: ["discipline"],
    text: "Do not spend beyond your income.",
    textTr: "Gelirinin ötesinde harcama yapma.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201787, author: "Bengal Atasözü", category: "regret", tags: ["reckoning"],
    text: "Excess pride brought down Lanka.",
    textTr: "Aşırı gurur, Lanka'nın bile yıkılmasına yol açtı.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201788, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A one-eyed uncle is better than no uncle at all.",
    textTr: "Tek gözlü dayı, dayısız olmaktan iyidir; azıcık aşım kaygısız başım.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201789, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Beggars must not be choosers.",
    textTr: "Dilenciler seçici olamaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201790, author: "Bengal Atasözü", category: "legacy", tags: ["legacy"],
    text: "Like father, like son.",
    textTr: "Baba nasılsa oğul da öyledir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201791, author: "Bengal Atasözü", category: "discipline", tags: ["discipline"],
    text: "Waste not, want not.",
    textTr: "İsraf etme ki, muhtaç olmayasın.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201792, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A friend in need is a friend indeed.",
    textTr: "Gerçek dost, ihtiyaç anında belli olur.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201793, author: "Bengal Atasözü", category: "discipline", tags: ["focus"],
    text: "Too many cooks spoil the broth.",
    textTr: "Çok aşçı çorbayı bozar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201794, author: "Bengal Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Too much courtesy, too much craft.",
    textTr: "Fazla nezaket, fazla hesaptır; aşırı kibarlık şüphe uyandırır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201795, author: "Pencap Atasözü", category: "identity", tags: ["wisdom"],
    text: "Not every Sufi is a true one.",
    textTr: "Her Sufi, hakiki bir Sufi değildir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201796, author: "Pencap Atasözü", category: "wisdom", tags: ["peace"],
    text: "The rich weep in their mansions; the poor sleep peacefully in their huts.",
    textTr: "Zengin, konağında huzursuzca ağlar; yoksul, kulübesinde huzurla uyur.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201797, author: "Pencap Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Dogs keep barking, and elephants keep passing by.",
    textTr: "Köpekler havlamaya devam eder, fil ise yoluna devam eder.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201798, author: "Pencap Atasözü", category: "identity", tags: ["wisdom"],
    text: "One who has not seen Lahore has not truly lived.",
    textTr: "Lahor'u görmeyen, gerçekten yaşamış sayılmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201799, author: "Pencap Atasözü", category: "wisdom", tags: ["peace"],
    text: "Cherish love, or it turns foul.",
    textTr: "Sevgiyi koru, yoksa çürür.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201800, author: "Pencap Atasözü", category: "identity", tags: ["wisdom","legacy"],
    text: "Preserve the honor of your turban.",
    textTr: "Sarığının onurunu koru; haysiyetini kaybetme.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201801, author: "Pencap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "If you are good, the world seems good to you; if you are bad, the world seems bad.",
    textTr: "Sen iyiysen dünya sana iyi, kötüysen dünya sana kötü görünür.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201802, author: "Pencap Atasözü", category: "identity", tags: ["wisdom"],
    text: "Without a moustache, a man is nothing.",
    textTr: "Bıyığı olmayan adamın hiçbir kıymeti yoktur; onuru olmayanın değeri de olmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201803, author: "Pencap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Wealth without use is no wealth at all.",
    textTr: "Kullanılmayan servet, servet sayılmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201804, author: "Pencap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A hundred wise men share one counsel, but every fool has his own.",
    textTr: "Yüz akıllı tek bir öğütte birleşir, her aptalın öğüdüyse kendine göredir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201805, author: "Pencap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "One who cannot manage himself gives advice to others.",
    textTr: "Kendi işini beceremeyen, başkasına akıl öğretir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201806, author: "Pencap Atasözü", category: "regret", tags: ["reckoning"],
    text: "Do a good deed, get a punch in return.",
    textTr: "İyilik yap, karşılığında yumruk ye.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201807, author: "Pencap Atasözü", category: "discipline", tags: ["discipline"],
    text: "Extraordinary care is needed to keep a precious thing.",
    textTr: "Değerli bir şeyi korumak için olağanüstü bir özen gerekir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201808, author: "Peştun Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The empty vessel makes the most noise.",
    textTr: "Boş kap en çok ses çıkarır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201809, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "Wherever the donkey goes, it remains a donkey.",
    textTr: "Eşek nereye giderse gitsin, yine eşektir; doğa değişmez.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201810, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "The snake's offspring is also a snake.",
    textTr: "Yılanın yavrusu da yılandır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201811, author: "Peştun Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A crooked load will never reach its destination.",
    textTr: "Eğri yüklenen yük, hedefine asla ulaşmaz; dürüstlük şarttır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201812, author: "Peştun Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A wise enemy is better than a foolish friend.",
    textTr: "Akıllı bir düşman, aptal bir dosttan iyidir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201813, author: "Peştun Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Even on a mountain, there is still a road.",
    textTr: "Dağın üzerinde bile bir yol vardır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201814, author: "Peştun Atasözü", category: "suffering", tags: ["reckoning"],
    text: "The wound of the sword will heal, but not that of the tongue.",
    textTr: "Kılıcın yarası iyileşir, ama dilin yarası iyileşmez.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201815, author: "Peştun Atasözü", category: "discipline", tags: ["focus"],
    text: "With too many butchers, the cow dies without being properly slaughtered.",
    textTr: "Çok kasap olunca, inek düzgün kesilmeden ölür.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201816, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "A bird only flies as high as his wings take him.",
    textTr: "Kuş, ancak kanatlarının taşıyabildiği kadar yükseğe uçar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201817, author: "Peştun Atasözü", category: "suffering", tags: ["peace"],
    text: "A broken hand can work, but a broken heart cannot.",
    textTr: "Kırık bir el çalışabilir, ama kırık bir kalp çalışamaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201818, author: "Peştun Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A cheap thing does not lack defect, nor an expensive thing quality.",
    textTr: "Ucuz şeyin kusuru, pahalı şeyin de kalitesi eksik olmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201819, author: "Peştun Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Without investigating the water, don't take off your shoes.",
    textTr: "Suyu araştırmadan ayakkabılarını çıkarma.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201820, author: "Peştun Atasözü", category: "regret", tags: ["reckoning"],
    text: "Don't dig a well for others, or you will fall into it yourself.",
    textTr: "Başkasına kuyu kazma, yoksa kendin düşersin.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201821, author: "Peştun Atasözü", category: "resilience", tags: ["resilience"],
    text: "He who is cornered will fight.",
    textTr: "Köşeye sıkışan, savaşır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201822, author: "Peştun Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Little talk, more action.",
    textTr: "Az konuş, çok iş yap.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201823, author: "Peştun Atasözü", category: "discipline", tags: ["discipline"],
    text: "Hasty work does not succeed.",
    textTr: "Aceleyle yapılan iş başarılı olmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201824, author: "Peştun Atasözü", category: "fire", tags: ["discipline"],
    text: "Poor iron will not make a sharp sword.",
    textTr: "Kötü demirden keskin kılıç çıkmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201825, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "Even the five fingers of the hand are not alike.",
    textTr: "Elin beş parmağı bile birbirinin aynı değildir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201826, author: "Peştun Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "No one says his own buttermilk is sour.",
    textTr: "Hiç kimse kendi ayranının ekşi olduğunu söylemez.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201827, author: "Peştun Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Free vinegar is sweeter than honey.",
    textTr: "Bedava sirke, baldan tatlıdır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201828, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "Where your heart goes, there your feet will go.",
    textTr: "Kalbinin gittiği yere, ayakların da gider.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201829, author: "Peştun Atasözü", category: "suffering", tags: ["peace"],
    text: "Time softens all griefs.",
    textTr: "Zaman, her acıyı hafifletir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201830, author: "Peştun Atasözü", category: "discipline", tags: ["discipline"],
    text: "Skill is stronger than strength.",
    textTr: "Hüner, güçten daha kuvvetlidir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201831, author: "Peştun Atasözü", category: "legacy", tags: ["legacy"],
    text: "Charity begins at home.",
    textTr: "Hayırseverlik evden başlar.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201832, author: "Peştun Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "You cannot accomplish anything by doing nothing.",
    textTr: "Hiçbir şey yapmadan hiçbir şey başaramazsın.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201833, author: "Peştun Atasözü", category: "regret", tags: ["reckoning"],
    text: "A bad beginning makes a bad ending.",
    textTr: "Kötü başlangıç, kötü sonla biter.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201834, author: "Peştun Atasözü", category: "regret", tags: ["reckoning"],
    text: "He ran out from under a leaking roof and sat down in the rain.",
    textTr: "Damlayan çatının altından kaçtı, gidip yağmurun altına oturdu.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201835, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "What you see in yourself is what you see in the world.",
    textTr: "Kendinde ne görüyorsan, dünyada da onu görürsün.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201836, author: "Peştun Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A liar is forgetful.",
    textTr: "Yalancının hafızası zayıftır.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201837, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "One who calls himself a Khan is not a Khan.",
    textTr: "Kendine han diyen, han değildir.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201838, author: "Peştun Atasözü", category: "wisdom", tags: ["peace"],
    text: "Blood cannot be washed out with blood.",
    textTr: "Kan, kanla temizlenmez.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201839, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "A donkey has two friends: his own two hind legs.",
    textTr: "Eşeğin iki dostu vardır: kendi arka bacakları.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201840, author: "Peştun Atasözü", category: "identity", tags: ["wisdom"],
    text: "If a donkey goes to Mecca, that does not make him a pilgrim.",
    textTr: "Eşek Mekke'ye gitse de hacı olmaz.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
  { id: 201841, author: "Peştun Atasözü", category: "regret", tags: ["reckoning"],
    text: "A frog climbed onto a stone and cried, 'I saw Kashmir!'",
    textTr: "Kurbağa bir taşa tırmandı ve 'Keşmir'i gördüm!' diye bağırdı.",
    origin: "Hindistan", originEmoji: "🇮🇳", era: "ancient", packId: "asian-proverbs" },
];

