const MIDDLE_EASTERN_PROVERBS_QUOTES = [
  { id: 201901, author: "Arap Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Unity is power.",
    textTr: "Birlik kuvvettir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201902, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Actions speak louder than words.",
    textTr: "Eylemler sözlerden daha yüksek sesle konuşur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201903, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "The smarter you are, the less you speak.",
    textTr: "Ne kadar akıllıysan, o kadar az konuşursun.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201904, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Silence is the sign of approval.",
    textTr: "Sükût, onay işaretidir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201905, author: "Arap Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "If speech is silver, then silence is gold.",
    textTr: "Söz gümüşse, sükût altındır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201906, author: "Arap Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Keeping a secret is a commitment.",
    textTr: "Bir sırrı saklamak, bir sorumluluktur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201907, author: "Arap Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "A secret is like a dove: when it leaves my hand, it takes wing.",
    textTr: "Sır, bir güvercin gibidir: elimden çıktığı an uçup gider.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201908, author: "Arap Atasözü", category: "discipline", tags: ["discipline"],
    text: "Your chest is the best place for your secrets.",
    textTr: "Sırların için en güvenli yer kendi göğsündür.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201909, author: "Arap Atasözü", category: "resilience", tags: ["resilience","focus"],
    text: "Be patient and you will get what you want.",
    textTr: "Sabret, istediğine kavuşursun.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201910, author: "Arap Atasözü", category: "resilience", tags: ["resilience"],
    text: "No crowd ever waited at the gates of patience.",
    textTr: "Sabrın kapısında hiçbir zaman kalabalık oluşmamıştır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201911, author: "Arap Atasözü", category: "regret", tags: ["resilience","reckoning"],
    text: "In haste there is regret, but in patience there is peace and safety.",
    textTr: "Acelede pişmanlık vardır, sabırda ise huzur ve güven.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201912, author: "Arap Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Tomorrow is close if you have patience.",
    textTr: "Sabrın varsa, yarın çok yakındır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201913, author: "Arap Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Determination is the key to everything.",
    textTr: "Kararlılık, her şeyin anahtarıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201914, author: "Arap Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "He who desires the top must stay up many nights.",
    textTr: "Zirveyi arzulayan, geceler boyu uyanık kalmalıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201915, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "He who demands it all loses it all.",
    textTr: "Her şeyi isteyen, her şeyi kaybeder.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201916, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Necessity is the mother of invention.",
    textTr: "İhtiyaç, icadın anasıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201917, author: "Arap Atasözü", category: "fire", tags: ["focus","motivation"],
    text: "Strike the iron while it is hot.",
    textTr: "Demiri tavında döv.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201918, author: "Arap Atasözü", category: "wisdom", tags: ["motivation","focus"],
    text: "If the wind blows, ride it.",
    textTr: "Rüzgâr eserse, ona binip git.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201919, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The winds do not blow as the ships wish.",
    textTr: "Rüzgârlar, gemilerin istediği yönde esmez.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201920, author: "Arap Atasözü", category: "resilience", tags: ["resilience","focus"],
    text: "A pebble can support a barrel.",
    textTr: "Küçük bir çakıl taşı, koca bir fıçıyı bile tutabilir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201921, author: "Arap Atasözü", category: "wisdom", tags: ["motivation","focus"],
    text: "Movement is a blessing.",
    textTr: "Hareket bereket getirir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201922, author: "Arap Atasözü", category: "legacy", tags: ["motivation","legacy"],
    text: "A tree begins with a seed.",
    textTr: "Her ağaç bir tohumla başlar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201923, author: "Arap Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Time is made of gold.",
    textTr: "Zaman altından yapılmıştır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201924, author: "Arap Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "There is always tomorrow.",
    textTr: "Her zaman bir yarın vardır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201925, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Every sun has to set.",
    textTr: "Her güneş, bir gün batmak zorundadır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201926, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Days are like countries, always changing.",
    textTr: "Günler de ülkeler gibidir, durmadan değişir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201927, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The world is like a belly-dancer: it dances a little while for everyone.",
    textTr: "Dünya bir rakkase gibidir; herkes için bir süre oynar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201928, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","wisdom"],
    text: "Wealth comes like a turtle, and runs away like a gazelle.",
    textTr: "Zenginlik kaplumbağa gibi gelir, ceylan gibi kaçar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201929, author: "Arap Atasözü", category: "suffering", tags: ["wisdom","reckoning"],
    text: "Wishing does not make a poor man rich.",
    textTr: "Dilemek, yoksulu zengin etmez.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201930, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "When brains were given out, everyone was pleased with their share; but when fortunes were given out, no one was satisfied.",
    textTr: "Akıllar dağıtılırken herkes kendi payından memnundu; ama kısmetler dağıtılırken kimse payına razı olmadı.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201931, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Ignorance is the most terrible acquaintance.",
    textTr: "Cehalet, en kötü arkadaştır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201932, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Lack of intelligence is the greatest poverty.",
    textTr: "Akıl yoksunluğu, yoksulluğun en büyüğüdür.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201933, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Arrogance diminishes wisdom.",
    textTr: "Kibir, hikmeti azaltır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201934, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Arrogance is a weed that grows mostly on a dunghill.",
    textTr: "Kibir, çoğunlukla gübre yığınında yeşeren bir yabani ottur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201935, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Everyone is critical of the flaws of others but blind to their own.",
    textTr: "Herkes başkasının kusurunu eleştirir, kendi kusuruna kördür.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201936, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "He whose house is made of glass should not throw stones at people.",
    textTr: "Evi camdan olan, insanlara taş atmamalıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201937, author: "Arap Atasözü", category: "fire", tags: ["wisdom","resilience"],
    text: "The one whose hand is in fire is not like the one whose hand is in water.",
    textTr: "Eli ateşte olan ile eli suda olan bir değildir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201938, author: "Arap Atasözü", category: "fire", tags: ["discipline","reckoning"],
    text: "Whoever plays with a cat will find its claws.",
    textTr: "Kediyle oynayan, pençesini de bulur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201939, author: "Arap Atasözü", category: "fire", tags: ["resilience","reckoning"],
    text: "Whoever gets burned by soup blows on yogurt.",
    textTr: "Çorbada ağzı yanan, yoğurdu bile üfleyerek yer.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201940, author: "Arap Atasözü", category: "identity", tags: ["wisdom","reckoning"],
    text: "A dog's tail will never straighten.",
    textTr: "Köpeğin kuyruğu asla doğrulmaz.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201941, author: "Arap Atasözü", category: "identity", tags: ["wisdom","reckoning"],
    text: "The rooster dies with its eye still on the dunghill.",
    textTr: "Horoz, gözü gübre yığınında olduğu hâlde ölür.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201942, author: "Arap Atasözü", category: "identity", tags: ["focus","wisdom"],
    text: "Every rooster crows on its own dunghill.",
    textTr: "Her horoz kendi gübreliğinde öter.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201943, author: "Arap Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "The monkey is a gazelle in the eyes of its mother.",
    textTr: "Maymun, annesinin gözünde bir ceylandır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201944, author: "Arap Atasözü", category: "identity", tags: ["legacy","wisdom"],
    text: "Flip the jar on its mouth, and the daughter comes out like her mother.",
    textTr: "Testiyi ters çevir, kız yine annesine benzer çıkar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201945, author: "Arap Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "This cub is from that lion.",
    textTr: "Bu yavru, o aslandandır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201946, author: "Arap Atasözü", category: "legacy", tags: ["legacy"],
    text: "A goose's baby is a swimmer.",
    textTr: "Kazın yavrusu da yüzücü çıkar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201947, author: "Arap Atasözü", category: "discipline", tags: ["discipline","legacy"],
    text: "Discipline your son when he is young, and be his friend when he grows up.",
    textTr: "Oğlunu küçükken terbiye et, büyüyünce ona arkadaş ol.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201948, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","resilience"],
    text: "A house divided cannot stand.",
    textTr: "Bölünmüş bir ev ayakta kalamaz.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201949, author: "Arap Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who digs a pit for his brother falls into it himself.",
    textTr: "Kardeşine çukur kazan, kendisi düşer içine.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201950, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The rope of lies is short.",
    textTr: "Yalanın ipi kısadır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201951, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","legacy"],
    text: "Falseness lasts an hour, the truth lasts until the end of time.",
    textTr: "Yalan bir saat sürer, doğru ise zamanın sonuna dek kalır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201952, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Lying is a disease, and truth is a cure.",
    textTr: "Yalan bir hastalıktır, doğru ise onun devasıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201953, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A known mistake is better than an unknown truth.",
    textTr: "Bilinen bir hata, bilinmeyen bir doğrudan iyidir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201954, author: "Arap Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "Anger begins with madness, but ends in regret.",
    textTr: "Öfke delilikle başlar, pişmanlıkla biter.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201955, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Beware the levelheaded person if they become angry.",
    textTr: "Sakin insanın öfkesinden sakın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201956, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "The best answer will come from the person who is not angry.",
    textTr: "En iyi cevap, öfkelenmeyen kişiden gelir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201957, author: "Arap Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "Avoid that which requires an apology.",
    textTr: "Özür gerektirecek şeyden sakın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201958, author: "Arap Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "It is better to avoid mistakes altogether than to apologize afterward.",
    textTr: "Hatadan tamamen kaçınmak, sonradan özür dilemekten iyidir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201959, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Ask the experienced rather than the learned.",
    textTr: "Bilgiliye değil, tecrübeliye danış.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201960, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Ask someone experienced; do not ask a doctor.",
    textTr: "Tecrübeliye sor, doktora sorma.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201961, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Send a wise man; do not advise him.",
    textTr: "Akıllı adamı gönder, ona öğüt verme.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201962, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "A hint is enough for a wise man.",
    textTr: "Akıllıya bir işaret yeter.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201963, author: "Arap Atasözü", category: "identity", tags: ["wisdom","reckoning"],
    text: "Real character defeats pretension.",
    textTr: "Gerçek karakter, sahtekârlığı yener.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201964, author: "Arap Atasözü", category: "identity", tags: ["wisdom"],
    text: "Birds only meet birds alike.",
    textTr: "Kuşlar, ancak kendi cinsiyle bir araya gelir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201965, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Be wary of your enemy once, and your friend a thousand times.",
    textTr: "Düşmanından bir kez, dostundan bin kez sakın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201966, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Give your friends your money and your blood, but never justify yourself.",
    textTr: "Dostuna paranı ve kanını ver, ama asla kendini savunma.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201967, author: "Arap Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Avoid the company of liars, but if you cannot, do not believe them.",
    textTr: "Yalancıların arkadaşlığından kaçın; kaçamıyorsan da onlara inanma.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201968, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "A true friend is one who shows up in times of need.",
    textTr: "Gerçek dost, ihtiyaç anında yanında olandır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201969, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Choose your neighbor before you choose your home.",
    textTr: "Evi seçmeden önce komşunu seç.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201970, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The neighbor comes before the house.",
    textTr: "Komşu, evden önce gelir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201971, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Extreme humbleness results in humiliation.",
    textTr: "Aşırı alçakgönüllülük, küçümsenmeyle sonuçlanır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201972, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A servant who has two masters lies to one of them.",
    textTr: "İki efendiye hizmet eden, birine yalan söyler.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201973, author: "Arap Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "He who laughs last, laughs the most.",
    textTr: "Son gülen, en iyi güler.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201974, author: "Arap Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "Laugh and the world laughs with you; weep, and you weep alone.",
    textTr: "Gül, dünya seninle güler; ağla, tek başına ağlarsın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201975, author: "Arap Atasözü", category: "discipline", tags: ["discipline"],
    text: "Laughing without a reason is rude.",
    textTr: "Sebepsiz gülmek, kabalıktır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201976, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "What comes quickly goes quickly.",
    textTr: "Çabuk gelen, çabuk gider.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201977, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "I hear noise but see no grinding.",
    textTr: "Gürültü duyuyorum ama öğütülen bir şey görmüyorum.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201978, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "He who does not know the falcon would grill it.",
    textTr: "Doğanı tanımayan, onu kebap yapar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201979, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "His height is that of a palm tree, but his mind is that of a sheep.",
    textTr: "Boyu hurma ağacı kadar, aklı ise koyun kadar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201980, author: "Arap Atasözü", category: "discipline", tags: ["discipline","legacy"],
    text: "Whoever guides someone to virtue will be rewarded for it.",
    textTr: "Birini iyiliğe yönlendiren, bunun karşılığını görür.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201981, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Think it through, then place your trust in God.",
    textTr: "İyice düşün, sonra Allah'a güven.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201982, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A person of two minds is a liar, and a person of three minds is a hypocrite.",
    textTr: "İki fikirli kişi yalancıdır, üç fikirli kişi ise ikiyüzlüdür.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201983, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "If you read a book's title, you know what it is about.",
    textTr: "Bir kitabın adını okursan, ne hakkında olduğunu anlarsın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201984, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Be generous to a generous person and you will win him over.",
    textTr: "Cömerde cömert davran, onu kendine kazanırsın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201985, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "The best speech is the one that is precise and concise.",
    textTr: "En iyi söz, kısa ve öz olandır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201986, author: "Arap Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "A paradise without people is not worth stepping foot in.",
    textTr: "İnsansız bir cennete ayak basmaya değmez.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201987, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Speaking is not like seeing.",
    textTr: "Anlatmak, görmek gibi değildir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201988, author: "Arap Atasözü", category: "identity", tags: ["wisdom","reckoning"],
    text: "The shoemaker is barefoot and the weaver is naked.",
    textTr: "Ayakkabıcı yalınayak, dokumacı çıplak gezer.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201989, author: "Arap Atasözü", category: "wisdom", tags: ["reckoning","wisdom"],
    text: "The crooked furrow is caused by the big bull.",
    textTr: "Eğri sabanın suçu, büyük öküzdedir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201990, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","resilience"],
    text: "Receiving the stick is not the same as counting the blows.",
    textTr: "Değneği yemekle, darbeleri saymak bir değildir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201991, author: "Arap Atasözü", category: "resilience", tags: ["resilience","focus"],
    text: "Do not say beans until they are on the measuring scale.",
    textTr: "Terazide tartılmadan, fasulyeye güvenme.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201992, author: "Arap Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Even if your friend is honey, do not lick him all up.",
    textTr: "Dostun bal olsa bile, onu sonuna kadar yalama.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201993, author: "Arap Atasözü", category: "identity", tags: ["legacy","peace"],
    text: "Blood does not become water.",
    textTr: "Kan, su olmaz.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201994, author: "Arap Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "He who eats alone chokes on his food.",
    textTr: "Tek başına yiyen, lokmasında boğulur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201995, author: "Arap Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "We have eaten bread and salt together.",
    textTr: "Birlikte ekmek ve tuz yedik.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201996, author: "Arap Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Stretch your legs only as far as your quilt extends.",
    textTr: "Ayağını yorganına göre uzat.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201997, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A lie has no legs.",
    textTr: "Yalanın ayağı yoktur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201998, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "When the sad girl finally decided to be happy, she could not find a place to be.",
    textTr: "Üzgün kız mutlu olmaya karar verdiğinde, kendine yer bulamadı.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 201999, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "He fasted for so long, only to break his fast with an onion.",
    textTr: "O kadar uzun oruç tuttu ki, orucunu bir soğanla açtı.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202000, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "News that is worth money today will be free tomorrow.",
    textTr: "Bugün parayla değer bulan haber, yarın bedavaya döner.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202001, author: "Arap Atasözü", category: "suffering", tags: ["resilience","reckoning"],
    text: "He who has been bitten by a snake gets scared of the rope.",
    textTr: "Yılan sokan, ipten bile korkar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202002, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Remember your lover and adore them; remember their mistakes and leave them.",
    textTr: "Sevgilini hatırla ve sev onu; hatalarını hatırla ve ayrıl ondan.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202003, author: "Arap Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "May God bless the visitor who does not stay too long.",
    textTr: "Allah, fazla kalmayan misafiri bereketlendirsin.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202004, author: "Arap Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "He came to help dig his father's grave, and ran off with the spade.",
    textTr: "Babasının mezarını kazmaya yardıma geldi, küreği alıp kaçtı.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202005, author: "Arap Atasözü", category: "legacy", tags: ["legacy","reckoning"],
    text: "You can build all the houses you want; eventually you will leave them all and go to the grave alone.",
    textTr: "İstediğin kadar ev yap; sonunda hepsini bırakıp mezara tek başına gidersin.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202006, author: "Arap Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "He tried to apply kohl to her eyes but ended up blinding her.",
    textTr: "Gözüne sürme çekmeye çalışırken onu kör etti.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202007, author: "Arap Atasözü", category: "legacy", tags: ["legacy","reckoning"],
    text: "A bad reputation persists even after the person's death.",
    textTr: "Kötü şöhret, insanın ölümünden sonra bile sürer.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202008, author: "Arap Atasözü", category: "identity", tags: ["wisdom","reckoning"],
    text: "Sleep with the frogs, and by morning you will be croaking like them.",
    textTr: "Kurbağalarla yat, sabah kalktığında onlar gibi vraklarsın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202009, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "He fled a drop of rain and found himself under the gutter.",
    textTr: "Bir damladan kaçtı, kendini oluğun altında buldu.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202010, author: "Arap Atasözü", category: "resilience", tags: ["resilience","reckoning"],
    text: "The old woman is swept along by the river, yet she calls it a fruitful year.",
    textTr: "Yaşlı kadın nehir tarafından sürüklenir de yine de 'bereketli yıl' der.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202011, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The camel does not see its own hump.",
    textTr: "Deve, kendi hörgücünü göremez.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202012, author: "Arap Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Her arm failed her, so she said she was bewitched.",
    textTr: "Kolu tutmadı, bunu büyüye yordu.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202013, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "When the cow falls, the knives appear around it.",
    textTr: "İnek düşünce, çevresinde bıçaklar belirir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202014, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Pretend to be a fool, and you will live.",
    textTr: "Kendini deli göster ki yaşayasın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202015, author: "Arap Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "The mute man's oath is kept in his own chest.",
    textTr: "Dilsizin yemini, kendi göğsündedir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202016, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Listen to the words that make you cry, and do not listen to those that make you laugh.",
    textTr: "Seni ağlatan sözü dinle, güldüren sözü dinleme.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202017, author: "Arap Atasözü", category: "resilience", tags: ["resilience","reckoning"],
    text: "Entering the hammam is not like leaving it.",
    textTr: "Hamama girmek, çıkmak gibi değildir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202018, author: "Arap Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "The one who created you will not let you get lost.",
    textTr: "Seni yaratan, kaybolmana izin vermez.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202019, author: "Arap Atasözü", category: "discipline", tags: ["discipline","legacy"],
    text: "He who gave his word gave his neck.",
    textTr: "Sözünü veren, boynunu da vermiştir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202020, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "When a trader gives you advice, half of that advice is for himself.",
    textTr: "Tüccar sana öğüt verdiğinde, öğüdün yarısı kendi çıkarınadır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202021, author: "Arap Atasözü", category: "legacy", tags: ["legacy","reckoning"],
    text: "When respect falls down, life itself has ended.",
    textTr: "Saygı düşünce, yaşam da biter.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202022, author: "Arap Atasözü", category: "fire", tags: ["resilience","wisdom"],
    text: "Only he who walks on burning embers can truly feel them.",
    textTr: "Korun üzerinde yürüyen, onu gerçekten hisseder.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202023, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","wisdom"],
    text: "Put money on a dead man's mouth, and he will start laughing.",
    textTr: "Ölünün ağzına para koy, gülmeye başlar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202024, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Beware of the one to whom you have been charitable.",
    textTr: "İyilik ettiğin kişiden sakın.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202025, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Far from sight, far from the heart.",
    textTr: "Gözden ırak olan, gönülden de ırak olur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202026, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Good health is a crown worn by the healthy that only the sick can see.",
    textTr: "Sağlık, sağlıklının başındaki bir taçtır; onu ancak hasta olan görebilir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202027, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","wisdom"],
    text: "An envious person is the unhappiest of all.",
    textTr: "Kıskanç insan, en mutsuz insandır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202028, author: "Arap Atasözü", category: "suffering", tags: ["reckoning"],
    text: "The envious were created only to be infuriated.",
    textTr: "Kıskançlar, sadece öfkelenmek için yaratılmıştır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202029, author: "Arap Atasözü", category: "suffering", tags: ["resilience","peace"],
    text: "He who sees the calamity of other people finds his own calamity light.",
    textTr: "Başkalarının felaketini gören, kendi felaketini hafif bulur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202030, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The stingy man has a large porch and little morality.",
    textTr: "Cimrinin evi geniş, ahlakı dardır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202031, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "If you are charitable, you are rich.",
    textTr: "Cömertsen, zaten zenginsindir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202032, author: "Arap Atasözü", category: "wisdom", tags: ["peace","discipline"],
    text: "The fruit of silence is tranquility.",
    textTr: "Sükûtun meyvesi, huzurdur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202033, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The fruit of timidity is neither gain nor loss.",
    textTr: "Çekingenliğin meyvesi, ne kazançtır ne de kayıp.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202034, author: "Arap Atasözü", category: "legacy", tags: ["legacy","discipline"],
    text: "What is learned in youth is carved in stone.",
    textTr: "Gençlikte öğrenilen, taşa kazınmış gibi kalıcıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202035, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Opinion comes before the bravery of the brave.",
    textTr: "Görüş, cesurun cesaretinden önce gelir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202036, author: "Arap Atasözü", category: "regret", tags: ["reckoning"],
    text: "You reap what you sow.",
    textTr: "Ne ekersen onu biçersin.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202037, author: "Arap Atasözü", category: "legacy", tags: ["legacy","reckoning"],
    text: "The house of a tyrant becomes a ruin.",
    textTr: "Zalimin evi, virane olur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202038, author: "Arap Atasözü", category: "wisdom", tags: ["peace","discipline"],
    text: "Close the door that brings in the wind, and rest easy.",
    textTr: "Rüzgârı içeri alan kapıyı kapat da rahat et.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202039, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Experimentation is the greatest science.",
    textTr: "Deneyim, bilimlerin en büyüğüdür.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202040, author: "Arap Atasözü", category: "discipline", tags: ["discipline"],
    text: "Keep your distance from every kind of dirtiness.",
    textTr: "Kendini her türlü pislikten uzak tut.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202041, author: "Arap Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Eat less to sleep more.",
    textTr: "Az ye ki çok uyuyabilesin.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202042, author: "Arap Atasözü", category: "resilience", tags: ["resilience"],
    text: "Tougher than a stone.",
    textTr: "Taştan bile daha dayanıklı.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202043, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Forgetting is the plague of knowledge.",
    textTr: "Unutmak, bilginin vebasıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202044, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "The wisest is the one who can forgive.",
    textTr: "En bilge olan, affedebilendir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202045, author: "Arap Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "More skillful than a silk worm.",
    textTr: "İpekböceğinden bile daha maharetli.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202046, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "You are striking cold iron.",
    textTr: "Soğuk demire vuruyorsun.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202047, author: "Arap Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Get together like brothers, but work together like strangers.",
    textTr: "Kardeş gibi bir araya gel, yabancı gibi çalış.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202048, author: "Arap Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Planning is half of living.",
    textTr: "Planlamak, yaşamanın yarısıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202049, author: "Arap Atasözü", category: "identity", tags: ["focus","wisdom"],
    text: "Like a fish in water.",
    textTr: "Sudaki balık gibi.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202050, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "He makes a dome out of a single grain.",
    textTr: "Bir taneden koca bir kubbe yapıyor.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202051, author: "Arap Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Visit rarely, and you will be loved more.",
    textTr: "Seyrek ziyaret et, daha çok sevilirsin.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202052, author: "Arap Atasözü", category: "discipline", tags: ["discipline"],
    text: "Do not eat your bread at somebody else's table.",
    textTr: "Ekmeğini başkasının sofrasında yeme.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202053, author: "Arap Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Do not delay today's work for tomorrow.",
    textTr: "Bugünün işini yarına bırakma.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202054, author: "Arap Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Ask your purse what you should buy.",
    textTr: "Ne alacağını, önce cüzdanına sor.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202055, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Think of the way out before you enter.",
    textTr: "İçeri girmeden önce çıkışı düşün.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202056, author: "Arap Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "With care, you come to recognize your opportunities.",
    textTr: "Fırsatlarını ancak dikkatle fark edersin.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202057, author: "Arap Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "A sense of humor is the pole that adds balance to our steps as we walk the tightrope of life.",
    textTr: "Mizah duygusu, hayatın gerdiği ip üzerinde yürürken bize denge veren sırıktır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202058, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A foolish man may be known by six things: anger without cause, speech without profit, change without progress, inquiry without object, trusting a stranger, and mistaking foes for friends.",
    textTr: "Ahmak bir adam altı şeyden tanınır: sebepsiz öfke, faydasız söz, ilerlemesiz değişim, amaçsız soru, yabancıya güvenmek ve düşmanı dost sanmak.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202059, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "Whoever has a head-wound keeps feeling it.",
    textTr: "Başı yaralı olan, yarasını sürekli yoklar.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202060, author: "Arap Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "A person does not attain everything he wishes for; the winds do not blow as the ships desire.",
    textTr: "İnsan dilediği her şeye kavuşamaz; rüzgârlar da gemilerin istediği gibi esmez.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202061, author: "Arap Atasözü", category: "suffering", tags: ["reckoning"],
    text: "When it comes to the stomach, the mind gets lost.",
    textTr: "Mide söz konusu olunca, akıl kaybolur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202062, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "For the Bedouin, everything is soap.",
    textTr: "Bedevi için her şey sabundur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202063, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Oh bald man, we are confused about where to kiss you.",
    textTr: "Ey kel adam, seni nereden öpeceğimizi şaşırdık.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202064, author: "Arap Atasözü", category: "regret", tags: ["reckoning","resilience"],
    text: "The straw that broke the camel's back.",
    textTr: "Devenin belini kıran son saman çöpü.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202065, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Walk in a funeral procession, but do not walk in a wedding procession.",
    textTr: "Cenazeye git, ama düğüne gitme.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202066, author: "Arap Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Among the blind, the one-eyed man is king.",
    textTr: "Körler ülkesinde, tek gözlü adam kraldır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202067, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "A bird in the hand is better than ten on a tree.",
    textTr: "Eldeki bir kuş, ağaçtaki on kuştan iyidir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202068, author: "Arap Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Complaining is the weapon of the weak.",
    textTr: "Şikâyet, zayıfın silahıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202069, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Good manners are the greatest friend.",
    textTr: "Güzel ahlak, en büyük dosttur.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202070, author: "Arap Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Seek knowledge from the cradle to the grave.",
    textTr: "Beşikten mezara kadar ilim öğren.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202071, author: "Arap Atasözü", category: "discipline", tags: ["discipline"],
    text: "Cleanliness comes from faith.",
    textTr: "Temizlik, imandan gelir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202072, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Endings are what settle the value of matters.",
    textTr: "İşlerin değeri, sonuçlarıyla belirlenir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202073, author: "Arap Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The misfortunes of some people are advantages to others.",
    textTr: "Birinin felaketi, başkasının kazancıdır.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202074, author: "Arap Atasözü", category: "identity", tags: ["wisdom","reckoning"],
    text: "The carpenter's own door hangs loose.",
    textTr: "Marangozun kendi kapısı gevşektir.",
    origin: "Arabistan", originEmoji: "🐪", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202075, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Haste lets the devil into the work.",
    textTr: "Acele işe şeytan karışır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202076, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "The inexperienced mule dumps its load right at the door.",
    textTr: "Acemi katır kapı önünde yük indirir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202077, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A tree falls from its own root.",
    textTr: "Ağaç kökünden yıkılır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202078, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "However tall a tree grows, it never reaches the sky.",
    textTr: "Ağaç ne kadar uzasa göğe ermez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202079, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Go slowly, so that you may go far.",
    textTr: "Ağır git ki yol alasın.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202080, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "A heavy stone does not move from its place.",
    textTr: "Ağır taş yerinden oynamaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202081, author: "Türk Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Whoever's mind boiled in August has a pot boiling in the depths of winter.",
    textTr: "Ağustosta beyni kaynayanın zemheride kazanı kaynar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202082, author: "Türk Atasözü", category: "regret", tags: ["reckoning"],
    text: "A curse never stays lying on the ground.",
    textTr: "Ah yerde kalmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202083, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Flowing water gathers no moss.",
    textTr: "Akan su yosun tutmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202084, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Wisdom is not in the age, but in the mind.",
    textTr: "Akıl yaşta değil baştadır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202085, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A clever enemy is better than a foolish friend.",
    textTr: "Akıllı düşman akılsız dosttan hayırlıdır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202086, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The path of reason is one and the same for all.",
    textTr: "Aklın yolu birdir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202087, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Your own mind can disgrace you, and your own mind can make you a vizier.",
    textTr: "Aklınla rezil olursun, aklınla vezir olursun.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202088, author: "Türk Atasözü", category: "fire", tags: ["resilience","wisdom"],
    text: "Gold reveals itself in fire, a person reveals themselves in hardship.",
    textTr: "Altın ateşte, insan mihnette belli olur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202089, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "Gold does not rust.",
    textTr: "Altın pas tutmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202090, author: "Türk Atasözü", category: "resilience", tags: ["resilience"],
    text: "Gold does not rust on the ground, and stone is not soaked by the rain.",
    textTr: "Altın yerde paslanmaz, taş yağmurdan ıslanmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202091, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Only a jeweler knows the true worth of gold.",
    textTr: "Altının kıymetini sarraf bilir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202092, author: "Türk Atasözü", category: "fire", tags: ["discipline","wisdom"],
    text: "Saying the word 'fire' does not burn the mouth.",
    textTr: "Ateş demekle ağız yanmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202093, author: "Türk Atasözü", category: "fire", tags: ["wisdom","reckoning"],
    text: "There is no smoke where there is no fire.",
    textTr: "Ateş olmayan yerden duman çıkmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202094, author: "Türk Atasözü", category: "regret", tags: ["reckoning"],
    text: "An arrow that has been shot never returns.",
    textTr: "Atılan ok geri dönmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202095, author: "Türk Atasözü", category: "fire", tags: ["resilience","reckoning"],
    text: "A small fire can burn a great pile of wood.",
    textTr: "Az ateş çok odunu yakar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202096, author: "Türk Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Better a little food and a headache-free life.",
    textTr: "Azıcık aşım, ağrısız başım.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202097, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Whoever seeks, finds — be it their Lord or their own ruin.",
    textTr: "Arayan Mevla'sını da bulur, belasını da.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202098, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "Tell me who your friend is, and I will tell you who you are.",
    textTr: "Arkadaşını söyle, kim olduğunu söyleyeyim.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202099, author: "Türk Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "Without passion, there is no mastery.",
    textTr: "Aşk olmayınca meşk olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202100, author: "Türk Atasözü", category: "identity", tags: ["discipline"],
    text: "A stomach used to porridge keeps craving porridge.",
    textTr: "Alışmış kursak bulamacını ister.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202101, author: "Türk Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Whoever is not content with little never finds much.",
    textTr: "Aza kanaat etmeyen çoğu hiç bulamaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202102, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Whoever sets out on the road without provisions keeps eyeing other travelers' bags.",
    textTr: "Azıksız yola çıkanın gözü el torbasında kalır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202103, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "They put everyone's wits up for sale at the market, and each went home carrying only their own.",
    textTr: "Akılları pazara çıkarmışlar, herkes yine kendi aklını almış.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202104, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "A tree rustles loudest with its own leaves.",
    textTr: "Ağaç yaprağıyla gürler.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202105, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Whoever holds the honey licks their own finger.",
    textTr: "Bal tutan parmağını yalar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202106, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The fish rots from the head down.",
    textTr: "Balık baştan kokar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202107, author: "Türk Atasözü", category: "resilience", tags: ["resilience"],
    text: "There is no tree the axe has never touched.",
    textTr: "Balta değmedik ağaç olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202108, author: "Türk Atasözü", category: "identity", tags: ["motivation"],
    text: "Be the head, even if only the head of a donkey.",
    textTr: "Baş ol da eşek başı ol.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202109, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "A thousand friends are too few; a single enemy is already too many.",
    textTr: "Bin dost az, bir düşman çok.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202110, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Measure a thousand times before you cut once.",
    textTr: "Bin ölçüp bir biçmeli.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202111, author: "Türk Atasözü", category: "discipline", tags: ["motivation","discipline"],
    text: "What can one hand do alone? Two hands together make a sound.",
    textTr: "Bir elin nesi var, iki elin sesi var.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202112, author: "Türk Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "Two watermelons do not fit under one arm.",
    textTr: "Bir koltuğa iki karpuz sığmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202113, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "One nail saves a horseshoe, one horseshoe saves a horse.",
    textTr: "Bir mıh bir nal kurtarır, bir nal bir at kurtarır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202114, author: "Türk Atasözü", category: "resilience", tags: ["discipline","resilience"],
    text: "A tree does not fall with a single blow.",
    textTr: "Bir vuruşla ağaç devrilmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202115, author: "Türk Atasözü", category: "discipline", tags: ["motivation","discipline"],
    text: "Strength is born from unity.",
    textTr: "Birlikten kuvvet doğar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202116, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "An empty ear of wheat stands the tallest.",
    textTr: "Boş başak dik durur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202117, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Working for free is still better than wandering about idle.",
    textTr: "Boş gezmekten bedava çalışmak yeğdir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202118, author: "Türk Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Take a big bite of food, but never make a big promise.",
    textTr: "Büyük lokma ye büyük söz söyleme.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202119, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The big fish swallows the small fish.",
    textTr: "Büyük balık küçük balığı yutar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202120, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Today's hen is better than tomorrow's goose.",
    textTr: "Bugünkü tavuk yarınki kazdan iyidir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202121, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Saying 'honey, honey' never sweetens the mouth.",
    textTr: "Bal bal demekle ağız tatlanmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202122, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Tend the vineyard and it flourishes; neglect it and it turns to wild hillside.",
    textTr: "Bakarsan bağ olur, bakmazsan dağ olur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202123, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "The five fingers of a hand are not all alike.",
    textTr: "Beş parmak bir olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202124, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "One hard-earned lesson teaches more than a thousand pieces of advice.",
    textTr: "Bin nasihatten bir musibet yeğdir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202125, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "Let not the left hand know what the right hand has given.",
    textTr: "Bir elin verdiğini öbür el duymasın.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202126, author: "Türk Atasözü", category: "identity", tags: ["legacy"],
    text: "They caged the nightingale in gold, and still it cried, 'ah, my homeland.'",
    textTr: "Bülbülü altın kafese koymuşlar, 'ah vatanım' demiş.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202127, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "Mountains never meet each other, but people always meet again.",
    textTr: "Dağ dağa kavuşmaz, insan insana kavuşur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202128, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Whoever asks for guidance crosses the mountain; whoever does not, loses the way on flat ground.",
    textTr: "Danışan dağı aşmış, danışmayan düz yolda şaşmış.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202129, author: "Türk Atasözü", category: "suffering", tags: ["resilience"],
    text: "Iron rusts from dampness, and a person decays from sorrow.",
    textTr: "Demir nemden, insan gamdan çürür.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202130, author: "Türk Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "Whoever gives the sorrow also gives its remedy.",
    textTr: "Derdi veren devasını da verir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202131, author: "Türk Atasözü", category: "suffering", tags: ["wisdom"],
    text: "Whoever cannot speak their pain will never find its cure.",
    textTr: "Derdini söylemeyen derman bulamaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202132, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Do not change horses while crossing the stream.",
    textTr: "Dereyi geçerken at değiştirilmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202133, author: "Türk Atasözü", category: "suffering", tags: ["wisdom"],
    text: "Sorrow is measured by the one who has to carry it.",
    textTr: "Dert, çekene göredir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202134, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Fortune does not walk to a man's door on its own feet.",
    textTr: "Devlet adama ayağıyla gelmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202135, author: "Türk Atasözü", category: "suffering", tags: ["wisdom"],
    text: "There is no rose without a thorn.",
    textTr: "Dikensiz gül olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202136, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A true word is bitter.",
    textTr: "Doğru söz acıdır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202137, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "A true word needs no oath.",
    textTr: "Doğru söz yemin istemez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202138, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "A true friend tells you the bitter truth.",
    textTr: "Dost acı söyler.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202139, author: "Türk Atasözü", category: "identity", tags: ["resilience"],
    text: "A friend is known on a dark day.",
    textTr: "Dost kara günde belli olur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202140, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "A stone thrown by a friend never cracks the skull.",
    textTr: "Dostun attığı taş baş yarmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202141, author: "Türk Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "Worldly wealth stays behind in this world.",
    textTr: "Dünya malı dünyada kalır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202142, author: "Türk Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "The world dies, and every day ends in evening.",
    textTr: "Dünya ölümlü, gün akşamlı.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202143, author: "Türk Atasözü", category: "suffering", tags: ["wisdom"],
    text: "The fallen have no friends left.",
    textTr: "Düşenin dostu olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202144, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","resilience"],
    text: "Even if your enemy is only an ant, never look down on it.",
    textTr: "Düşmanın karınca ise de hor bakma.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202145, author: "Türk Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Seeking horns, the camel lost its ears instead.",
    textTr: "Deve boynuz ararken kulaktan olmuş.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202146, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "What reaches the tongue eventually reaches the hand.",
    textTr: "Dile gelen ele gelir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202147, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "They chase the truth-teller out of nine villages.",
    textTr: "Doğru söyleyeni dokuz köyden kovarlar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202148, author: "Türk Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "There is no cure for death.",
    textTr: "Ecele çare bulunmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202149, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "The doer finds his reward, the moaner only dies complaining.",
    textTr: "Eden bulur, inleyen ölür.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202150, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "A bowed head is never struck off.",
    textTr: "Eğilen baş kesilmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202151, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "One hand washes the other, and together the two hands wash the face.",
    textTr: "El eli yıkar, iki el yüzü.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202152, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Whoever leaves early goes to work; whoever leaves late goes for nothing.",
    textTr: "Er giden işine, geç giden boşuna.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202153, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "An old friend never turns into an enemy.",
    textTr: "Eski dost düşman olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202154, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "Flesh does not separate from the nail.",
    textTr: "Et tırnaktan ayrılmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202155, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Do not buy a house, buy a neighbor.",
    textTr: "Ev alma, komşu al.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202156, author: "Türk Atasözü", category: "discipline", tags: ["reckoning","discipline"],
    text: "Reckon the cost first, before you commit to the butcher.",
    textTr: "Evvel hesap, sonra kasap.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202157, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "An old enemy never becomes a friend.",
    textTr: "Eski düşman dost olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202158, author: "Türk Atasözü", category: "wisdom", tags: ["reckoning","wisdom"],
    text: "The accounting made at home never matches the marketplace.",
    textTr: "Evdeki hesap çarşıya uymaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202159, author: "Türk Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "The worth of youth is only known once old age arrives.",
    textTr: "Gençliğin kıymeti ihtiyarlıkta bilinir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202160, author: "Türk Atasözü", category: "discipline", tags: ["discipline","legacy"],
    text: "Carry stones in your youth, so you may eat your meal in comfort in old age.",
    textTr: "Gençlikte taş taşı, kocalıkta ye aşı.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202161, author: "Türk Atasözü", category: "discipline", tags: ["motivation","discipline"],
    text: "The wandering wolf never goes hungry.",
    textTr: "Gezen kurt aç kalmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202162, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "You cannot prop up the sky, nor put a lid over the sea.",
    textTr: "Göğe direk, denize kapak olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202163, author: "Türk Atasözü", category: "suffering", tags: ["peace"],
    text: "The heart is a palace of glass; once it is broken, it cannot be rebuilt.",
    textTr: "Gönül bir sırça saraydır, kırılırsa yapılmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202164, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A village already in view needs no guide.",
    textTr: "Görünen köy kılavuz istemez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202165, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "What is far from the eye grows far from the heart as well.",
    textTr: "Gözden ırak olan gönülden de ırak olur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202166, author: "Türk Atasözü", category: "suffering", tags: ["resilience"],
    text: "Whoever loves the rose must endure its thorn.",
    textTr: "Gülü seven dikenine katlanır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202167, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The sun cannot be smeared over with mud.",
    textTr: "Güneş balçıkla sıvanmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202168, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Do not trust in wealth, or you will fall into want.",
    textTr: "Güvenme varlığa, düşersin darlığa.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202169, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Before the sun has risen, no one can pronounce how the day will turn out.",
    textTr: "Gün doğmadan kimliği söylenmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202170, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "A single greeting to a lonely stranger is worth a thousand gold coins.",
    textTr: "Garibe bir selam bin altın değer.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202171, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Nothing stays hidden from the perceptive eye.",
    textTr: "Gözlüye gizli yoktur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202172, author: "Türk Atasözü", category: "identity", tags: ["legacy"],
    text: "One tires of beauty in forty days, but never tires of good character in forty years.",
    textTr: "Güzele kırk günde doyulur, iyi huyluya kırk yılda doyulmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202173, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","resilience"],
    text: "Without hardship, a person's true worth is never known.",
    textTr: "Kader olmayınca kadir bilinmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202174, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "Heart answers to heart.",
    textTr: "Kalp kalbe karşıdır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202175, author: "Türk Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "There is no wealth like contentment.",
    textTr: "Kanaat gibi devlet olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202176, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Blood is not washed away with blood, but with water.",
    textTr: "Kanı kanla yumazlar, kanı suyla yurlar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202177, author: "Türk Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "A dark day never stays dark forever.",
    textTr: "Kara gün kararıp kalmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202178, author: "Türk Atasözü", category: "identity", tags: ["resilience"],
    text: "Brothers may stab one another, yet they still return to embrace.",
    textTr: "Kardeş kardeşi bıçaklamış, dönmüş yine kucaklamış.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202179, author: "Türk Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "When its end draws near, even the ant grows wings.",
    textTr: "Karınca, zevali gelince kanatlanır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202180, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Take a lesson from the ant, which prepares for winter in the middle of summer.",
    textTr: "Karıncadan ibret al, yazdan kışı karşılar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202181, author: "Türk Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "The burial shroud has no pocket.",
    textTr: "Kefenin cebi yok.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202182, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Fortune does not descend from the sky in a basket.",
    textTr: "Kısmet gökten zembille inmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202183, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Whatever a person does, in the end they do it to themselves.",
    textTr: "Kişi ne yaparsa kendine yapar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202184, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "A neighbor needs even the ashes of a neighbor.",
    textTr: "Komşu komşunun külüne muhtaçtır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202185, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Better to lie awake all night than to live through a nightmare.",
    textTr: "Korkulu rüya görmektense uyanık yatmak evladır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202186, author: "Türk Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Fear is of no use against death.",
    textTr: "Korkunun ecele faydası yoktur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202187, author: "Türk Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "A dog never learns to swim until it falls into the water.",
    textTr: "Köpek suya düşmeyince yüzmeyi öğrenmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202188, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "No human being is without fault.",
    textTr: "Kul hatasız olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202189, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The wolf loves foggy weather.",
    textTr: "Kurt dumanlı havayı sever.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202190, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "The wolf may change its village, but never its nature.",
    textTr: "Kurt köyünü değiştirir, huyunu değiştirmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202191, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Whoever seeks a flawless friend ends up with no friend at all.",
    textTr: "Kusursuz dost arayan dostsuz kalır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202192, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Empty effort only wears out your sandals.",
    textTr: "Kuru gayret çarık eskitir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202193, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Empty words never fill a stomach.",
    textTr: "Kuru laf karın doyurmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202194, author: "Türk Atasözü", category: "suffering", tags: ["wisdom","resilience"],
    text: "Before the thick ones can be thinned, the thin ones are wrung dry.",
    textTr: "Kalın incelene kadar ince süzülür.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202195, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "A wingless bird cannot fly.",
    textTr: "Kanatsız kuş uçmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202196, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Bad news is heard quickly.",
    textTr: "Kara haber tez duyulur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202197, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "The crow, trying to copy the partridge's walk, forgot its own.",
    textTr: "Karga kekliği taklit edeyim derken kendi yürüyüşünü şaşırmış.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202198, author: "Türk Atasözü", category: "identity", tags: ["peace"],
    text: "The sword never cuts its own sheath.",
    textTr: "Kılıç kınını kesmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202199, author: "Türk Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Be patient in your work, and good will come your way.",
    textTr: "Sabreyle işine, hayır gelsin başına.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202200, author: "Türk Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "The end of patience is safety.",
    textTr: "Sabrın sonu selamettir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202201, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "A loyal friend is worth more than a relative.",
    textTr: "Sadık dost akrabadan yeğdir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202202, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Health is better than riches.",
    textTr: "Sağlık varlıktan yeğdir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202203, author: "Türk Atasözü", category: "legacy", tags: ["legacy","discipline"],
    text: "A trade in the hands is a golden bracelet.",
    textTr: "Sanat altın bileziktir.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202204, author: "Türk Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "Whoever scorns their own craft ends up begging with a sack around their neck.",
    textTr: "Sanatını hor gören boğazına torba takar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202205, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Not even a bird takes flight without a reason.",
    textTr: "Sebepsiz kuş bile uçmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202206, author: "Türk Atasözü", category: "legacy", tags: ["legacy","resilience"],
    text: "The flood passes on, but the sand it carried remains.",
    textTr: "Sel gider, kum kalır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202207, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A flood's mouth can be dammed, but a person's tongue cannot.",
    textTr: "Selin ağzı tutulur, elin ağzı tutulmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202208, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Whoever fears the sparrow never plants the millet.",
    textTr: "Serçeden korkan darı ekmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202209, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "If speech is silver, silence is gold.",
    textTr: "Söz gümüşse sükût altındır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202210, author: "Türk Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Fill your jug while the water is still flowing.",
    textTr: "Su akarken testiyi doldurmalı.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202211, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","resilience"],
    text: "Water does not run clear until it has first been stirred.",
    textTr: "Su bulanmayınca durulmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202212, author: "Türk Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "The water jug breaks precisely on its way to fetch water.",
    textTr: "Su testisi su yolunda kırılır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202213, author: "Türk Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Water always finds its own bed.",
    textTr: "Su yatağını bulur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202214, author: "Türk Atasözü", category: "identity", tags: ["discipline"],
    text: "A habit that enters with the mother's milk leaves only with the soul.",
    textTr: "Sütle giren huy, canla çıkar.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202215, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Whoever has burned their mouth on hot milk blows even on cold yogurt.",
    textTr: "Sütten ağzı yanan yoğurdu üfleyerek yer.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202216, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A miracle is never repeated twice for the one who refuses to listen.",
    textTr: "Sağır için iki kere keramet olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202217, author: "Türk Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "Numbered days pass quickly.",
    textTr: "Sayılı günler tez geçer.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202218, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The fly is small, yet it still turns the stomach.",
    textTr: "Sinek küçüktür ama mide bulandırır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202219, author: "Türk Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "Whoever left no footprint in the field has no voice at the harvest.",
    textTr: "Tarlada izi olmayanın harmanda sözü olmaz.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202220, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "A sweet tongue draws even the snake out of its hole.",
    textTr: "Tatlı dil yılanı deliğinden çıkarır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202221, author: "Türk Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "A kind word is food for the soul; a harsh word is a stake through the head.",
    textTr: "Tatlı söz can azığı, acı söz baş kazığı.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202222, author: "Türk Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Whoever keeps watch at the lodge is the one who gets to drink the soup.",
    textTr: "Tekkeyi bekleyen çorbayı içer.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202223, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "The pot rolled along and finally found its lid.",
    textTr: "Tencere yuvarlanmış, kapağını bulmuş.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202224, author: "Türk Atasözü", category: "identity", tags: ["wisdom"],
    text: "The tailor cannot mend his own torn seam.",
    textTr: "Terzi kendi söküğünü dikemez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202225, author: "Türk Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Even if the jug breaks, its handle stays behind in your hand.",
    textTr: "Testi kırılsa da kulpu elde kalır.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202226, author: "Türk Atasözü", category: "suffering", tags: ["wisdom"],
    text: "The well-fed cannot understand the condition of the hungry.",
    textTr: "Tok açın hâlinden bilmez.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202227, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Whoever tills the soil gets to bite into the bread.",
    textTr: "Toprağı işleyen ekmeği dişler.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202228, author: "Türk Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Whoever forgets the debt owed for bread and salt goes blind.",
    textTr: "Tuz ekmek hakkını bilmeyen kör olur.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202229, author: "Türk Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "If you have nails of your own, scratch your own head with them.",
    textTr: "Tırnağın varsa başını kaşı.",
    origin: "Anadolu", originEmoji: "🇹🇷", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202230, author: "Fars Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "The water that has already flowed will never return to the stream.",
    textTr: "Akıp giden su, dereye bir daha dönmez.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202231, author: "Fars Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Drop by drop, the sea itself is formed.",
    textTr: "Damla damla birikir, sonunda deniz olur.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202232, author: "Fars Atasözü", category: "suffering", tags: ["resilience","discipline"],
    text: "Without hardship endured, no treasure is ever gained.",
    textTr: "Zahmet çekmeden hazineye ulaşılmaz.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202233, author: "Fars Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "The true traveler is the one who goes slowly, but never stops.",
    textTr: "Gerçek yolcu, yavaş ama durmadan yürüyendir.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202234, author: "Fars Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Rise at dawn, if it is success you seek.",
    textTr: "Başarmak istiyorsan seherde kalk.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202235, author: "Fars Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Doing a job well comes only from doing it again and again.",
    textTr: "İyi iş yapmak, çok tekrardan gelir.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202236, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Whoever has knowledge also has strength.",
    textTr: "Bilgisi olanın, gücü de olur.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202237, author: "Fars Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "There is no cure for a wound you brought upon yourself.",
    textTr: "Kendi ettiğine çare bulunmaz.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202238, author: "Fars Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "Even within despair itself, a great deal of hope is hidden.",
    textTr: "Umutsuzluğun içinde bile çokça umut vardır.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202239, author: "Fars Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Two hundred words are not worth even half a real deed.",
    textTr: "İki yüz söz, yarım işin değerini tutmaz.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202240, author: "Fars Atasözü", category: "identity", tags: ["resilience"],
    text: "A true friend is the one who takes your hand on your darkest day.",
    textTr: "Gerçek dost, en karanlık anında elinden tutandır.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202241, author: "Fars Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Every person forges their own honor with their own two hands.",
    textTr: "Herkesin onuru kendi elindedir.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202242, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Treat the trouble before it ever has the chance to happen.",
    textTr: "Dert başına gelmeden önce çaresine bak.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202243, author: "Fars Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "If you are patient, you can turn sour, unripe grapes into sweet halva.",
    textTr: "Sabreden, koruktan bile helva çıkarır.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202244, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Do not play with the tail of the lion.",
    textTr: "Aslanın kuyruğuyla oynama.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202245, author: "Fars Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Strike two targets with a single arrow.",
    textTr: "Bir okla iki hedefi vur.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202246, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "An early quarrel over the terms is better than a peace that arrives too late.",
    textTr: "Baştaki çekişme, sondaki barıştan iyidir.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202247, author: "Fars Atasözü", category: "identity", tags: ["wisdom"],
    text: "The wolf only repents once it is dead.",
    textTr: "Kurdun tövbesi ancak ölümle olur.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202248, author: "Fars Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Luck knocks on a person's door only the one time.",
    textTr: "Şans, insanın kapısını yalnızca bir kez çalar.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202249, author: "Fars Atasözü", category: "discipline", tags: ["motivation","discipline"],
    text: "To truly want a thing is already to be able to do it.",
    textTr: "İstemek, yapabilmektir.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202250, author: "Fars Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "The antidote arrived only after Sohrab had already died.",
    textTr: "Derman, Sührab öldükten sonra geldi.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202251, author: "Fars Atasözü", category: "suffering", tags: ["wisdom","resilience"],
    text: "The bigger the roof a man owns, the more snow it must bear.",
    textTr: "Damı büyük olanın, karı da çok olur.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202252, author: "Fars Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "No one scratches my back as well as the nail of my own finger.",
    textTr: "Sırtımı kendi tırnağımdan iyi kimse kaşıyamaz.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202253, author: "Fars Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "The fish is fresh no matter what hour you pull it from the water.",
    textTr: "Balığı sudan ne zaman çıkarırsan çıkar, taze sayılır.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202254, author: "Fars Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Never take a bite bigger than your own mouth.",
    textTr: "Ağzına sığmayacak lokmayı alma.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202255, author: "Fars Atasözü", category: "suffering", tags: ["wisdom","resilience"],
    text: "There is no treasure without its snake, and no rose without its thorn.",
    textTr: "Yılansız hazine, dikensiz gül olmaz.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202256, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "It goes in through one ear and straight out through the other.",
    textTr: "Bir kulağından girer, öbür kulağından çıkar.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202257, author: "Fars Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Find yourself a steady stillness, for no plant ever grows on a rolling stone.",
    textTr: "Kararlı ol; yuvarlanan taşın üstünde bitki yeşermez.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202258, author: "Fars Atasözü", category: "identity", tags: ["wisdom"],
    text: "Only what already lies inside the jug can ever pour out of it.",
    textTr: "Testiden ne varsa dışarı o akar.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202259, author: "Fars Atasözü", category: "suffering", tags: ["wisdom","peace"],
    text: "The tear of an orphan carries a very heavy price.",
    textTr: "Yetimin gözyaşının bedeli ağırdır.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202260, author: "Fars Atasözü", category: "fire", tags: ["resilience","reckoning"],
    text: "A hidden fire, once fed by the wind, only grows larger still.",
    textTr: "Gizli ateşi rüzgâr büyütür.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202261, author: "Fars Atasözü", category: "identity", tags: ["wisdom"],
    text: "The lamp fit for your own home is forbidden inside the mosque.",
    textTr: "Eve yakışan kandil, camiye haramdır.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202262, author: "Fars Atasözü", category: "regret", tags: ["reckoning","resilience"],
    text: "Arriving late is still better than never arriving at all.",
    textTr: "Geç varmak, hiç varamamaktan iyidir.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202263, author: "Fars Atasözü", category: "identity", tags: ["wisdom"],
    text: "The grass must first taste sweet to the goat that has to eat it.",
    textTr: "Ot, onu yiyen keçinin ağzına tatlı gelmeli.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202264, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "A little porridge is better than having nothing at all.",
    textTr: "Az bir çorba, hiç yoktan iyidir.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202265, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Vinegar paid for in cash is worth more than halva only promised on credit.",
    textTr: "Peşin sirke, veresiye helvadan iyidir.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202266, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Like carrying cumin all the way to Kerman.",
    textTr: "Kirman'a kimyon taşımak.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202267, author: "Fars Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "One blind man becomes the guide of another blind man.",
    textTr: "Kör, başka bir körün kılavuzu olur.",
    origin: "İran", originEmoji: "🕌", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202268, author: "Yahudi Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "The quality of a cucumber can be recognized when it is still a blossom.",
    textTr: "Salatalığın kalitesi daha çiçekken bellidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202269, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "The prattle of a child is either from his father or from his mother.",
    textTr: "Çocuğun gevezeliği ya babasından ya da anasındandır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202270, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "The ewe follows the ewe; the daughter's actions are the same as her mother's.",
    textTr: "Koyun koyunu izler; kızın davranışları da annesininkiyle aynıdır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202271, author: "Yahudi Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "A pot belonging to partners is neither hot nor cold.",
    textTr: "Ortakların çömleği ne sıcak olur ne soğuk.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202272, author: "Yahudi Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "A single sharp pepper is better than a basketful of gourds.",
    textTr: "Bir sepet dolusu kabaktan tek bir acı biber yeğdir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202273, author: "Yahudi Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "In the spoon that the carpenter himself made, the mustard will burn his palate.",
    textTr: "Marangozun kendi yaptığı kaşıkta hardal, kendi damağını yakar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202274, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "Either a friend or death.",
    textTr: "Ya bir dost, ya da ölüm.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202275, author: "Yahudi Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "He who has been bitten by a snake is scared of a rope.",
    textTr: "Yılanın ısırdığı kişi, ipten bile korkar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202276, author: "Yahudi Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "In my town I am known by my name. When away, I am known by my clothing.",
    textTr: "Kendi kasabamda adımla, gurbette ise kıyafetimle tanınırım.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202277, author: "Yahudi Atasözü", category: "resilience", tags: ["resilience","reckoning"],
    text: "A hungry dog will even eat dung.",
    textTr: "Aç köpek pisliği bile yer.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202278, author: "Yahudi Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "Poverty follows the poor.",
    textTr: "Yoksulluk, yoksulu izler.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202279, author: "Yahudi Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "When a camel tries to get horns, his ears are cut off.",
    textTr: "Deve boynuz edinmeye çalışırken kulaklarını kaybeder.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202280, author: "Yahudi Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "If you have a fault, be the first to say it.",
    textTr: "Bir kusurun varsa, onu ilk söyleyen sen ol.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202281, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","discipline"],
    text: "Don't throw stones into the well from which you drank.",
    textTr: "Su içtiğin kuyuya taş atma.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202282, author: "Yahudi Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Sell your herbs in a place where herbs grow.",
    textTr: "Otunu, otun zaten yetiştiği yerde satma.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202283, author: "Yahudi Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "Use an expensive goblet today; tomorrow let it break.",
    textTr: "Değerli kadehi bugün kullan; kırılacaksa yarın kırılsın.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202284, author: "Yahudi Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Whether you are right or wrong, don't swear.",
    textTr: "Haklı da olsan haksız da olsan, yemin etme.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202285, author: "Yahudi Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "Don't do favors for evildoers, and no evil will befall you.",
    textTr: "Kötülük yapanlara iyilik etme ki başına kötülük gelmesin.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202286, author: "Yahudi Atasözü", category: "identity", tags: ["resilience","wisdom"],
    text: "Even when you're minding your own business, your enemy feels threatened.",
    textTr: "Sen kendi işinle uğraşırken bile düşmanın kendini tehdit altında hisseder.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202287, author: "Yahudi Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Better to be cursed than to curse.",
    textTr: "Lanetlemektense lanetlenmek yeğdir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202288, author: "Yahudi Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "According to the camel is its load.",
    textTr: "Yük, deveye göre biçilir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202289, author: "Yahudi Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Sixty runners run and do not reach the person who ate in the morning.",
    textTr: "Altmış koşucu koşar da sabah yemek yiyen kişiye yetişemez.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202290, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","resilience"],
    text: "If you lift the load with me, I will be able to lift it; and if you will not, I won't lift it.",
    textTr: "Yükü benimle kaldırırsan kaldırabilirim; kaldırmazsan ben de kaldıramam.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202291, author: "Yahudi Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "One who takes revenge due to his zealotry destroys his own house.",
    textTr: "Aşırı hırsla intikam alan, kendi evini yıkar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202292, author: "Yahudi Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "A thief standing at the entrance of the tunnel calls out to G-d.",
    textTr: "Tünelin girişinde duran hırsız bile Tanrı'ya seslenir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202293, author: "Yahudi Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Wine belongs to the master. Thanks goes to the waiter.",
    textTr: "Şarap efendinindir, teşekkürse hizmetkarınadır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202294, author: "Yahudi Atasözü", category: "identity", tags: ["resilience","wisdom"],
    text: "A myrtle among thorns is still called a myrtle.",
    textTr: "Dikenler arasındaki mersin dalı yine mersin dalıdır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202295, author: "Yidiş Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "A tree doesn't fall with one blow.",
    textTr: "Bir ağaç tek bir darbeyle devrilmez.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202296, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "If a stone stays in one place, it becomes overgrown with grass.",
    textTr: "Bir taş bir yerde durursa üzeri otla kaplanır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202297, author: "Yidiş Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Better to be cursed than pitied.",
    textTr: "Acınmaktansa lanetlenmek yeğdir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202298, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "A wise man hears one word and understands two.",
    textTr: "Akıllı adam bir söz duyar, ikisini anlar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202299, author: "Yidiş Atasözü", category: "fire", tags: ["discipline","peace"],
    text: "Don't pour oil on fire.",
    textTr: "Ateşin üzerine yağ dökme.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202300, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Sometimes the cure is worse than the disease.",
    textTr: "Bazen ilaç, hastalıktan beter olur.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202301, author: "Yidiş Atasözü", category: "identity", tags: ["wisdom","discipline"],
    text: "You can't make a shtreimel from a pig's tail.",
    textTr: "Domuz kuyruğundan kürk şapka yapılmaz.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202302, author: "Yidiş Atasözü", category: "identity", tags: ["legacy","wisdom"],
    text: "The apple doesn't fall far from the tree.",
    textTr: "Elma, ağacından uzağa düşmez.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202303, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Still water digs deep.",
    textTr: "Durgun su derini oyar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202304, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Even silence speaks.",
    textTr: "Sessizlik bile konuşur.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202305, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Better an honest slap in the face than an insincere kiss.",
    textTr: "İçten bir tokat, sahte bir öpücükten iyidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202306, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "You do not fall because you are weak; you fall because you think you are strong.",
    textTr: "İnsan zayıf olduğu için değil, güçlü olduğunu sandığı için düşer.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202307, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","resilience"],
    text: "From success to failure is one step; from failure to success is a long road.",
    textTr: "Başarıdan başarısızlığa bir adım vardır; başarısızlıktan başarıya uzun bir yol.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202308, author: "Yidiş Atasözü", category: "suffering", tags: ["peace","wisdom"],
    text: "What soap is to the body, laughter is to the soul.",
    textTr: "Sabun bedene neyse, kahkaha da ruha odur.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202309, author: "Yidiş Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "One old friend is better than two new ones.",
    textTr: "Eski bir dost, iki yeni dosttan iyidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202310, author: "Yidiş Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "Make new friends, but don't forget the old ones.",
    textTr: "Yeni dostlar edin, ama eskilerini unutmayın.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202311, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Before you start up a ladder, count the rungs.",
    textTr: "Merdivene çıkmadan önce basamakları say.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202312, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Words should be weighed, not counted.",
    textTr: "Sözler sayılmaz, tartılır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202313, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Better ask ten times than go astray once.",
    textTr: "Bir kez yanlış yola sapmaktansa on kez sormak yeğdir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202314, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "In life, each of us must sometimes play the fool.",
    textTr: "Hayatta her birimiz zaman zaman aptalı oynamak zorundadır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202315, author: "Yidiş Atasözü", category: "fire", tags: ["resilience","discipline"],
    text: "The wolf is not afraid of the dog, but he doesn't like the sound of his barking.",
    textTr: "Kurt köpekten korkmaz, ama havlamasından hoşlanmaz.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202316, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "What you don't see with your eyes, don't invent with your mouth.",
    textTr: "Gözünle görmediğini ağzınla uydurma.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202317, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The pen wounds deeper than an arrow.",
    textTr: "Kalem, oktan daha derin yaralar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202318, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "He who is aware of his folly is wise.",
    textTr: "Ahmaklığının farkında olan, bilgedir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202319, author: "Yidiş Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "Old age, to the unlearned, is winter; to the learned, it's harvest time.",
    textTr: "Yaşlılık, öğrenmemiş kişi için kıştır; öğrenmiş kişi içinse hasat zamanı.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202320, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Nothing tastes bitterer than the truth.",
    textTr: "Hiçbir şey gerçek kadar acı tatmaz.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202321, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Provide for the worst; the best can take care of itself.",
    textTr: "En kötüsüne hazırlan; en iyisi zaten kendine bakar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202322, author: "Yidiş Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "Hope for miracles, but don't rely on one.",
    textTr: "Mucizeyi um, ama ona güvenme.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202323, author: "Yidiş Atasözü", category: "suffering", tags: ["peace","resilience"],
    text: "Time is the best doctor.",
    textTr: "Zaman en iyi doktordur.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202324, author: "Yidiş Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Better ten times ill than one time dead.",
    textTr: "On kez hasta olmak, bir kez ölmekten iyidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202325, author: "Yidiş Atasözü", category: "suffering", tags: ["peace","resilience"],
    text: "Weeping makes the heart grow lighter.",
    textTr: "Ağlamak kalbi hafifletir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202326, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "If we cannot do what we will, we must will what we can.",
    textTr: "Yapmak istediğimizi yapamıyorsak, yapabildiğimizi istemeliyiz.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202327, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","motivation"],
    text: "When luck joins in the game, cleverness scores double.",
    textTr: "Şans oyuna katılınca zeka iki kat sayar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202328, author: "Yidiş Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "Confidence is half of victory.",
    textTr: "Kendine güven, zaferin yarısıdır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202329, author: "Yidiş Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Better to die upright than to live on your knees.",
    textTr: "Diz çökerek yaşamaktansa dik durarak ölmek yeğdir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202330, author: "Yidiş Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "Let it be worse, so long as it's a change.",
    textTr: "Daha kötü olsun, yeter ki bir değişiklik olsun.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202331, author: "Yidiş Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "You can make the dream bigger than the night.",
    textTr: "Hayalini geceden daha büyük yapabilirsin.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202332, author: "Yidiş Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "With time even a bear can learn to dance.",
    textTr: "Zamanla bir ayı bile dans etmeyi öğrenir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202333, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","resilience"],
    text: "The longer the blind live, the more they see.",
    textTr: "Kör olan, ne kadar uzun yaşarsa o kadar çok görür.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202334, author: "Yidiş Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "If things are not as you wish, wish them as they are.",
    textTr: "İşler istediğin gibi değilse, onları oldukları gibi iste.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202335, author: "Yidiş Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Don't be scared when you have no other choice.",
    textTr: "Başka seçeneğin yokken korkma.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202336, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "The heaviest burden is an empty pocket.",
    textTr: "En ağır yük, boş bir cebtir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202337, author: "Yidiş Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "When Dame Fortune calls, offer her a chair.",
    textTr: "Talih kapını çaldığında, ona bir sandalye sun.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202338, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","focus"],
    text: "Lost years are worse than lost dollars.",
    textTr: "Kaybedilen yıllar, kaybedilen paradan daha kötüdür.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202339, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "Money buys everything but good sense.",
    textTr: "Para her şeyi satın alır, ama sağduyuyu satın alamaz.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202340, author: "Yidiş Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "The truly rich are those who enjoy what they have.",
    textTr: "Gerçek zenginler, sahip olduklarının tadını çıkaranlardır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202341, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Experience is what we call the accumulation of our mistakes.",
    textTr: "Deneyim dediğimiz şey, hatalarımızın birikimidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202342, author: "Yidiş Atasözü", category: "identity", tags: ["wisdom","discipline"],
    text: "Too humble is half proud.",
    textTr: "Fazla alçakgönüllülük, yarı kibirliliktir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202343, author: "Yidiş Atasözü", category: "identity", tags: ["wisdom","legacy"],
    text: "Everyone is kneaded out of the same dough but not baked in the same oven.",
    textTr: "Herkes aynı hamurdan yoğrulur, ama aynı fırında pişmez.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202344, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "To every answer you can find a new question.",
    textTr: "Her cevaba yeni bir soru bulabilirsin.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202345, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","legacy"],
    text: "When the time comes for you to live, there aren't enough years.",
    textTr: "Yaşama sırası sana geldiğinde, yıllar yetmez.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202346, author: "Yidiş Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "God created a world full of little worlds.",
    textTr: "Tanrı, küçük dünyalarla dolu bir dünya yarattı.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202347, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "The nearer to the synagogue, the farther from God.",
    textTr: "Sinagoga ne kadar yakınsan, Tanrı'dan o kadar uzaksındır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202348, author: "Yidiş Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Prayers go up and blessings come down.",
    textTr: "Dualar yukarı çıkar, bereketler aşağı iner.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202349, author: "Yidiş Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "Once it was the parents who taught their children to talk; now the children teach their parents to keep quiet.",
    textTr: "Bir zamanlar ebeveynler çocuklarına konuşmayı öğretirdi; şimdi çocuklar ebeveynlerine susmayı öğretiyor.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202350, author: "Yidiş Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "He who is down, cannot fall.",
    textTr: "Dibe vurmuş olan, artık düşemez.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202351, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A smart blow subsides, the sting of a word abides.",
    textTr: "Akıllıca bir darbenin acısı geçer, ama bir sözün acısı kalır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202352, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Tell a donkey by his long ears, a fool by his long tongue.",
    textTr: "Eşek uzun kulaklarından, ahmak uzun dilinden bellidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202353, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "When a fool is silent, he too is thought clever.",
    textTr: "Ahmak sustuğunda, o da akıllı sanılır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202354, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "The whole world rests on the tip of the tongue.",
    textTr: "Bütün dünya, dilin ucunda durur.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202355, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "He who keeps down a wise-crack demonstrates strength.",
    textTr: "Nüktesini yutan, gücünü gösterir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202356, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Eloquent silence is better than eloquent speech.",
    textTr: "Belagatli bir sükût, belagatli bir sözden iyidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202357, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "The less we speak the healthier we are.",
    textTr: "Ne kadar az konuşursak o kadar sağlıklı oluruz.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202358, author: "Yidiş Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "He who remains silent gets the best portion.",
    textTr: "Sessiz kalan, en iyi payı alır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202359, author: "Yidiş Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "They that are mute want to talk most.",
    textTr: "En çok konuşmak isteyen, dilsiz olandır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202360, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Half a truth is a whole lie.",
    textTr: "Yarım gerçek, tam bir yalandır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202361, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "A lock is meant only for honest men.",
    textTr: "Kilit, yalnızca dürüst insanlar içindir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202362, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "A deaf man heard a mute tell how a blind man saw a cripple run.",
    textTr: "Sağır biri, dilsiz birinin anlattığına göre kör birinin topalın koştuğunu gördüğünü duymuş.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202363, author: "Yidiş Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "When both litigants are right, it is bad.",
    textTr: "İki taraf da haklıysa, bu kötüye işarettir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202364, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "The truth never dies, but lives a wretched life.",
    textTr: "Gerçek asla ölmez, ama sefil bir hayat sürer.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202365, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "A false coin always stays around.",
    textTr: "Sahte bir para her zaman ortalıkta kalır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202366, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "False tears keep the true ones out of heaven.",
    textTr: "Sahte gözyaşları, gerçek olanların cennete girmesini engeller.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202367, author: "Yidiş Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Many people like the truth, but not many speak it.",
    textTr: "Çoğu insan gerçeği sever, ama pek azı onu söyler.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202368, author: "Yahudi Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "If a man's destiny is to drown, he will drown even in a glass of water.",
    textTr: "Bir insanın kaderi boğulmaksa, bir bardak suda bile boğulur.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202369, author: "Yahudi Atasözü", category: "suffering", tags: ["peace","wisdom"],
    text: "I was unhappy about not having shoes until I saw a man without feet.",
    textTr: "Ayakkabım olmadığı için üzülüyordum, ta ki ayağı olmayan birini görene kadar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202370, author: "Yahudi Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Youth is a mistake, middle age a battle, and old age a regret.",
    textTr: "Gençlik bir hatadır, orta yaş bir savaş, yaşlılık ise bir pişmanlıktır.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202371, author: "Yahudi Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "A book gives knowledge, but it is life that gives understanding.",
    textTr: "Kitap bilgi verir, ama anlayışı hayat verir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202372, author: "Yahudi Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "The righteous fall seven times, they rise again.",
    textTr: "Doğru kişi yedi kere düşer, yedisinde de yeniden kalkar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202373, author: "Yahudi Atasözü", category: "suffering", tags: ["reckoning","resilience"],
    text: "From happiness to suffering is one step, from suffering to happiness an eternity.",
    textTr: "Mutluluktan acıya bir adım vardır, acıdan mutluluğa bir ömür.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202374, author: "Yahudi Atasözü", category: "identity", tags: ["wisdom","legacy"],
    text: "Everyone is made of the same dough, but not baked in the same oven.",
    textTr: "Herkes aynı hamurdan yapılır, ama aynı fırında pişmez.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202375, author: "Yahudi Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "Two Jews, three opinions.",
    textTr: "İki Yahudi, üç görüş.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202376, author: "Yahudi Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "If everyone were moving in one direction, the whole world would flip over.",
    textTr: "Herkes tek bir yöne doğru gitseydi, tüm dünya alt üst olurdu.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202377, author: "Yahudi Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "People make plans and GOD laughs.",
    textTr: "İnsan plan yapar, Tanrı güler.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202378, author: "Yahudi Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "A bad peace is better than a good war.",
    textTr: "Kötü bir barış, iyi bir savaştan yeğdir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202379, author: "Yahudi Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "We worry about the past, we stress about the present, we get scared about the future.",
    textTr: "Geçmiş için endişeleniriz, şimdiki zamanda gerileriz, gelecekten korkarız.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202380, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","reckoning"],
    text: "When a father helps a son, they both smile, but when a son needs to help his father, they both cry.",
    textTr: "Baba oğluna yardım ettiğinde ikisi de güler; oğul babasına yardım etmek zorunda kaldığındaysa ikisi de ağlar.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202381, author: "Yahudi Atasözü", category: "discipline", tags: ["discipline","reckoning"],
    text: "The girl who can't dance says the orchestra can't play.",
    textTr: "Dans edemeyen kız, orkestranın çalamadığını söyler.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202382, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","reckoning"],
    text: "The shroud has no pockets.",
    textTr: "Kefenin cebi yoktur.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202383, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "A good friend is often better than a brother.",
    textTr: "İyi bir dost, çoğu zaman kardeşten daha iyidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202384, author: "Yahudi Atasözü", category: "suffering", tags: ["resilience","reckoning"],
    text: "To know nothing about suffering means not to be a real man.",
    textTr: "Acıyı hiç tanımamak, gerçek bir insan olmamak demektir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202385, author: "Yahudi Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "If you cannot be thankful for what you have received, be thankful for what has been spared from you.",
    textTr: "Aldığın için şükredemiyorsan, başına gelmeyen için şükret.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202386, author: "Yahudi Atasözü", category: "suffering", tags: ["discipline","peace"],
    text: "It is better to keep a pain in your heart than to expose it to others.",
    textTr: "Acını kalbinde saklamak, başkalarına göstermekten iyidir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202387, author: "Yahudi Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "On the facade we show to others we manifest our potential; through our children we reveal our reality.",
    textTr: "Başkalarına gösterdiğimiz cephede potansiyelimizi sergileriz; çocuklarımızla ise gerçekliğimizi ortaya koyarız.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202388, author: "Yahudi Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "You can't control the wind but you can adjust the sail.",
    textTr: "Rüzgarı kontrol edemezsin, ama yelkeni ayarlayabilirsin.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202389, author: "Yahudi Atasözü", category: "suffering", tags: ["resilience","discipline"],
    text: "The cold strengthens you more than hunger.",
    textTr: "Seni açlıktan çok soğuk güçlendirir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
  { id: 202390, author: "Yahudi Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "It's good to hope, it's the waiting that spoils it.",
    textTr: "Ummak güzeldir, insanı bozan şey beklemektir.",
    origin: "İsrail", originEmoji: "🇮🇱", era: "ancient", packId: "middle-eastern-proverbs" },
];

