const SE_EUROPEAN_PROVERBS_QUOTES = [
  { id: 202901, author: "Fransız Atasözü", category: "identity", tags: ["wisdom"],
    text: "The robe does not make the monk.",
    textTr: "Cübbe insanı keşiş yapmaz.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202902, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "He who lives shall see.",
    textTr: "Yaşayan görecektir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202903, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "To want is to be able.",
    textTr: "İstemek, yapabilmektir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202904, author: "Fransız Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "After the rain, fine weather.",
    textTr: "Yağmurdan sonra güzel hava gelir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202905, author: "Fransız Atasözü", category: "suffering", tags: ["reckoning"],
    text: "A scalded cat fears cold water.",
    textTr: "Sütten ağzı yanan kedi soğuk sudan bile korkar.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202906, author: "Fransız Atasözü", category: "identity", tags: ["wisdom"],
    text: "Everyone sees noon at their own door.",
    textTr: "Herkes öğleni kendi kapısından görür.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202907, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Night brings counsel.",
    textTr: "Gece akıl verir; karar vermeden önce bir gece geçir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202908, author: "Fransız Atasözü", category: "suffering", tags: ["peace"],
    text: "Each day has enough trouble of its own.",
    textTr: "Her günün derdi kendine yeter.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202909, author: "Fransız Atasözü", category: "regret", tags: ["reckoning"],
    text: "As you make your bed, so you must lie in it.",
    textTr: "Yatağını nasıl serersen öyle yatarsın.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202910, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Everything comes to those who know how to wait.",
    textTr: "Beklemesini bilene her şey zamanında gelir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202911, author: "Fransız Atasözü", category: "discipline", tags: ["discipline"],
    text: "Running does no good; you must set out on time.",
    textTr: "Koşmanın faydası yok, zamanında yola çıkmak gerekir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202912, author: "Fransız Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Paris wasn't built in a day.",
    textTr: "Paris bir günde inşa edilmedi.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202913, author: "Fransız Atasözü", category: "discipline", tags: ["discipline"],
    text: "He who wants to travel far spares his mount.",
    textTr: "Uzağa gitmek isteyen atını yormaz.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202914, author: "Fransız Atasözü", category: "legacy", tags: ["legacy","resilience"],
    text: "Little streams make great rivers.",
    textTr: "Küçük dereler büyük nehirleri oluşturur.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202915, author: "Fransız Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "He who does not move forward, falls back.",
    textTr: "İlerlemeyen geriler.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202916, author: "Fransız Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "Strike while the iron is hot.",
    textTr: "Demir tavında dövülür.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202917, author: "Fransız Atasözü", category: "identity", tags: ["wisdom"],
    text: "Those who resemble each other flock together.",
    textTr: "Birbirine benzeyenler bir araya gelir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202918, author: "Fransız Atasözü", category: "suffering", tags: ["reckoning"],
    text: "Far from the eyes, far from the heart.",
    textTr: "Gözden ırak olan gönülden de ırak olur.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202919, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Good accounts make good friends.",
    textTr: "İyi hesap iyi dostluk yaratır.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202920, author: "Fransız Atasözü", category: "legacy", tags: ["legacy"],
    text: "A good friend is worth more than a hundred relatives.",
    textTr: "İyi bir dost, yüz akrabadan daha değerlidir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202921, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Money does not make happiness.",
    textTr: "Para mutluluk getirmez.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202922, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "You can't make an omelet without breaking eggs.",
    textTr: "Yumurta kırmadan omlet yapılmaz.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202923, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "No sooner said than done.",
    textTr: "Söylemesiyle yapması bir oldu.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202924, author: "Fransız Atasözü", category: "identity", tags: ["wisdom"],
    text: "All that glitters is not gold.",
    textTr: "Parlayan her şey altın değildir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202925, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Prevention is better than cure.",
    textTr: "Önlem almak, tedavi etmekten iyidir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202926, author: "Fransız Atasözü", category: "regret", tags: ["reckoning"],
    text: "Don't sell the bear's skin before you've killed it.",
    textTr: "Ayıyı öldürmeden derisini satma.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202927, author: "Fransız Atasözü", category: "identity", tags: ["reckoning"],
    text: "He who steals an egg will steal an ox.",
    textTr: "Yumurta çalan öküz de çalar.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202928, author: "Fransız Atasözü", category: "wisdom", tags: ["peace"],
    text: "Don't wake the sleeping cat.",
    textTr: "Uyuyan kediyi uyandırma.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202929, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "He who says nothing consents.",
    textTr: "Sessiz kalan onaylamış sayılır.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202930, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Speech is silver, but silence is golden.",
    textTr: "Söz gümüşse sükût altındır.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202931, author: "Fransız Atasözü", category: "resilience", tags: ["resilience","focus"],
    text: "The dogs bark, the caravan moves on.",
    textTr: "Köpekler havlar, kervan yürür.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202932, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "To hit two birds with one stone.",
    textTr: "Tek taşla iki kuş vurmak.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202933, author: "Fransız Atasözü", category: "discipline", tags: ["focus"],
    text: "Don't chase two hares at once.",
    textTr: "Aynı anda iki tavşanın peşine düşme.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202934, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "To a good cat, a good rat.",
    textTr: "İyi kediye iyi fare denk gelir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202935, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "When the cat's away, the mice will play.",
    textTr: "Kedi yokken fareler dans eder.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202936, author: "Fransız Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who breaks the glasses pays for them.",
    textTr: "Bardağı kıran, bedelini de öder.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202937, author: "Fransız Atasözü", category: "suffering", tags: ["reckoning"],
    text: "He who laughs on Friday will weep on Sunday.",
    textTr: "Cuma günü gülen, pazar günü ağlar.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202938, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Help yourself, and heaven will help you.",
    textTr: "Sen kendine yardım et ki gökyüzü de sana yardım etsin.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202939, author: "Fransız Atasözü", category: "regret", tags: ["reckoning"],
    text: "Ill-gotten goods never prosper.",
    textTr: "Haram mal insana yaramaz.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202940, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "It is by forging that one becomes a blacksmith.",
    textTr: "Demirci, demir döverek demirci olur.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202941, author: "Fransız Atasözü", category: "identity", tags: ["wisdom"],
    text: "Chase away the natural, and it returns at a gallop.",
    textTr: "Doğanı kovsan da o dörtnala geri döner.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202942, author: "Fransız Atasözü", category: "fire", tags: ["wisdom","reckoning"],
    text: "One must not play with fire.",
    textTr: "Ateşle oynanmaz.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202943, author: "Fransız Atasözü", category: "suffering", tags: ["discipline","peace"],
    text: "One must not burn the candle at both ends.",
    textTr: "Mumu iki ucundan yakmamalı.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202944, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "One must not put all one's eggs in the same basket.",
    textTr: "Bütün yumurtaları aynı sepete koyma.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202945, author: "Fransız Atasözü", category: "identity", tags: ["wisdom"],
    text: "One must not trust appearances.",
    textTr: "Görünüşe güvenilmez.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202946, author: "Fransız Atasözü", category: "fire", tags: ["reckoning"],
    text: "To add oil to the fire.",
    textTr: "Ateşe odun atmak.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202947, author: "Fransız Atasözü", category: "legacy", tags: ["legacy"],
    text: "Art is long, life is short.",
    textTr: "Sanat uzun, ömür kısadır.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202948, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "One must think before acting.",
    textTr: "Davranmadan önce düşünmek gerekir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202949, author: "Fransız Atasözü", category: "legacy", tags: ["legacy","discipline"],
    text: "One must lead by example.",
    textTr: "Örnek olarak öğretmek gerekir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202950, author: "Fransız Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Patience is the virtue of the wise.",
    textTr: "Sabır, bilgenin erdemidir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202951, author: "Fransız Atasözü", category: "wisdom", tags: ["peace","discipline"],
    text: "Everything in its own time.",
    textTr: "Her şeyin bir zamanı vardır.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202952, author: "Fransız Atasözü", category: "identity", tags: ["wisdom"],
    text: "Every man is master in his own house.",
    textTr: "Herkes kendi evinde efendidir.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202953, author: "Fransız Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Charity well-ordered begins with oneself.",
    textTr: "Sağlıklı hayırseverlik önce kendinden başlar.",
    origin: "Fransa", originEmoji: "🇫🇷", era: "medieval", packId: "se-european-proverbs" },
  { id: 202954, author: "İspanyol Atasözü", category: "identity", tags: ["wisdom"],
    text: "Tell me who you walk with, and I will tell you who you are.",
    textTr: "Söyle bana kiminle gezersin, söyleyeyim sana kim olduğunu.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202955, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Don't look a gift horse in the mouth.",
    textTr: "Hediye edilen atın dişine bakılmaz.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202956, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "To bad weather, a good face.",
    textTr: "Kötü havaya iyi bir yüz göster.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202957, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Lacking bread, cakes will do.",
    textTr: "Ekmek yoksa pasta da olur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202958, author: "İspanyol Atasözü", category: "wisdom", tags: ["peace"],
    text: "Full stomach, happy heart.",
    textTr: "Dolu karın, mutlu yürek.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202959, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "The shrimp that falls asleep is swept away by the current.",
    textTr: "Uyuyan karides akıntıya kapılır.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202960, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning"],
    text: "Raise crows and they will peck your eyes out.",
    textTr: "Karga besle, gözünü oysun.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202961, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "When the river makes noise, it is carrying water.",
    textTr: "Nehir gürlüyorsa su taşıyordur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202962, author: "İspanyol Atasözü", category: "legacy", tags: ["legacy"],
    text: "From such a stick, such a splinter.",
    textTr: "Odun neyse, kıymık da odur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202963, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "God helps those who rise early.",
    textTr: "Erken kalkana Tanrı yardım eder.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202964, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "A bird in the hand is worth a hundred flying.",
    textTr: "Eldeki kuş, uçan yüz kuştan iyidir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202965, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "There is no bad from which good does not come.",
    textTr: "İçinden bir iyilik çıkmayan kötülük yoktur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202966, author: "İspanyol Atasözü", category: "suffering", tags: ["reckoning"],
    text: "Eyes that do not see, heart that does not feel.",
    textTr: "Görmeyen göz, hissetmeyen kalp.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202967, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Flies don't enter a closed mouth.",
    textTr: "Kapalı ağıza sinek girmez.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202968, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Skill is worth more than strength.",
    textTr: "Beceri, güçten daha değerlidir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202969, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Zamora wasn't won in an hour.",
    textTr: "Zamora bir saatte fethedilmedi.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202970, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Before speaking, one must think.",
    textTr: "Konuşmadan önce düşünmek gerekir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202971, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who sows winds, reaps storms.",
    textTr: "Rüzgar eken fırtına biçer.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202972, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who kills by the sword dies by the sword.",
    textTr: "Kılıçla öldüren kılıçla ölür.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202973, author: "İspanyol Atasözü", category: "identity", tags: ["wisdom"],
    text: "Though the monkey dress in silk, she remains a monkey.",
    textTr: "Maymun ipekle giyinse de yine maymundur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202974, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning"],
    text: "No one knows the worth of water until it runs out.",
    textTr: "Suyun kıymeti, o tükenince anlaşılır.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202975, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "In danger, you know your friend.",
    textTr: "Dostunu tehlike anında tanırsın.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202976, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "What's cheap comes out costly.",
    textTr: "Ucuz olan sonunda pahalıya mal olur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202977, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Necessity makes masters.",
    textTr: "İhtiyaç, ustalar yetiştirir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202978, author: "İspanyol Atasözü", category: "wisdom", tags: ["peace"],
    text: "Don't wake the sleeping dog.",
    textTr: "Uyuyan köpeği uyandırma.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202979, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Better to prevent than to cure.",
    textTr: "Önlemek, tedavi etmekten iyidir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202980, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning"],
    text: "Don't sell the bear's skin before hunting it.",
    textTr: "Ayıyı avlamadan derisini satma.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202981, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "What's done, face with your chest.",
    textTr: "Olan oldu, göğsünü ger ve karşıla.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202982, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Don't leave for tomorrow what you can do today.",
    textTr: "Bugün yapabileceğini yarına bırakma.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202983, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "When the cat sleeps, the mice dance.",
    textTr: "Kedi uyurken fareler dans eder.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202984, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Four eyes see more than two.",
    textTr: "Dört göz, iki gözden daha çok görür.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202985, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline"],
    text: "He who does not waste, does not want.",
    textTr: "İsraf etmeyen, muhtaç kalmaz.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202986, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Wherever you go, do as you see.",
    textTr: "Nereye gidersen git, orada gördüğün gibi davran.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202987, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "It's never too late if the outcome is good.",
    textTr: "Sonuç iyiyse hiçbir zaman geç değildir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202988, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "When you see your neighbor's beard being trimmed, put yours to soak.",
    textTr: "Komşunun sakalı kırpılırken sen kendininkini ıslat.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202989, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "He who wants something must pay something for it.",
    textTr: "Bir şey isteyen, bir şeyler ödemelidir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202990, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Eating and scratching, it is all in starting.",
    textTr: "Yemek de kaşınmak da, iş başlamaktır.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202991, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "You shall not go to bed without knowing one more thing.",
    textTr: "Bir şey daha öğrenmeden yatağa girme.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202992, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who went to Seville, lost his seat.",
    textTr: "Sevilla'ya giden, yerini kaybeder.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202993, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "After the storm comes the calm.",
    textTr: "Fırtınadan sonra sükunet gelir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202994, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "No matter how early you rise, dawn will not come sooner.",
    textTr: "Ne kadar erken kalkarsan kalk, şafak daha erken sökmez.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202995, author: "İspanyol Atasözü", category: "identity", tags: ["wisdom"],
    text: "A tree that grows crooked never straightens its trunk.",
    textTr: "Eğri büyüyen ağacın gövdesi bir daha doğrulmaz.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202996, author: "İspanyol Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "He who grasps too much, holds little.",
    textTr: "Çok şeye el atan, azını tutabilir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202997, author: "İspanyol Atasözü", category: "identity", tags: ["wisdom"],
    text: "The habit does not make the monk.",
    textTr: "Cübbe insanı keşiş yapmaz.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202998, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "There is no shortcut without work.",
    textTr: "Emeksiz kısayol yoktur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 202999, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "He who does not risk, does not win.",
    textTr: "Riske girmeyen kazanamaz.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203000, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "There is none so deaf as he who does not want to hear.",
    textTr: "Duymak istemeyenden daha sağır kimse yoktur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203001, author: "İspanyol Atasözü", category: "identity", tags: ["wisdom"],
    text: "Each sheep with its own match.",
    textTr: "Her koyunun eşi kendine denktir.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203002, author: "İspanyol Atasözü", category: "identity", tags: ["legacy"],
    text: "Temperament and figure, until the grave.",
    textTr: "Huy ve endam, mezara kadar değişmez.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203003, author: "İspanyol Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "He who pursues it, achieves it.",
    textTr: "Peşinden koşan, ona kavuşur.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203004, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Beans are cooked everywhere.",
    textTr: "Her yerde fasulye pişer (dert her yerde vardır).",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203005, author: "İspanyol Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Hasten through the bad step.",
    textTr: "Kötü adımı hızlıca geç.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203006, author: "İspanyol Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "Put all the meat on the grill.",
    textTr: "Bütün eti ateşe koy, her şeyini ortaya koy.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203007, author: "İspanyol Atasözü", category: "legacy", tags: ["legacy","reckoning"],
    text: "Build a reputation and go to sleep.",
    textTr: "Bir şöhret kazan, sonra rahatına bak.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203008, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Clear accounts, long friendships.",
    textTr: "Hesap ne kadar açık, dostluk o kadar uzun sürer.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203009, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who does it, pays for it.",
    textTr: "Yapan öder.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203010, author: "İspanyol Atasözü", category: "regret", tags: ["reckoning"],
    text: "Every pig gets its San Martín's day.",
    textTr: "Her domuzun bir San Martín günü gelir (herkes hesabını öder).",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203011, author: "İspanyol Atasözü", category: "wisdom", tags: ["wisdom","legacy"],
    text: "Deeds are love, not fine words.",
    textTr: "Sevgi eylemdir, güzel sözler değil.",
    origin: "İspanya", originEmoji: "🇪🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203012, author: "İtalyan Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "He who goes slowly, goes safely and goes far.",
    textTr: "Yavaş giden, sağlam ve uzağa gider.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203013, author: "İtalyan Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "He who sleeps does not catch fish.",
    textTr: "Uyuyan balık tutamaz.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203014, author: "İtalyan Atasözü", category: "suffering", tags: ["resilience","peace"],
    text: "There is no rose without thorns.",
    textTr: "Dikensiz gül olmaz.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203015, author: "İtalyan Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "To every bird, its own nest is beautiful.",
    textTr: "Her kuşa kendi yuvası güzel görünür.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203016, author: "İtalyan Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "To catch two pigeons with one fava bean.",
    textTr: "Tek bir bakla ile iki güvercin yakalamak.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203017, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning"],
    text: "The cat goes to the lard so often that she leaves her paw print.",
    textTr: "Kedi domuz yağına o kadar sık gider ki sonunda pati izini bırakır.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203018, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "Water that has passed no longer turns the mill.",
    textTr: "Akıp giden su artık değirmeni döndürmez.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203019, author: "İtalyan Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "A good beginning makes a good end.",
    textTr: "İyi bir başlangıç, iyi bir son getirir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203020, author: "İtalyan Atasözü", category: "identity", tags: ["wisdom"],
    text: "Tell me who you go with, and I will tell you who you are.",
    textTr: "Söyle bana kiminle gezersin, söyleyeyim sana kim olduğunu.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203021, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A dog that barks does not bite.",
    textTr: "Havlayan köpek ısırmaz.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203022, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "In the land of the blind, blessed is he who has one eye.",
    textTr: "Körler ülkesinde tek gözlü olan kutsanmıştır.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203023, author: "İtalyan Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "Whoever finds a friend, finds a treasure.",
    textTr: "Bir dost bulan, bir hazine bulmuştur.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203024, author: "İtalyan Atasözü", category: "legacy", tags: ["legacy"],
    text: "A friend is worth more than a hundred relatives.",
    textTr: "Bir dost, yüz akrabadan daha değerlidir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203025, author: "İtalyan Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "There is no better mirror than an old friend.",
    textTr: "Eski bir dosttan daha iyi bir ayna yoktur.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203026, author: "İtalyan Atasözü", category: "discipline", tags: ["peace","discipline"],
    text: "He who minds his own business lives a hundred years.",
    textTr: "Kendi işine bakan yüz yıl yaşar.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203027, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "The night brings advice.",
    textTr: "Gece akıl verir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203028, author: "İtalyan Atasözü", category: "resilience", tags: ["motivation","focus"],
    text: "Everything left behind is lost.",
    textTr: "Bırakılan her şey kaybedilir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203029, author: "İtalyan Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "He who has time should not wait for time.",
    textTr: "Vakti olan, vakti beklemesin.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203030, author: "İtalyan Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "He who does not risk, does not gnaw.",
    textTr: "Riske girmeyen, kemiremez.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203031, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Good wine makes good blood.",
    textTr: "İyi şarap iyi kan yapar.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203032, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning"],
    text: "Lies have short legs.",
    textTr: "Yalanın ayakları kısadır.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203033, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Trusting is good, but not trusting is better.",
    textTr: "Güvenmek iyidir ama güvenmemek daha iyidir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203034, author: "İtalyan Atasözü", category: "suffering", tags: ["peace","resilience"],
    text: "Shared trouble, half joy.",
    textTr: "Paylaşılan dert, yarı sevinçtir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203035, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who does it, should expect it.",
    textTr: "Yapan, karşılığını bekleyebilir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203036, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Opportunity makes a man a thief.",
    textTr: "Fırsat, insanı hırsız yapar.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203037, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who is the cause of his own harm should weep for himself.",
    textTr: "Kendi belasına sebep olan, kendine ağlasın.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203038, author: "İtalyan Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "Not all misfortunes come to harm us.",
    textTr: "Her kötülük zarar vermek için gelmez.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203039, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "It is no use crying over spilt milk.",
    textTr: "Dökülen süte ağlamanın faydası yoktur.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203040, author: "İtalyan Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "Better one day as a lion than a hundred as a sheep.",
    textTr: "Yüz gün koyun olarak yaşamaktansa bir gün aslan olmak yeğdir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203041, author: "İtalyan Atasözü", category: "resilience", tags: ["motivation","discipline"],
    text: "For extreme ills, extreme remedies.",
    textTr: "Aşırı dertlere aşırı çareler gerekir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203042, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The neighbor's grass is always greener.",
    textTr: "Komşunun çimi hep daha yeşildir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203043, author: "İtalyan Atasözü", category: "wisdom", tags: ["discipline","wisdom"],
    text: "He who has no head should have good legs.",
    textTr: "Kafası olmayanın bacakları sağlam olmalı.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203044, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "You wanted the bicycle? Now pedal!",
    textTr: "Bisikleti sen istedin, şimdi pedal çevir!",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203045, author: "İtalyan Atasözü", category: "identity", tags: ["wisdom"],
    text: "In the small barrel, there is good wine.",
    textTr: "Küçük fıçıda iyi şarap olur.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203046, author: "İtalyan Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "A true friend is seen in a time of need.",
    textTr: "Gerçek dost, ihtiyaç anında belli olur.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203047, author: "İtalyan Atasözü", category: "suffering", tags: ["reckoning","discipline"],
    text: "Bacchus, tobacco, and Venus reduce a man to ashes.",
    textTr: "Şarap, tütün ve aşk, insanı küle çevirir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203048, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The ambassador bears no blame.",
    textTr: "Elçiye zeval olmaz.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203049, author: "İtalyan Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "The wolf loses its fur but not its vice.",
    textTr: "Kurt kılını değiştirir ama huyunu değiştirmez.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203050, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "To make an elephant out of a fly.",
    textTr: "Sinekten fil yapmak.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203051, author: "İtalyan Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Dirty laundry is washed within the family.",
    textTr: "Kirli çamaşırlar ailenin içinde yıkanır.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203052, author: "İtalyan Atasözü", category: "regret", tags: ["reckoning"],
    text: "He who sows the wind, reaps the storm.",
    textTr: "Rüzgar eken fırtına biçer.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203053, author: "İtalyan Atasözü", category: "legacy", tags: ["legacy","resilience"],
    text: "Union makes strength.",
    textTr: "Birlik, gücü doğurur.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203054, author: "İtalyan Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Between saying and doing lies the sea.",
    textTr: "Söylemek ile yapmak arasında bir deniz vardır.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203055, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Red sky at evening, fine weather is hoped for.",
    textTr: "Akşam kızıllığı, güzel havanın habercisidir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203056, author: "İtalyan Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "He who does it himself does the work of three.",
    textTr: "İşini kendi yapan, üç kişilik iş yapmış olur.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203057, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "He who does nothing, makes no mistakes.",
    textTr: "Hiçbir şey yapmayan, hata da yapmaz.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203058, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "A man forewarned is half saved.",
    textTr: "Önceden uyarılan, yarı yarıya kurtulmuştur.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203059, author: "İtalyan Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Rome was not built in a day.",
    textTr: "Roma bir günde inşa edilmedi.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203060, author: "İtalyan Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "One nail drives out another.",
    textTr: "Bir çivi diğerini söker.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203061, author: "İtalyan Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "One learns by making mistakes.",
    textTr: "İnsan hata yaparak öğrenir.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203062, author: "İtalyan Atasözü", category: "discipline", tags: ["motivation","discipline"],
    text: "Appetite comes with eating.",
    textTr: "İştah yerken açılır.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203063, author: "İtalyan Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "While there is life, there is hope.",
    textTr: "Hayat varken umut da vardır.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203064, author: "İtalyan Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "The early bird catches the worm.",
    textTr: "Erken kalkan kuş kurdu yakalar.",
    origin: "İtalya", originEmoji: "🇮🇹", era: "medieval", packId: "se-european-proverbs" },
  { id: 203065, author: "Rus Atasözü", category: "suffering", tags: ["resilience"],
    text: "Trouble never comes alone.",
    textTr: "Dert asla yalnız gelmez.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203066, author: "Rus Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Without effort, you cannot pull even a fish out of the pond.",
    textTr: "Emek vermeden gölden bir balık bile çıkaramazsın.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203067, author: "Rus Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Live for a century, learn for a century.",
    textTr: "Bir asır yaşa, bir asır öğren.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203068, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "Even under a sheep's hide, a wolf stays a wolf.",
    textTr: "Kuzu postuna bürünse de kurt yine kurttur.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203069, author: "Rus Atasözü", category: "resilience", tags: ["resilience"],
    text: "It will snap where it is thinnest.",
    textTr: "İp en ince olduğu yerden kopar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203070, author: "Rus Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "The eyes are afraid, but the hands still do the work.",
    textTr: "Gözler korkar ama eller yine de işi yapar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203071, author: "Rus Atasözü", category: "regret", tags: ["reckoning"],
    text: "Give him an inch and he will take a mile.",
    textTr: "Ona bir parmak ver, kolunu alır.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203072, author: "Rus Atasözü", category: "discipline", tags: ["discipline"],
    text: "Work fears a skilled hand.",
    textTr: "İş, usta bir eli görünce korkar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203073, author: "Rus Atasözü", category: "regret", tags: ["wisdom"],
    text: "If only youth knew, if only old age could.",
    textTr: "Gençlik bilebilse, yaşlılık yapabilse.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203074, author: "Rus Atasözü", category: "suffering", tags: ["resilience"],
    text: "Living a life is not like crossing a field.",
    textTr: "Bir ömrü yaşamak, bir tarlayı geçmek gibi değildir.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203075, author: "Rus Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "What you go looking for, you will find.",
    textTr: "Ne ararsan onu bulursun.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203076, author: "Rus Atasözü", category: "fire", tags: ["discipline"],
    text: "They knock out one wedge with another.",
    textTr: "Kamayı kamayla çıkarırlar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203077, author: "Rus Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Do not swap horses in the middle of the river.",
    textTr: "Nehrin ortasında at değiştirilmez.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203078, author: "Rus Atasözü", category: "wisdom", tags: ["peace"],
    text: "Do not beat a man who has already fallen.",
    textTr: "Düşmüş birine bir daha vurulmaz.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203079, author: "Rus Atasözü", category: "suffering", tags: ["resilience"],
    text: "When wood is chopped, the chips will fly.",
    textTr: "Odun yontulunca talaş sıçrar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203080, author: "Rus Atasözü", category: "regret", tags: ["reckoning"],
    text: "A single spoonful of tar spoils a barrel of honey.",
    textTr: "Bir kaşık katran, bir fıçı balı bozar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203081, author: "Rus Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "It is better to see once than to hear a hundred times.",
    textTr: "Yüz kere duymaktansa bir kere görmek daha iyidir.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203082, author: "Rus Atasözü", category: "resilience", tags: ["resilience"],
    text: "Do not look for trouble; trouble will find you on its own.",
    textTr: "Belayı arama, bela seni kendi bulur.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203083, author: "Rus Atasözü", category: "wisdom", tags: ["peace"],
    text: "There is no bad without some good hidden in it.",
    textTr: "Her kötülüğün içinde bir iyilik gizlidir.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203084, author: "Rus Atasözü", category: "regret", tags: ["wisdom"],
    text: "He who was scalded by hot milk blows even on cold water.",
    textTr: "Sıcak sütle dilini yakan, soğuk suyu bile üfleyerek içer.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203085, author: "Rus Atasözü", category: "fire", tags: ["wisdom"],
    text: "The game is not worth the candle.",
    textTr: "Oyun, yakılan muma değmez.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203086, author: "Rus Atasözü", category: "suffering", tags: ["resilience"],
    text: "I ran from the wolf and ran straight into a bear.",
    textTr: "Kurttan kaçarken ayıya rastladım.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203087, author: "Rus Atasözü", category: "regret", tags: ["peace"],
    text: "They do not swing their fists once the fight is over.",
    textTr: "Kavga bittikten sonra yumruk sallanmaz.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203088, author: "Rus Atasözü", category: "identity", tags: ["discipline"],
    text: "Habit is a second nature.",
    textTr: "Alışkanlık, insanın ikinci doğasıdır.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203089, author: "Rus Atasözü", category: "discipline", tags: ["discipline"],
    text: "Work is not a wolf; it will not run off into the forest.",
    textTr: "İş kurt değildir, ormana kaçmaz.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203090, author: "Rus Atasözü", category: "legacy", tags: ["wisdom"],
    text: "One hand washes the other.",
    textTr: "Bir el diğerini yıkar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203091, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "If you live among wolves, you must howl like a wolf.",
    textTr: "Kurtlarla yaşayan, kurt gibi ulur.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203092, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "One's own shirt is closer to the body.",
    textTr: "İnsanın kendi gömleği tenine daha yakındır.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203093, author: "Rus Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A holy place is never left empty.",
    textTr: "Kutsal bir yer asla boş kalmaz.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203094, author: "Rus Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Measure seven times, cut once.",
    textTr: "Yedi kere ölç, bir kere kes.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203095, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "However much you feed a wolf, it still looks to the forest.",
    textTr: "Kurdu ne kadar beslesen de gözü hep ormandadır.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203096, author: "Rus Atasözü", category: "regret", tags: ["reckoning"],
    text: "A word is not a sparrow: once it flies out, you will never catch it.",
    textTr: "Söz serçe değildir, ağızdan çıkınca bir daha yakalanmaz.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203097, author: "Rus Atasözü", category: "discipline", tags: ["wisdom","peace"],
    text: "Words are silver, but silence is golden.",
    textTr: "Söz gümüşse, sükût altındır.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203098, author: "Rus Atasözü", category: "legacy", tags: ["legacy"],
    text: "An old friend is better than two new ones.",
    textTr: "Eski bir dost, iki yeni dosttan iyidir.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203099, author: "Rus Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Patience and toil will grind down anything.",
    textTr: "Sabır ve emek, her şeyi öğütür.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203100, author: "Rus Atasözü", category: "regret", tags: ["reckoning"],
    text: "The small thief is hanged, but the great one is honored.",
    textTr: "Küçük hırsız asılır, büyüğü baş tacı edilir.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203101, author: "Rus Atasözü", category: "legacy", tags: ["legacy"],
    text: "With a helping hand, a thousand things become possible.",
    textTr: "Yardımlaşınca bin iş bile mümkün olur.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203102, author: "Rus Atasözü", category: "regret", tags: ["wisdom"],
    text: "So close, and yet you still cannot bite it.",
    textTr: "O kadar yakın ki, yine de ısıramazsın.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203103, author: "Rus Atasözü", category: "suffering", tags: ["wisdom"],
    text: "God gives, and God takes away.",
    textTr: "Tanrı verir, Tanrı alır.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203104, author: "Rus Atasözü", category: "regret", tags: ["reckoning"],
    text: "The mills of God grind slowly, but they grind exceedingly fine.",
    textTr: "Tanrının değirmenleri yavaş öğütür ama mutlaka öğütür.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203105, author: "Rus Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "God does not give horns to a cow that gores.",
    textTr: "Tanrı, tos vuran ineğe boynuz vermez.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203106, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "A beard does not make a philosopher.",
    textTr: "Sakal, bir insanı filozof yapmaz.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203107, author: "Rus Atasözü", category: "resilience", tags: ["resilience"],
    text: "Cursing does not stick to the collar.",
    textTr: "Küfür, yakaya yapışmaz.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203108, author: "Rus Atasözü", category: "legacy", tags: ["motivation","legacy"],
    text: "A great ship needs deep waters.",
    textTr: "Büyük gemi, derin sular ister.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203109, author: "Rus Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "God loves the third try.",
    textTr: "Tanrı üçüncüyü sever.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203110, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "Still waters run deep.",
    textTr: "Durgun sular derinden akar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203111, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "Do not enter a strange monastery with your own rule.",
    textTr: "Yabancı bir manastıra kendi kuralınla girme.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203112, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "Every family has its own black sheep.",
    textTr: "Her ailenin bir kara koyunu vardır.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203113, author: "Rus Atasözü", category: "identity", tags: ["wisdom"],
    text: "All cats are grey in the dark.",
    textTr: "Karanlıkta bütün kediler gridir.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203114, author: "Rus Atasözü", category: "regret", tags: ["wisdom"],
    text: "What was promised is awaited even three years.",
    textTr: "Söz verilen şey üç yıl bile beklenir.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203115, author: "Rus Atasözü", category: "regret", tags: ["discipline","motivation"],
    text: "The first pancake always comes out lumpy.",
    textTr: "İlk gözleme daima şekilsiz çıkar.",
    origin: "Rusya", originEmoji: "🇷🇺", era: "medieval", packId: "se-european-proverbs" },
  { id: 203116, author: "Polonya Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Without work, there is no cake.",
    textTr: "Emek olmadan çörek olmaz.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203117, author: "Polonya Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "He who rises early is rewarded by God.",
    textTr: "Erken kalkanı Tanrı ödüllendirir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203118, author: "Polonya Atasözü", category: "regret", tags: ["wisdom"],
    text: "Do not divide the bear's skin while the bear is still alive.",
    textTr: "Ayı daha hayattayken postunu paylaşma.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203119, author: "Polonya Atasözü", category: "identity", tags: ["wisdom"],
    text: "A honeyed tongue can hide a heart of gall.",
    textTr: "Bal gibi bir dil, zehirli bir kalbi gizleyebilir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203120, author: "Polonya Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Trust in God, but keep working with your own hands.",
    textTr: "Tanrıya güven, ama elini de taşın altına koy.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203121, author: "Polonya Atasözü", category: "identity", tags: ["wisdom"],
    text: "If a beard made a philosopher, the goat could preach.",
    textTr: "Sakal filozof yapsaydı, teke vaaz verirdi.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203122, author: "Polonya Atasözü", category: "regret", tags: ["reckoning"],
    text: "What has happened will not come back.",
    textTr: "Olan bir daha geri gelmez.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203123, author: "Polonya Atasözü", category: "legacy", tags: ["legacy"],
    text: "The apple never falls far from the tree.",
    textTr: "Elma, ağacından uzağa düşmez.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203124, author: "Polonya Atasözü", category: "identity", tags: ["wisdom"],
    text: "It takes two to tango.",
    textTr: "Tango için iki kişi gerekir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203125, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Children, fools, and drunkards always tell the truth.",
    textTr: "Çocuklar, deliler ve sarhoşlar hep doğruyu söyler.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203126, author: "Polonya Atasözü", category: "discipline", tags: ["discipline"],
    text: "Haste is the devil's delight.",
    textTr: "Acele, şeytanın hoşuna gider.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203127, author: "Polonya Atasözü", category: "regret", tags: ["wisdom"],
    text: "Even Homer nods off sometimes.",
    textTr: "Homeros bile bazen uyuklar.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203128, author: "Polonya Atasözü", category: "regret", tags: ["wisdom"],
    text: "A liar needs a good memory.",
    textTr: "Yalancının belleği güçlü olmalıdır.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203129, author: "Polonya Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "He who can wait, gets what he wants.",
    textTr: "Sabredebilen, istediğini elde eder.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203130, author: "Polonya Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "Chase two hares and you will catch neither.",
    textTr: "İki tavşanı kovalayan, hiçbirini yakalayamaz.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203131, author: "Polonya Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "He who does not move forward, moves backward.",
    textTr: "İleri gitmeyen geriler.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203132, author: "Polonya Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Constant dripping wears away the stone.",
    textTr: "Sürekli damlayan su taşı deler.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203133, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The cure is sometimes worse than the disease.",
    textTr: "Bazen ilaç, hastalıktan beter olur.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203134, author: "Polonya Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Better to die standing than to live on your knees.",
    textTr: "Diz çökerek yaşamaktansa ayakta ölmek yeğdir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203135, author: "Polonya Atasözü", category: "discipline", tags: ["motivation","discipline"],
    text: "One today is worth two tomorrows.",
    textTr: "Bugünün biri, yarının ikisine bedeldir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203136, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The better is the enemy of the good.",
    textTr: "İyinin düşmanı, daha iyisidir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203137, author: "Polonya Atasözü", category: "legacy", tags: ["wisdom","legacy"],
    text: "Speech is just wind, but writing endures.",
    textTr: "Söz rüzgardır, yazı kalır.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203138, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Do not praise the day before sunset.",
    textTr: "Günü, batmadan önce övme.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203139, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "There is no rule without an exception.",
    textTr: "İstisnasız kural olmaz.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203140, author: "Polonya Atasözü", category: "identity", tags: ["wisdom"],
    text: "Not everything that glitters is gold.",
    textTr: "Parlayan her şey altın değildir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203141, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "There is nothing new under the sun.",
    textTr: "Güneşin altında yeni bir şey yoktur.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203142, author: "Polonya Atasözü", category: "regret", tags: ["motivation","reckoning"],
    text: "Opportunity knocks but once.",
    textTr: "Fırsat, kapıyı yalnızca bir kez çalar.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203143, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Wealth rarely brings happiness.",
    textTr: "Zenginlik, nadiren mutluluk getirir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203144, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "In wine there is truth.",
    textTr: "Şarapta gerçek vardır.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203145, author: "Polonya Atasözü", category: "regret", tags: ["reckoning"],
    text: "Pride comes before the fall.",
    textTr: "Kibir, düşüşten önce gelir.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203146, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "The heart sees farther than the head.",
    textTr: "Kalp, akıldan daha uzağı görür.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203147, author: "Polonya Atasözü", category: "identity", tags: ["wisdom"],
    text: "The shoemaker always goes barefoot.",
    textTr: "Kunduracı hep yalınayak gezer.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203148, author: "Polonya Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "He who laughs last, laughs longest.",
    textTr: "Son gülen, en uzun güler.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203149, author: "Polonya Atasözü", category: "suffering", tags: ["resilience"],
    text: "A drowning man clutches at a straw.",
    textTr: "Boğulan adam, bir samana bile sarılır.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203150, author: "Polonya Atasözü", category: "identity", tags: ["wisdom"],
    text: "What is bred in the bone will not go out of the flesh.",
    textTr: "Kemikte olan, etten çıkmaz.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203151, author: "Polonya Atasözü", category: "suffering", tags: ["reckoning"],
    text: "Wine has drowned more men than the sea.",
    textTr: "Şarap, denizden daha çok insanı boğmuştur.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203152, author: "Polonya Atasözü", category: "fire", tags: ["resilience"],
    text: "Out of the frying pan and into the fire.",
    textTr: "Yağmurdan kaçarken doluya tutulmak.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203153, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "From nothing, nothing will come.",
    textTr: "Hiçlikten hiçlik doğar.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203154, author: "Polonya Atasözü", category: "regret", tags: ["reckoning"],
    text: "A bad workman always blames his tools.",
    textTr: "Kötü usta, aletlerini suçlar.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203155, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "No one can be the judge in his own case.",
    textTr: "Hiç kimse kendi davasında yargıç olamaz.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203156, author: "Polonya Atasözü", category: "legacy", tags: ["wisdom","legacy"],
    text: "Yesterday is the master of today.",
    textTr: "Dün, bugünün ustasıdır.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203157, author: "Polonya Atasözü", category: "identity", tags: ["wisdom"],
    text: "You can tell a fool by his laughter.",
    textTr: "Bir aptalı gülüşünden tanırsın.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203158, author: "Polonya Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Where fear rules, there is slavery.",
    textTr: "Korkunun hüküm sürdüğü yerde kölelik vardır.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203159, author: "Polonya Atasözü", category: "suffering", tags: ["wisdom"],
    text: "Even a four-legged horse stumbles.",
    textTr: "Dört ayaklı at bile tökezler.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203160, author: "Polonya Atasözü", category: "regret", tags: ["wisdom"],
    text: "The old ox forgets he was once a calf.",
    textTr: "Yaşlı öküz, bir zamanlar buzağı olduğunu unutur.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203161, author: "Polonya Atasözü", category: "identity", tags: ["resilience"],
    text: "A sunbeam loses nothing of its brightness for shining on a dung heap.",
    textTr: "Güneş ışığı, gübre yığınına vursa da parlaklığından bir şey kaybetmez.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203162, author: "Polonya Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Roasted pigeons do not fly straight into your mouth.",
    textTr: "Kızarmış güvercinler ağzına kendiliğinden uçup gelmez.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203163, author: "Polonya Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Kiss the hand you cannot bite.",
    textTr: "Isıramayacağın eli öp.",
    origin: "Polonya", originEmoji: "🇵🇱", era: "medieval", packId: "se-european-proverbs" },
  { id: 203164, author: "Ukrayna Atasözü", category: "suffering", tags: ["resilience"],
    text: "While the fat man grows thin, the thin man dies.",
    textTr: "Şişman zayıflayana kadar, zayıf ölür.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203165, author: "Ukrayna Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "It is good fishing in muddy water.",
    textTr: "Bulanık suda balık tutmak kolaydır.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203166, author: "Ukrayna Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Under a lying stone, water does not flow.",
    textTr: "Yerinde duran taşın altından su akmaz.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203167, author: "Ukrayna Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A bird in the hand is better than two promises.",
    textTr: "Eldeki kuş, iki vaatten iyidir.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203168, author: "Ukrayna Atasözü", category: "identity", tags: ["wisdom"],
    text: "Alike as two drops of water.",
    textTr: "İki su damlası gibi birbirinin aynı.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203169, author: "Ukrayna Atasözü", category: "identity", tags: ["wisdom"],
    text: "Two shoes make a pair.",
    textTr: "İki ayakkabı bir çift eder.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203170, author: "Ukrayna Atasözü", category: "regret", tags: ["wisdom"],
    text: "It is good everywhere we are not.",
    textTr: "İyi olan her yer, bizim olmadığımız yerdir.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203171, author: "Ukrayna Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "A drop in the sea.",
    textTr: "Denizde bir damla.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203172, author: "Ukrayna Atasözü", category: "fire", tags: ["resilience"],
    text: "Truth does not drown in water, nor burn in fire.",
    textTr: "Gerçek, ne suda boğulur ne ateşte yanar.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203173, author: "Ukrayna Atasözü", category: "wisdom", tags: ["motivation","wisdom"],
    text: "A person is made for happiness, as a bird is made for flight.",
    textTr: "İnsan mutluluk için yaratılmıştır, tıpkı kuşun uçmak için yaratıldığı gibi.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203174, author: "Ukrayna Atasözü", category: "discipline", tags: ["discipline"],
    text: "Where there are too many mistresses of the house, the floor stays unswept.",
    textTr: "Ev sahibesi çok olunca, taban süpürülmeden kalır.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203175, author: "Ukrayna Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "A warm word can even melt ice.",
    textTr: "Sıcak bir söz, buzu bile eritir.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203176, author: "Ukrayna Atasözü", category: "suffering", tags: ["resilience"],
    text: "To live a life is not to cross an open field.",
    textTr: "Bir ömür yaşamak, bir tarlayı geçmek değildir.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203177, author: "Ukrayna Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Water wears away the stone.",
    textTr: "Su, taşı aşındırır.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203178, author: "Ukrayna Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Everything has its own time.",
    textTr: "Her şeyin bir zamanı vardır.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203179, author: "Ukrayna Atasözü", category: "regret", tags: ["reckoning"],
    text: "Show him where the crayfish spend the winter.",
    textTr: "Ona ıstakozların kışı nerede geçirdiğini göster.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203180, author: "Ukrayna Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Speak of the wolf, and he appears at the door.",
    textTr: "Kurdu anarsan, kapıda belirir.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203181, author: "Ukrayna Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Mute as a fish.",
    textTr: "Balık gibi suskun.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203182, author: "Ukrayna Atasözü", category: "wisdom", tags: ["motivation","wisdom"],
    text: "The tongue will lead you all the way to Kyiv.",
    textTr: "Dil, seni Kiev'e kadar götürür.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203183, author: "Ukrayna Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "Either a lord, or a ruined man.",
    textTr: "Ya bey ol, ya da her şeyini kaybet.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203184, author: "Ukrayna Atasözü", category: "discipline", tags: ["discipline"],
    text: "God protects the one who protects himself.",
    textTr: "Kendini koruyanı Tanrı da korur.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203185, author: "Ukrayna Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "He who fears wolves should never enter the forest.",
    textTr: "Kurttan korkan, ormana girmemeli.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203186, author: "Ukrayna Atasözü", category: "fire", tags: ["reckoning"],
    text: "Pouring oil on the fire.",
    textTr: "Ateşe yağ dökmek.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203187, author: "Ukrayna Atasözü", category: "resilience", tags: ["resilience"],
    text: "Where it is thin, that is where it tears.",
    textTr: "İnce olan yerden kopar.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203188, author: "Ukrayna Atasözü", category: "legacy", tags: ["peace","legacy"],
    text: "At home, even the walls help you.",
    textTr: "Evde duvarlar bile sana yardım eder.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203189, author: "Ukrayna Atasözü", category: "legacy", tags: ["discipline","legacy"],
    text: "Guard it like the pupil of your eye.",
    textTr: "Onu, gözünün bebeği gibi koru.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203190, author: "Ukrayna Atasözü", category: "discipline", tags: ["discipline","legacy"],
    text: "A penny saved builds toward a fortune.",
    textTr: "Biriken kuruş, gün gelir servete dönüşür.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203191, author: "Ukrayna Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "Do not buy a cat hidden in a sack.",
    textTr: "Çuvaldaki kediyi görmeden alma.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203192, author: "Ukrayna Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "No matter how hard you try, the bull will never give you milk.",
    textTr: "Ne kadar uğraşırsan uğraş, boğa sana asla süt vermez.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203193, author: "Ukrayna Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Your head is not only for wearing a hat.",
    textTr: "Kafan sadece şapka takmak için değildir.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203194, author: "Ukrayna Atasözü", category: "suffering", tags: ["resilience"],
    text: "A squeezed lemon has nothing left to give.",
    textTr: "Sıkılmış limonun verecek bir şeyi kalmaz.",
    origin: "Ukrayna", originEmoji: "🇺🇦", era: "medieval", packId: "se-european-proverbs" },
  { id: 203195, author: "Sırp Atasözü", category: "identity", tags: ["wisdom"],
    text: "A crow does not peck out another crow's eyes.",
    textTr: "Karga, kargasının gözünü oymaz.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203196, author: "Sırp Atasözü", category: "identity", tags: ["wisdom"],
    text: "God made his own beard first.",
    textTr: "Tanrı önce kendi sakalını yaratmış.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203197, author: "Sırp Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "Where there are too many midwives, the child is born crippled.",
    textTr: "Ebe çok olunca çocuk sakat doğar.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203198, author: "Sırp Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "The morning is wiser than the evening.",
    textTr: "Sabah, akşamdan daha akıllıdır.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203199, author: "Sırp Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "The early riser seizes fortune twice over.",
    textTr: "Erken kalkan, talihi iki kez yakalar.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203200, author: "Sırp Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "First bake it, then say it.",
    textTr: "Önce pişir, sonra söyle.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203201, author: "Sırp Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Leap first, and only then announce that you have jumped.",
    textTr: "Önce atla, ancak ondan sonra atladığını söyle.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203202, author: "Sırp Atasözü", category: "identity", tags: ["wisdom"],
    text: "The pot calls the kettle black.",
    textTr: "Tencere dibin kara, seninki benden kara.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203203, author: "Sırp Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Measure three times, cut once.",
    textTr: "Üç kere ölç, bir kere kes.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203204, author: "Sırp Atasözü", category: "identity", tags: ["resilience","wisdom"],
    text: "Trust in yourself and in your own horse.",
    textTr: "Kendine ve kendi atına güven.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203205, author: "Sırp Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "What you can do today, do not leave for tomorrow.",
    textTr: "Bugün yapabileceğini yarına bırakma.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203206, author: "Sırp Atasözü", category: "discipline", tags: ["discipline"],
    text: "Deeds speak, not words.",
    textTr: "Sözler değil, işler konuşur.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203207, author: "Sırp Atasözü", category: "wisdom", tags: ["focus","wisdom"],
    text: "You cannot see the forest for the trees.",
    textTr: "Ağaçlardan ormanı görememek.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203208, author: "Sırp Atasözü", category: "regret", tags: ["reckoning"],
    text: "Everything comes back around, and everything is paid for.",
    textTr: "Her şey döner dolaşır, ve her şeyin bir bedeli vardır.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203209, author: "Sırp Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Something is better than nothing.",
    textTr: "Hiç yoktan iyidir.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203210, author: "Sırp Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Quiet water undermines the mountain.",
    textTr: "Sessiz su, dağı bile oyar.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203211, author: "Sırp Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "The wiser one gives way.",
    textTr: "Akıllı olan, geri adım atar.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203212, author: "Sırp Atasözü", category: "suffering", tags: ["discipline","resilience"],
    text: "Without struggle there is no learning.",
    textTr: "Zahmet olmadan bilgi olmaz.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203213, author: "Sırp Atasözü", category: "identity", tags: ["wisdom"],
    text: "What the wise man is ashamed of, the fool boasts about.",
    textTr: "Akıllının utandığı şeyle, deli övünür.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203214, author: "Sırp Atasözü", category: "regret", tags: ["discipline"],
    text: "He who lacks it in his head carries it in his legs.",
    textTr: "Kafasında olmayanı, bacaklarında taşır.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203215, author: "Sırp Atasözü", category: "regret", tags: ["reckoning"],
    text: "A lie has short legs.",
    textTr: "Yalanın ayakları kısadır.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203216, author: "Sırp Atasözü", category: "suffering", tags: ["wisdom"],
    text: "The well-fed does not understand the hungry.",
    textTr: "Tok, açın halinden anlamaz.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203217, author: "Sırp Atasözü", category: "identity", tags: ["reckoning","wisdom"],
    text: "Give a man power, and you will see who he truly is.",
    textTr: "Bir adama güç ver, gerçekte kim olduğunu göreceksin.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203218, author: "Sırp Atasözü", category: "discipline", tags: ["discipline"],
    text: "There is no bread without the hoe.",
    textTr: "Çapa olmadan ekmek olmaz.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203219, author: "Sırp Atasözü", category: "identity", tags: ["wisdom"],
    text: "You become like the company you keep.",
    textTr: "Kiminle gezersen, onun gibi olursun.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203220, author: "Sırp Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Do not grow proud in fortune, nor bowed in hardship.",
    textTr: "Talihte böbürlenme, zorlukta eğilme.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203221, author: "Sırp Atasözü", category: "identity", tags: ["wisdom"],
    text: "Fine clothes do not make the man.",
    textTr: "Güzel giysi, adamı yapmaz.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203222, author: "Sırp Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "One swallow does not make a spring.",
    textTr: "Bir kırlangıç bahar getirmez.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203223, author: "Sırp Atasözü", category: "identity", tags: ["wisdom"],
    text: "A wolf may shed its fur, but never its nature.",
    textTr: "Kurt tüyünü değiştirir ama huyunu asla.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203224, author: "Sırp Atasözü", category: "identity", tags: ["wisdom"],
    text: "A torn rag finds its matching patch.",
    textTr: "Yırtık bez, kendine uygun yamayı bulur.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203225, author: "Sırp Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "A kind word opens an iron door.",
    textTr: "Güzel bir söz, demir bir kapıyı bile açar.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203226, author: "Sırp Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "A clear account keeps a friendship long.",
    textTr: "Hesabın temiz olsun, dostluğun uzun sürsün.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203227, author: "Sırp Atasözü", category: "regret", tags: ["reckoning"],
    text: "A picky chooser ends up with the leftovers.",
    textTr: "Çok seçen, en kötüsüyle kalır.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203228, author: "Sırp Atasözü", category: "identity", tags: ["resilience","motivation"],
    text: "Dust rises in the wake of a good horse.",
    textTr: "İyi atın ardından toz kalkar.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203229, author: "Sırp Atasözü", category: "discipline", tags: ["discipline"],
    text: "A healthy spirit lives in a healthy body.",
    textTr: "Sağlam kafa, sağlam vücutta bulunur.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203230, author: "Sırp Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "Do not run out ahead of the wagon shaft.",
    textTr: "Arabanın oku önüne geçme.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203231, author: "Sırp Atasözü", category: "wisdom", tags: ["wisdom"],
    text: "You cannot have both the goat and the money.",
    textTr: "Hem keçiye hem paraya sahip olamazsın.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203232, author: "Sırp Atasözü", category: "wisdom", tags: ["motivation","wisdom"],
    text: "He who asks questions never loses his way.",
    textTr: "Soran, yolunu asla kaybetmez.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203233, author: "Sırp Atasözü", category: "regret", tags: ["reckoning"],
    text: "Stolen goods carry a curse.",
    textTr: "Çalıntı mal, lanetlidir.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203234, author: "Sırp Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "In hardship, true heroes are known.",
    textTr: "Zorlukta gerçek kahramanlar belli olur.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203235, author: "Sırp Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "A skilled hand is worth twice as much.",
    textTr: "Usta bir el, iki kat değer taşır.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203236, author: "Sırp Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Every guest is welcome for three days.",
    textTr: "Her misafir üç gün hoş karşılanır.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203237, author: "Sırp Atasözü", category: "legacy", tags: ["peace","legacy"],
    text: "Wherever you wander, come home in the end.",
    textTr: "Nereye gidersen git, sonunda evine dön.",
    origin: "Sırbistan", originEmoji: "🇷🇸", era: "medieval", packId: "se-european-proverbs" },
  { id: 203238, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Slowly, slowly, the unripe grape becomes honey.",
    textTr: "Yavaş yavaş, koruk üzüm bala dönüşür.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203239, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The tongue has no bones, yet it breaks bones.",
    textTr: "Dilin kemiği yoktur ama kemik kırar.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203240, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Even the walls have ears.",
    textTr: "Duvarların bile kulağı vardır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203241, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Better to tether the donkey than to go looking for it.",
    textTr: "Eşeği aramaktansa bağlamak daha iyidir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203242, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "Whoever rushes, stumbles.",
    textTr: "Acele eden ayağı takılır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203243, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The truth floats like oil on water.",
    textTr: "Gerçek, suyun üzerindeki yağ gibi yüzeye çıkar.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203244, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Half-knowledge is worse than ignorance.",
    textTr: "Yarım bilgi, cehaletten daha kötüdür.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203245, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Whoever tells the truth has God on his side.",
    textTr: "Doğruyu söyleyenin yanında Tanrı vardır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203246, author: "Yunan Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Every obstacle is for the good.",
    textTr: "Her engel bir hayra vesiledir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203247, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","legacy"],
    text: "Even grown old, the wolf never forgets his craft.",
    textTr: "Kurt yaşlansa da zanaatını unutmaz.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203248, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "What the fox cannot reach, she calls unripe.",
    textTr: "Tilki erişemediği üzüme koruk der.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203249, author: "Yunan Atasözü", category: "suffering", tags: ["resilience","wisdom"],
    text: "The one who suffers, learns.",
    textTr: "Acı çeken, öğrenir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203250, author: "Yunan Atasözü", category: "suffering", tags: ["resilience","peace"],
    text: "It is impossible to escape one's fate.",
    textTr: "Kaderden kaçmak mümkün değildir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203251, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "The beginning is half of the whole.",
    textTr: "Başlangıç, işin yarısıdır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203252, author: "Yunan Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Whoever digs a pit for another falls into it himself.",
    textTr: "Başkasına kuyu kazan, kendisi düşer.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203253, author: "Yunan Atasözü", category: "suffering", tags: ["resilience","reckoning"],
    text: "A cliff ahead, a torrent behind.",
    textTr: "Önünde uçurum, ardında sel.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203254, author: "Yunan Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "Do good and cast it into the sea.",
    textTr: "İyilik yap, denize at.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203255, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "First the soul departs, then the habit.",
    textTr: "Önce can çıkar, sonra huy.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203256, author: "Yunan Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Whatever you sow, that you will reap.",
    textTr: "Ne ekersen onu biçersin.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203257, author: "Yunan Atasözü", category: "regret", tags: ["peace","reckoning"],
    text: "What happened, happened.",
    textTr: "Olan oldu.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203258, author: "Yunan Atasözü", category: "identity", tags: ["legacy","wisdom"],
    text: "Blood does not turn to water.",
    textTr: "Kan su olmaz.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203259, author: "Yunan Atasözü", category: "identity", tags: ["legacy","peace"],
    text: "There is only one mother.",
    textTr: "Anne bir tanedir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203260, author: "Yunan Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "A true friend is known in times of need.",
    textTr: "Gerçek dost, ihtiyaç anında belli olur.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203261, author: "Yunan Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "Show me your friend, and I will tell you who you are.",
    textTr: "Bana dostunu göster, sana kim olduğunu söyleyeyim.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203262, author: "Yunan Atasözü", category: "suffering", tags: ["resilience","peace"],
    text: "Every house carries its own cross.",
    textTr: "Her evin kendi haçı vardır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203263, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Good things are acquired through toil.",
    textTr: "İyi şeyler emekle kazanılır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203264, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Bean by bean, the sack fills up.",
    textTr: "Tane tane, çuval dolar.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203265, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "The lazy man makes no progress.",
    textTr: "Tembel insan ilerleyemez.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203266, author: "Yunan Atasözü", category: "suffering", tags: ["resilience","discipline"],
    text: "Too much toil wears out the master.",
    textTr: "Aşırı çalışma efendisini yıpratır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203267, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Money does not bring happiness.",
    textTr: "Para mutluluk getirmez.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203268, author: "Yunan Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "Whoever chases many hares catches none.",
    textTr: "Çok tavşan kovalayan hiçbirini yakalayamaz.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203269, author: "Yunan Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Better rich in health than rich in money.",
    textTr: "Parası bol olandan, sağlığı bol olan yeğdir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203270, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Stinginess is half of poverty.",
    textTr: "Cimrilik, yoksulluğun yarısıdır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203271, author: "Yunan Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "Once for the thief, twice for the thief — the third time is his undoing.",
    textTr: "Hırsıza bir kez, iki kez; üçüncüsünde işi biter.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203272, author: "Yunan Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "Two watermelons cannot be held under one arm.",
    textTr: "İki karpuz bir koltuğa sığmaz.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203273, author: "Yunan Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "When the cat is away, the mice dance.",
    textTr: "Kedi yokken fareler dans eder.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203274, author: "Yunan Atasözü", category: "identity", tags: ["legacy","wisdom"],
    text: "Better to lose an eye than your good name.",
    textTr: "Adını kaybetmektense gözünü kaybetmek daha iyidir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203275, author: "Yunan Atasözü", category: "wisdom", tags: ["resilience","wisdom"],
    text: "Fear the calm river.",
    textTr: "Sakin nehirden kork.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203276, author: "Yunan Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "Next to the basil plant, even the flowerpot gets watered.",
    textTr: "Fesleğenin yanındaki saksı da sulanır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203277, author: "Yunan Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Jealousy is a sickness.",
    textTr: "Kıskançlık bir hastalıktır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203278, author: "Yunan Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Whoever becomes a sheep is eaten by the wolf.",
    textTr: "Koyun olan, kurt tarafından yenir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203279, author: "Yunan Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "Arrogance is the messenger of the fall.",
    textTr: "Kibir, düşüşün habercisidir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203280, author: "Yunan Atasözü", category: "fire", tags: ["wisdom","reckoning"],
    text: "Where there is smoke, there is fire.",
    textTr: "Duman olan yerde ateş de vardır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203281, author: "Yunan Atasözü", category: "discipline", tags: ["motivation","focus"],
    text: "A good day shows itself from the morning.",
    textTr: "İyi gün, sabahından bellidir.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203282, author: "Yunan Atasözü", category: "resilience", tags: ["motivation","resilience"],
    text: "Fortune favors the brave.",
    textTr: "Talih cesurdan yanadır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203283, author: "Yunan Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "Know thyself.",
    textTr: "Kendini bil.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203284, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Nothing in excess.",
    textTr: "Aşırıya kaçma.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203285, author: "Yunan Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Repetition is the mother of learning.",
    textTr: "Tekrar, öğrenmenin anasıdır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203286, author: "Yunan Atasözü", category: "identity", tags: ["wisdom","legacy"],
    text: "The office reveals the man.",
    textTr: "Görev, adamı ortaya çıkarır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203287, author: "Yunan Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "It matters not how many times you fall, but how many times you rise.",
    textTr: "Önemli olan kaç kez düştüğün değil, kaç kez ayağa kalktığındır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203288, author: "Yunan Atasözü", category: "resilience", tags: ["resilience","reckoning"],
    text: "A drowning man will grasp at his own hair.",
    textTr: "Boğulan adam kendi saçına sarılır.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203289, author: "Yunan Atasözü", category: "discipline", tags: ["motivation","discipline"],
    text: "With Athena's help, move your own hand too.",
    textTr: "Athena yardım etsin, sen de elini oynat.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203290, author: "Yunan Atasözü", category: "identity", tags: ["peace","wisdom"],
    text: "What belongs in the house should not go out to the square.",
    textTr: "Evin içindeki, meydana çıkmamalı.",
    origin: "Yunanistan", originEmoji: "🇬🇷", era: "ancient", packId: "se-european-proverbs" },
  { id: 203291, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The sun won't stay behind the cloud.",
    textTr: "Güneş bulutun ardında kalmaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203292, author: "Ermeni Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "The red cow won't change its hide.",
    textTr: "Kızıl inek derisini değiştirmez.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203293, author: "Ermeni Atasözü", category: "discipline", tags: ["discipline","peace"],
    text: "Let it be late, let it be good.",
    textTr: "Geç olsun da güç olmasın.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203294, author: "Ermeni Atasözü", category: "identity", tags: ["legacy","wisdom"],
    text: "However much fruit a tree bears, it bows its head all the more.",
    textTr: "Bir ağaç ne kadar çok meyve verirse, başını o kadar eğer.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203295, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Not everything round is an apple.",
    textTr: "Her yuvarlak şey elma değildir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203296, author: "Ermeni Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "If you speak too much, you will learn too little.",
    textTr: "Çok konuşursan, az öğrenirsin.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203297, author: "Ermeni Atasözü", category: "suffering", tags: ["reckoning","wisdom"],
    text: "The wound of a dagger heals, but that of the tongue never.",
    textTr: "Hançer yarası iyileşir ama dil yarası asla iyileşmez.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203298, author: "Ermeni Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "Far from the eye, far from the heart.",
    textTr: "Gözden ırak olan, gönülden de ırak olur.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203299, author: "Ermeni Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "The end of strife is repentance.",
    textTr: "Çekişmenin sonu pişmanlıktır.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203300, author: "Ermeni Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "One bad deed begets another.",
    textTr: "Bir kötülük başka bir kötülüğü doğurur.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203301, author: "Ermeni Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "A drowning man will clutch at straws.",
    textTr: "Boğulan adam samana bile sarılır.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203302, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "He who looks for a friend without fault will never find one.",
    textTr: "Kusursuz bir dost arayan, hiçbir zaman bulamaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203303, author: "Ermeni Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "To be willing is only half the job.",
    textTr: "İstemek, işin yalnızca yarısıdır.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203304, author: "Ermeni Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Dogs that fight each other will join forces against the wolf.",
    textTr: "Birbiriyle dövüşen köpekler, kurda karşı birleşir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203305, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "It is better to carry stones with a wise man than to accept a meal from a fool.",
    textTr: "Akıllı biriyle taş taşımak, akılsızın yemeğini yemekten iyidir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203306, author: "Ermeni Atasözü", category: "fire", tags: ["resilience","motivation"],
    text: "The rose of wintertime is fire.",
    textTr: "Kışın gülü ateştir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203307, author: "Ermeni Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "Water always finds its way.",
    textTr: "Su, yolunu mutlaka bulur.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203308, author: "Ermeni Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "When you go in, think first how you'll come out.",
    textTr: "İçeri girerken, nasıl çıkacağını önce düşün.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203309, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Quiet horses kick the hardest.",
    textTr: "Sessiz atlar en sert tekmeyi atar.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203310, author: "Ermeni Atasözü", category: "fire", tags: ["discipline","resilience"],
    text: "You cannot put out a fire with spit.",
    textTr: "Ateş, tükürükle söndürülmez.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203311, author: "Ermeni Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Begin with small things, that you may achieve great ones.",
    textTr: "Küçük şeylerle başla ki büyüğe ulaşasın.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203312, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Make friends with a dog, but keep a stick in your hand.",
    textTr: "Köpekle dost ol, ama elinde sopanı tut.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203313, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "When your fortune improves, the pillars of your house seem crooked.",
    textTr: "Talihin yükselince, evinin direkleri eğri görünür.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203314, author: "Ermeni Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "When God gives, He gives with both hands.",
    textTr: "Tanrı verince, iki eliyle verir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203315, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "One blossom does not make a spring.",
    textTr: "Bir çiçek bahar getirmez.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203316, author: "Ermeni Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "Where is there a tree not shaken by the wind?",
    textTr: "Rüzgârın sarsmadığı ağaç nerede var?",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203317, author: "Ermeni Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "The butterfly that lands on a branch fears it will break.",
    textTr: "Dala konan kelebek, dalın kırılmasından korkar.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203318, author: "Ermeni Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "You cannot strike the point of a needle with a fist.",
    textTr: "İğnenin ucuna yumrukla vurulmaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203319, author: "Ermeni Atasözü", category: "resilience", tags: ["resilience","peace"],
    text: "He who falls into the water need not fear the rain.",
    textTr: "Suya düşen, yağmurdan korkmaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203320, author: "Ermeni Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "The eagle was killed by an arrow fledged with his own feather.",
    textTr: "Kartalı vuran ok, kendi tüyünden yapılmıştı.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203321, author: "Ermeni Atasözü", category: "identity", tags: ["legacy","wisdom"],
    text: "One can spoil the good name of a thousand.",
    textTr: "Biri, binlercesinin adını lekeleyebilir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203322, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "The bee gathers honey from the same flower where the snake draws poison.",
    textTr: "Arı balı, yılan zehri aynı çiçekten alır.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203323, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Choose a friend with the eyes of an old man, a horse with the eyes of a young one.",
    textTr: "Dostunu yaşlı bir adamın gözüyle, atını genç bir adamın gözüyle seç.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203324, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "You never know a man until you've eaten a sack of salt with him.",
    textTr: "Bir adamı, onunla bir çuval tuz yemeden tanıyamazsın.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203325, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Always tell the truth in the form of a joke.",
    textTr: "Gerçeği her zaman bir şaka kılığında söyle.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203326, author: "Ermeni Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "The world is a staircase: some go up, others go down.",
    textTr: "Dünya bir merdivendir: kimi çıkar, kimi iner.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203327, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "A devil with experience is better than an angel without.",
    textTr: "Deneyimli bir şeytan, deneyimsiz bir melekten iyidir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203328, author: "Ermeni Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "When a tree falls, there is plenty of kindling wood.",
    textTr: "Bir ağaç devrilince, çevresinde çıra bol olur.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203329, author: "Ermeni Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "Even in a golden cage, the nightingale dreams of the forest.",
    textTr: "Altın kafeste bile bülbül, ormanı düşler.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203330, author: "Ermeni Atasözü", category: "suffering", tags: ["reckoning","peace"],
    text: "The wolf grieves for what he left behind; the shepherd, for what was taken.",
    textTr: "Kurt geride bıraktığına yanar, çoban ise alınana yanar.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203331, author: "Ermeni Atasözü", category: "suffering", tags: ["peace","reckoning"],
    text: "Tears have meaning, but only the one who sheds them understands it.",
    textTr: "Gözyaşının bir anlamı vardır ama onu ancak döken anlar.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203332, author: "Ermeni Atasözü", category: "suffering", tags: ["reckoning","wisdom"],
    text: "No one will give a poor man bread, but everyone gives him advice.",
    textTr: "Yoksula kimse ekmek vermez ama herkes akıl verir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203333, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","legacy"],
    text: "A calf is not found under an ox.",
    textTr: "Öküzün altında buzağı bulunmaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203334, author: "Ermeni Atasözü", category: "suffering", tags: ["resilience","peace"],
    text: "Until you know trouble, you will never know joy.",
    textTr: "Dert nedir bilmeyen, sevinç nedir de bilmez.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203335, author: "Ermeni Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "He who steals an egg will steal a horse also.",
    textTr: "Yumurta çalan, at da çalar.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203336, author: "Ermeni Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "However deep love is, hate still exists; however great hate is, love still remains.",
    textTr: "Sevgi ne kadar derin olsa da nefret vardır; nefret ne kadar büyük olsa da sevgi kalır.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203337, author: "Ermeni Atasözü", category: "resilience", tags: ["resilience","reckoning"],
    text: "The more you stone a dog, the more it barks.",
    textTr: "Köpeği ne kadar taşlarsan o kadar çok havlar.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203338, author: "Ermeni Atasözü", category: "discipline", tags: ["focus","discipline"],
    text: "If you chase two rabbits at once, you will catch neither.",
    textTr: "Aynı anda iki tavşanı kovalarsan, hiçbirini yakalayamazsın.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203339, author: "Ermeni Atasözü", category: "identity", tags: ["wisdom","legacy"],
    text: "Better to be an ant's head than a lion's tail.",
    textTr: "Aslanın kuyruğu olmaktansa karıncanın başı olmak iyidir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203340, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Birds are caught with seed, men with money.",
    textTr: "Kuşlar tohumla, insanlar parayla yakalanır.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203341, author: "Ermeni Atasözü", category: "suffering", tags: ["reckoning","peace"],
    text: "A pain in the foot is soon forgotten; a pain in the head is not.",
    textTr: "Ayaktaki acı çabuk unutulur, baştaki acı unutulmaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203342, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "He who has money has no sense; he who has sense has no money.",
    textTr: "Parası olanın aklı yoktur, aklı olanın parası yoktur.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203343, author: "Ermeni Atasözü", category: "discipline", tags: ["discipline","legacy"],
    text: "What a man acquires in his youth serves as his staff in old age.",
    textTr: "İnsanın gençlikte kazandığı, yaşlılıkta bastonu olur.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203344, author: "Ermeni Atasözü", category: "resilience", tags: ["peace","reckoning"],
    text: "No one is sure that his lamp will burn till morning.",
    textTr: "Hiç kimse, lambasının sabaha kadar yanacağından emin olamaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203345, author: "Ermeni Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "There is no strife that reasonable men cannot settle.",
    textTr: "Akıllı insanların çözemeyeceği bir çekişme yoktur.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203346, author: "Ermeni Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "One hand cannot clap alone.",
    textTr: "Tek el alkış tutmaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203347, author: "Ermeni Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "The world is a pot, and man is but a spoon in it.",
    textTr: "Dünya bir kazan, insan onda yalnızca bir kaşıktır.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203348, author: "Ermeni Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "A near neighbor is better than a distant kinsman.",
    textTr: "Yakın komşu, uzak akrabadan iyidir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203349, author: "Ermeni Atasözü", category: "regret", tags: ["reckoning","peace"],
    text: "No other day can equal the one that has passed.",
    textTr: "Geçen güne hiçbir gün eş olamaz.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203350, author: "Ermeni Atasözü", category: "identity", tags: ["legacy","discipline"],
    text: "Better to lose your eyes than your calling.",
    textTr: "Sanatını kaybetmektense gözlerini kaybetmek daha iyidir.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203351, author: "Ermeni Atasözü", category: "identity", tags: ["legacy","peace"],
    text: "The stones of my native land are warmer than the ovens of Babylon.",
    textTr: "Vatanımın taşları, Babil'in fırınlarından daha sıcaktır.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203352, author: "Ermeni Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "When a thief steals from a thief, God laughs in heaven.",
    textTr: "Hırsız hırsızdan çalınca, Tanrı gökte güler.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203353, author: "Ermeni Atasözü", category: "suffering", tags: ["reckoning","peace"],
    text: "When a rich man dies, the whole world stirs; when a poor man dies, no one notices.",
    textTr: "Zengin ölünce dünya çalkalanır, yoksul ölünce kimse fark etmez.",
    origin: "Ermenistan", originEmoji: "🇦🇲", era: "medieval", packId: "se-european-proverbs" },
  { id: 203354, author: "Gürcü Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "A new broom sweeps clean; an old one gathers dust.",
    textTr: "Yeni süpürge iyi süpürür, eskisi toz toplar.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203355, author: "Gürcü Atasözü", category: "suffering", tags: ["peace","reckoning"],
    text: "\"I have much to say,\" said the fish, \"but my mouth is full of water.\"",
    textTr: "Balık demiş ki: 'Söyleyecek çok şeyim var ama ağzım suyla dolu.'",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203356, author: "Gürcü Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "A church without a shepherd is prey to the devil.",
    textTr: "Çobansız kilise, şeytana av olur.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203357, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "A communal field is ruined by the bears.",
    textTr: "Ortak tarlayı ayılar mahveder.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203358, author: "Gürcü Atasözü", category: "identity", tags: ["legacy","wisdom"],
    text: "A golden plate means nothing to me when my own blood is spilled on it.",
    textTr: "Kanım üzerine dökülmüşse, altın tabağın bana bir anlamı yoktur.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203359, author: "Gürcü Atasözü", category: "identity", tags: ["peace","wisdom"],
    text: "A mother understands what her mute son says.",
    textTr: "Anne, dilsiz oğlunun ne dediğini anlar.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203360, author: "Gürcü Atasözü", category: "identity", tags: ["legacy","wisdom"],
    text: "Better your own copper than another man's gold.",
    textTr: "Başkasının altınındansa kendi bakırın yeğdir.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203361, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Beware the front of a bull, the back of a horse, and both sides of a fool.",
    textTr: "Boğanın önünden, atın arkasından ve akılsızın her iki yanından sakın.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203362, author: "Gürcü Atasözü", category: "suffering", tags: ["reckoning","peace"],
    text: "Blood is not washed away with blood.",
    textTr: "Kan, kanla temizlenmez.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203363, author: "Gürcü Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Catch the bird before you build the cage.",
    textTr: "Kafesi yapmadan önce kuşu yakala.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203364, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Do not blame the sun for the darkness of the night.",
    textTr: "Gecenin karanlığı için güneşi suçlama.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203365, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Give a blind man eyes and he will ask for eyebrows too.",
    textTr: "Köre göz ver, kaşını da ister.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203366, author: "Gürcü Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "He who is in a hurry always arrives late.",
    textTr: "Acele eden her zaman geç kalır.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203367, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "If you forgive the fox for stealing your hen, he will take your sheep next.",
    textTr: "Tavuğunu çalan tilkiyi bağışlarsan, bir dahaki sefere koyununu alır.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203368, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "In a place with no dogs, they teach the cats to bark.",
    textTr: "Köpek olmayan yerde kedilere havlamayı öğretirler.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203369, author: "Gürcü Atasözü", category: "resilience", tags: ["peace","reckoning"],
    text: "What the wind brings, the wind carries away.",
    textTr: "Rüzgârın getirdiğini, rüzgâr götürür.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203370, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "You can conquer the whole world with words, but not with drawn swords.",
    textTr: "Bütün dünyayı sözle fethedebilirsin, çekilmiş kılıçla değil.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203371, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Better to drink from a small well of sweet water than from the salty sea.",
    textTr: "Tuzlu denizden içmektense, küçük bir tatlı su kuyusundan içmek iyidir.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203372, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "When three people tell you that you are drunk, go to sleep.",
    textTr: "Üç kişi sana sarhoşsun derse, git uyu.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203373, author: "Gürcü Atasözü", category: "identity", tags: ["wisdom","focus"],
    text: "The buzzing of flies does not make them bees.",
    textTr: "Sineklerin vızıltısı onları arı yapmaz.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203374, author: "Gürcü Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "One blind man followed another, and both fell into the ditch.",
    textTr: "Bir kör diğerinin peşinden gitti, ikisi de çukura düştü.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203375, author: "Gürcü Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Mewing cats catch no mice.",
    textTr: "Miyavlayan kedi fare tutmaz.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203376, author: "Gürcü Atasözü", category: "suffering", tags: ["reckoning","peace"],
    text: "The rich eat when they wish, the poor when they can.",
    textTr: "Zengin canı istediğinde yer, yoksul elinden geldiğinde.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203377, author: "Gürcü Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "What you give away is yours forever; what you keep is lost.",
    textTr: "Verdiğin sonsuza dek senindir, sakladığın kaybolur.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203378, author: "Gürcü Atasözü", category: "fire", tags: ["resilience","legacy"],
    text: "Having many children in the family is fire as well as silver.",
    textTr: "Ailede çok çocuk olması, hem ateş hem gümüştür.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203379, author: "Gürcü Atasözü", category: "identity", tags: ["peace","legacy"],
    text: "To be born under a happy star.",
    textTr: "Mutlu bir yıldız altında doğmak.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203380, author: "Gürcü Atasözü", category: "fire", tags: ["resilience","peace"],
    text: "To be caught between two fires.",
    textTr: "İki ateş arasında kalmak.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203381, author: "Gürcü Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "A low fence invites every passerby to cross it.",
    textTr: "Alçak çit, her geçenin aşmasına davetiye çıkarır.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203382, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "This is where the dog's head is buried.",
    textTr: "İşte köpeğin başının gömülü olduğu yer burası.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203383, author: "Gürcü Atasözü", category: "identity", tags: ["wisdom","legacy"],
    text: "A raven claims kinship with the jay.",
    textTr: "Karga, alakargayla akraba olduğunu iddia eder.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203384, author: "Gürcü Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "He burned neither the meat nor the skewer.",
    textTr: "Ne eti ne şişi yaktı.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203385, author: "Gürcü Atasözü", category: "suffering", tags: ["peace","wisdom"],
    text: "God is the comfort of the poor.",
    textTr: "Tanrı, yoksulun tesellisidir.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203386, author: "Gürcü Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "God laughs at man's proposal.",
    textTr: "Tanrı, insanın planına güler.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
  { id: 203387, author: "Gürcü Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "If you give a man nuts, give him something to crack them with.",
    textTr: "Bir adama ceviz verirsen, kırması için bir şey de ver.",
    origin: "Gürcistan", originEmoji: "🇬🇪", era: "medieval", packId: "se-european-proverbs" },
];

