const AMERICAS_PROVERBS_QUOTES = [
  { id: 203501, author: "Kızılderili Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "A single arrow is easily broken, but a bundle of arrows tied together cannot be broken.",
    textTr: "Tek bir ok kolayca kırılır ama bir arada bağlanmış oklar demeti kırılamaz.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203502, author: "Kızılderili Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "In every deliberation we must consider the impact on the seventh generation, even those whose faces are yet beneath the ground.",
    textTr: "Aldığımız her kararda, yüzleri henüz toprağın altında olan yedinci kuşağa etkisini düşünmeliyiz.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203503, author: "Kızılderili Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "We shall each travel down the river of life in our own boat, side by side, and neither will steer the other's vessel.",
    textTr: "Her birimiz hayat nehrinde kendi kayığımızla, yan yana ilerleyeceğiz; hiçbirimiz diğerinin teknesine dümen tutmayacak.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203504, author: "Kızılderili Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "All my relations — everything that exists is related and shares one life.",
    textTr: "Tüm akrabalarım — var olan her şey birbiriyle bağlantılıdır ve aynı yaşamı paylaşır.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203505, author: "Kızılderili Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "In beauty I walk, with beauty before me, with beauty behind me, with beauty above and about me.",
    textTr: "Güzellik içinde yürürüm; önümde güzellik, arkamda güzellik, üstümde ve çevremde güzellikle yürürüm.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203506, author: "Kızılderili Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "Wisdom sits in places.",
    textTr: "Bilgelik, yerlerde oturur.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203507, author: "Kızılderili Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "The land is always stalking people. The land makes people live right.",
    textTr: "Toprak her zaman insanları izler. Toprak insanları doğru yaşamaya zorlar.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203508, author: "Kızılderili Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "To cherish knowledge is to know wisdom.",
    textTr: "Bilgiyi değerli tutmak, bilgeliği bilmektir.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203509, author: "Kızılderili Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "To honor all creation is to have respect.",
    textTr: "Tüm yaratılışa saygı duymak, saygının ta kendisidir.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203510, author: "Kızılderili Atasözü", category: "fire", tags: ["resilience","focus"],
    text: "Bravery is to face the foe with integrity, and to do what is right even when the consequences are unpleasant.",
    textTr: "Cesaret, düşmanla dürüstçe yüzleşmek ve sonuçları ne kadar acı olursa olsun doğru olanı yapmaktır.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203511, author: "Kızılderili Atasözü", category: "identity", tags: ["wisdom","discipline"],
    text: "Honesty in facing a situation is to be brave; always be honest in word and action.",
    textTr: "Bir durumla dürüstçe yüzleşmek cesaret ister; sözde ve eylemde her zaman dürüst ol.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203512, author: "Kızılderili Atasözü", category: "identity", tags: ["wisdom"],
    text: "Humility is to know yourself as a sacred part of Creation.",
    textTr: "Alçakgönüllülük, kendini Yaratılış'ın kutsal bir parçası olarak bilmektir.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203513, author: "Kızılderili Atasözü", category: "identity", tags: ["wisdom","discipline"],
    text: "Speak the truth; do not deceive yourself or others.",
    textTr: "Gerçeği söyle; ne kendini ne de başkalarını aldat.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203514, author: "Kızılderili Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "To know peace is to know love, and love must be unconditional.",
    textTr: "Huzuru bilmek, sevgiyi bilmektir; ve sevgi koşulsuz olmalıdır.",
    origin: "Kuzey Amerika", originEmoji: "🪶", era: "ancient", packId: "americas-proverbs" },
  { id: 203515, author: "Latin Amerika Atasözü", category: "identity", tags: ["focus","discipline"],
    text: "He who walks with wolves learns to howl.",
    textTr: "Kurtlarla dolaşan ulumayı öğrenir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203516, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Put a good face on bad times.",
    textTr: "Kötü zamana iyi bir yüz göster.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203517, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "A steady step that lasts is worth more than a tiring gallop.",
    textTr: "Yorup biten dörtnala koşudansa, süregelen düz adım daha değerlidir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203518, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "There is no bad from which some good does not come.",
    textTr: "İyilik doğurmayan kötülük yoktur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203519, author: "Latin Amerika Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "He who does not dare, never crosses the sea.",
    textTr: "Cesaret etmeyen denizi asla geçemez.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203520, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","wisdom"],
    text: "When there is no bread, tortillas will do.",
    textTr: "Ekmek yoksa tortilla da olur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203521, author: "Latin Amerika Atasözü", category: "identity", tags: ["wisdom"],
    text: "Tell me who you walk with, and I'll tell you who you are.",
    textTr: "Kiminle yürüdüğünü söyle, sana kim olduğunu söyleyeyim.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203522, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "People only come to the cactus when it bears fruit.",
    textTr: "İnsanlar kaktüsün yanına ancak meyve verdiğinde yaklaşır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203523, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","focus"],
    text: "A barking dog does not bite.",
    textTr: "Havlayan köpek ısırmaz.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203524, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "We see faces, but we never know hearts.",
    textTr: "Yüzleri görürüz ama kalpleri asla bilemeyiz.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203525, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "He who does not look ahead is left behind.",
    textTr: "İleriye bakmayan geride kalır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203526, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","motivation"],
    text: "Pray to God, but keep swinging the hammer.",
    textTr: "Tanrı'ya dua et ama çekici sallamaktan da geri durma.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203527, author: "Latin Amerika Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Only after the child has drowned do they cover the well.",
    textTr: "Çocuk boğulduktan sonra kuyuyu kapatırlar.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203528, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "You don't have wings yet, and already you want to fly.",
    textTr: "Henüz kanatların yokken uçmak istiyorsun.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203529, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "We are all travelers, walking the same road.",
    textTr: "Hepimiz aynı yolda yürüyen yolcularız.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203530, author: "Latin Amerika Atasözü", category: "identity", tags: ["focus","discipline"],
    text: "Call bread bread, and wine wine.",
    textTr: "Ekmeğe ekmek de, şaraba şarap de.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203531, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "When the river makes noise, it is because it carries stones.",
    textTr: "Nehir ses çıkarıyorsa taş taşıyordur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203532, author: "Latin Amerika Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "He who has a friend has a fortune.",
    textTr: "Bir dostu olanın bir hazinesi vardır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203533, author: "Latin Amerika Atasözü", category: "regret", tags: ["reckoning","discipline"],
    text: "Greed bursts the sack.",
    textTr: "Açgözlülük çuvalı patlatır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203534, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "Where two can eat, three can eat.",
    textTr: "İkinin yediği yerde üçüncü de doyar.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203535, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "No hardship lasts a hundred years, nor is there a body that could endure it.",
    textTr: "Yüz yıl süren dert yoktur, buna dayanacak beden de yoktur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203536, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "He who has a godfather gets baptized.",
    textTr: "Vaftiz babası olanın vaftizi de olur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203537, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Where the captain commands, the sailor does not.",
    textTr: "Kaptanın emrettiği yerde denizci emretmez.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203538, author: "Latin Amerika Atasözü", category: "identity", tags: ["wisdom"],
    text: "The goat always pulls toward the hills.",
    textTr: "Keçi her zaman dağa doğru çeker.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203539, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Better a just-in-case than a who-would-have-known.",
    textTr: "'Ne olur ne olmaz' demek, 'keşke bilseydim' demekten iyidir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203540, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "No matter how early you rise, the sun will not dawn any sooner.",
    textTr: "Ne kadar erken kalkarsan kalk, güneş daha erken doğmaz.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203541, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "God raises them, and the devil brings them together.",
    textTr: "Tanrı büyütür, şeytan bir araya getirir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203542, author: "Latin Amerika Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "From such wood comes such a splinter.",
    textTr: "Odun neyse, kıymığı da odur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203543, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Better to prevent than to regret.",
    textTr: "Pişman olmaktansa önlem almak yeğdir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203544, author: "Latin Amerika Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "Every pig gets its slaughter day.",
    textTr: "Her domuzun kendi kesim günü gelir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203545, author: "Latin Amerika Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "Luck must be given a helping hand.",
    textTr: "Şansa yardım etmek gerekir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203546, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "What begins badly, ends badly.",
    textTr: "Kötü başlayan kötü biter.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203547, author: "Latin Amerika Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "When the king dies, a new king is crowned.",
    textTr: "Kral ölünce yerine yenisi tahta çıkar.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203548, author: "Latin Amerika Atasözü", category: "regret", tags: ["discipline","reckoning"],
    text: "Before you marry, look closely at what you are doing.",
    textTr: "Evlenmeden önce ne yaptığına iyice bak.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203549, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["peace","wisdom"],
    text: "From the tree of silence hangs the fruit of tranquility.",
    textTr: "Sessizlik ağacından sükunet meyvesi sarkar.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203550, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Gold shines all the brighter for having been hammered.",
    textTr: "Altın, dövüldükçe daha çok parlar.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203551, author: "Latin Amerika Atasözü", category: "suffering", tags: ["peace","wisdom"],
    text: "Only the one who carries it knows how heavy the cross is.",
    textTr: "Haçı taşıyan, onun ne kadar ağır olduğunu bilir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203552, author: "Latin Amerika Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "You cannot catch trout without wetting your feet.",
    textTr: "Ayaklarını ıslatmadan alabalık tutamazsın.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203553, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "When the road is long, even slippers begin to pinch.",
    textTr: "Yol uzun olunca terlik bile sıkmaya başlar.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203554, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "Never harm the bird that is brooding.",
    textTr: "Kuluçkadaki kuşa asla zarar verme.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203555, author: "Latin Amerika Atasözü", category: "suffering", tags: ["wisdom","peace"],
    text: "Envy for a friend tastes like a sour squash.",
    textTr: "Bir dostu kıskanmak, ekşi bir bal kabağının tadındadır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203556, author: "Latin Amerika Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "You go out for wool and come back shorn.",
    textTr: "Yün almaya gidip kırkılmış olarak dönersin.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203557, author: "Latin Amerika Atasözü", category: "legacy", tags: ["wisdom","legacy"],
    text: "Youth is intoxication without wine; old age is wine without intoxication.",
    textTr: "Gençlik, şarapsız bir sarhoşluktur; yaşlılık, sarhoşluksuz bir şaraptır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203558, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Grain by grain, the hen fills her crop.",
    textTr: "Tane tane, tavuk kursağını doldurur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203559, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","discipline"],
    text: "Soft water striking hard stone will bore through it in time.",
    textTr: "Yumuşak su, sert taşa vurdukça sonunda onu deler.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203560, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Go slowly, and you will go far.",
    textTr: "Yavaş git, uzağa varırsın.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203561, author: "Latin Amerika Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "He who does not risk does not get a taste.",
    textTr: "Riske girmeyen, tadına bile bakamaz.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203562, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "Hope is the last thing to die.",
    textTr: "Umut, en son ölendir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203563, author: "Latin Amerika Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "He who sows the wind reaps the storm.",
    textTr: "Rüzgar eken fırtına biçer.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203564, author: "Latin Amerika Atasözü", category: "legacy", tags: ["legacy","wisdom"],
    text: "The child of a fish is a little fish.",
    textTr: "Balığın çocuğu küçük bir balıktır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203565, author: "Latin Amerika Atasözü", category: "fire", tags: ["motivation","focus"],
    text: "He who has a mouth can find his way to Rome.",
    textTr: "Ağzı olan, Roma'ya giden yolu bulur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203566, author: "Latin Amerika Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "Each monkey belongs on its own branch.",
    textTr: "Her maymun kendi dalında olmalıdır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203567, author: "Latin Amerika Atasözü", category: "regret", tags: ["peace","wisdom"],
    text: "Waters that have passed no longer turn the mill.",
    textTr: "Geçmiş sular artık değirmeni döndürmez.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203568, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "He who stays silent gives his consent.",
    textTr: "Susan, onaylamış sayılır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203569, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "The saint of the house performs no miracles.",
    textTr: "Evin azizi mucize göstermez.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203570, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","wisdom"],
    text: "Opportunity is what makes the thief.",
    textTr: "Fırsat, hırsızı yaratır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203571, author: "Latin Amerika Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "He who wounds with iron will be wounded by iron.",
    textTr: "Demirle yaralayan, demirle yaralanır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203572, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "The cautious one lives to be old.",
    textTr: "Tedbirli olan uzun yaşar.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203573, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "Haste is the enemy of perfection.",
    textTr: "Acele, mükemmelliğin düşmanıdır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203574, author: "Latin Amerika Atasözü", category: "suffering", tags: ["wisdom","reckoning"],
    text: "From a fallen tree, everyone cuts firewood.",
    textTr: "Devrilen ağaçtan herkes odun keser.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203575, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "No one learns from another person's mistakes.",
    textTr: "Kimse başkasının hatasından ders çıkarmaz.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203576, author: "Latin Amerika Atasözü", category: "fire", tags: ["motivation","discipline"],
    text: "He who wants fish must be willing to get wet.",
    textTr: "Balık isteyen ıslanmayı göze almalıdır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203577, author: "Latin Amerika Atasözü", category: "regret", tags: ["reckoning","wisdom"],
    text: "To leave one bad place only to land in a worse one.",
    textTr: "Bir kötü yerden çıkıp daha kötüsüne düşmek.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203578, author: "Latin Amerika Atasözü", category: "identity", tags: ["wisdom"],
    text: "The tree is known by its fruit.",
    textTr: "Ağaç, meyvesinden bilinir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203579, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","motivation"],
    text: "When one door closes, a hundred others open.",
    textTr: "Bir kapı kapanınca, yüz kapı açılır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203580, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","reckoning"],
    text: "Beware of still waters; I'll watch out for the wild ones myself.",
    textTr: "Durgun sudan sakın; azgınından ben kendim sakınırım.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203581, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","discipline"],
    text: "He who will not listen to advice will not live to be old.",
    textTr: "Öğüde kulak vermeyen, yaşlılığa erişemez.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203582, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "A forewarned man is worth two.",
    textTr: "Tedbirli bir insan iki kişiye bedeldir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203583, author: "Latin Amerika Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "Today for me, tomorrow for you.",
    textTr: "Bugün benim için, yarın senin için.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203584, author: "Latin Amerika Atasözü", category: "resilience", tags: ["resilience","legacy"],
    text: "Unity creates strength.",
    textTr: "Birlik, güç yaratır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203585, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "There is a long stretch between saying and doing.",
    textTr: "Söylemekle yapmak arasında uzun bir yol vardır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203586, author: "Latin Amerika Atasözü", category: "identity", tags: ["focus","discipline"],
    text: "Dirty laundry is washed at home.",
    textTr: "Kirli çamaşır evde yıkanır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203587, author: "Latin Amerika Atasözü", category: "identity", tags: ["wisdom","peace"],
    text: "Each sheep with its own kind.",
    textTr: "Her koyun kendi eşiyle bir arada olur.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203588, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","resilience"],
    text: "With time, everything is achieved.",
    textTr: "Zamanla her şey başarılır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203589, author: "Latin Amerika Atasözü", category: "identity", tags: ["wisdom"],
    text: "Even if the monkey dresses in silk, she remains a monkey.",
    textTr: "Maymun ipek giyse de yine maymun kalır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203590, author: "Latin Amerika Atasözü", category: "fire", tags: ["motivation","resilience"],
    text: "He who perseveres, achieves.",
    textTr: "Sebat eden, başarır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203591, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "He who tries to grasp too much holds on to little.",
    textTr: "Çok şeyi kucaklamaya çalışan azına bile sıkı tutunamaz.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203592, author: "Latin Amerika Atasözü", category: "identity", tags: ["focus"],
    text: "Cobbler, stick to your own shoes.",
    textTr: "Kunduracı, kendi ayakkabına bak.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203593, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","peace"],
    text: "He who leans against a good tree is sheltered by good shade.",
    textTr: "İyi bir ağaca yaslanan, iyi bir gölgede barınır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203594, author: "Latin Amerika Atasözü", category: "wisdom", tags: ["wisdom","legacy"],
    text: "The devil knows more from being old than from being the devil.",
    textTr: "Şeytan, şeytan olduğu için değil, yaşlı olduğu için daha çok bilir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203595, author: "Latin Amerika Atasözü", category: "identity", tags: ["wisdom","reckoning"],
    text: "A lamp for the street, darkness in one's own house.",
    textTr: "Sokağa ışık, kendi evine karanlık.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203596, author: "Latin Amerika Atasözü", category: "identity", tags: ["wisdom","legacy"],
    text: "He who has no Congo blood has Carabalí blood.",
    textTr: "Kongolu kanı taşımayanın Carabalí kanı vardır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203597, author: "Latin Amerika Atasözü", category: "discipline", tags: ["discipline","focus"],
    text: "It's better to prevent than to cure.",
    textTr: "Tedavi etmektense önlem almak daha iyidir.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203598, author: "Latin Amerika Atasözü", category: "resilience", tags: ["focus","wisdom"],
    text: "Once caught in the net, it belongs to the fisherman.",
    textTr: "Ağa bir kez takılan, artık balıkçınındır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
  { id: 203599, author: "Latin Amerika Atasözü", category: "legacy", tags: ["legacy","peace"],
    text: "It is by giving that one receives.",
    textTr: "İnsan ancak verdikçe alır.",
    origin: "Latin Amerika", originEmoji: "🌎", era: "modern", packId: "americas-proverbs" },
];

